def _mask_feishu_webhook(value):
    text = str(value or "").strip()
    if not text:
        return ""
    prefix = 38
    suffix = 8
    if len(text) <= prefix + suffix:
        return text[:2] + "••••"
    return text[:prefix] + "••••••••" + text[-suffix:]


def _mask_secret_value(value, prefix=6, suffix=4):
    text = str(value or "").strip()
    if not text:
        return ""
    if len(text) <= prefix + suffix:
        return text[:2] + "••••"
    return text[:prefix] + "••••••••" + text[-suffix:]


