def _send_feishu_notification_test_cards(kind=None):
    cfg = VO_CONFIG.get("notifications", {}) or {}
    webhook = cfg.get("feishuWebhook") or ""
    if not webhook and not _feishu_app_configured(cfg):
        return {"ok": False, "error": "Feishu notification app or webhook is not configured", "code": "missing_feishu_config", "_status": 400}
    intents = _feishu_notification_test_intents()
    selected = [kind] if kind in intents else ["application_form", "notification", "warning", "error"]
    results = []
    for selected_kind in selected:
        results.append(send_feishu_notification(
            intents[selected_kind],
            webhook_url=webhook,
            app_config=_feishu_app_send_config(cfg),
            status_dir=STATUS_DIR,
            timeout=20,
        ))
    ok = bool(results and all(r.get("ok") for r in results))
    response = {"ok": ok, "results": results}
    if not ok:
        failed = next((r for r in results if not r.get("ok")), {})
        detail = failed.get("message") or failed.get("error") or failed.get("status") or "Feishu test failed"
        if failed.get("code") not in ("", None):
            detail = f"{detail} (code: {failed.get('code')})"
        response["error"] = detail
    return response


def _feishu_card_action_log_path():
    return os.path.join(STATUS_DIR, "feishu-card-actions.jsonl")


def _feishu_card_action_user(event):
    user = event.get("operator") or event.get("user") or {}
    if not isinstance(user, dict):
        return {}
    return {
        "openId": str(user.get("open_id") or user.get("openId") or "").strip(),
        "userId": str(user.get("user_id") or user.get("userId") or "").strip(),
        "unionId": str(user.get("union_id") or user.get("unionId") or "").strip(),
    }


def _feishu_card_action_value(event):
    action = event.get("action") if isinstance(event.get("action"), dict) else {}
    value = action.get("value") if isinstance(action.get("value"), dict) else {}
    if not value:
        for behavior in action.get("behaviors") or []:
            if isinstance(behavior, dict) and behavior.get("type") == "callback" and isinstance(behavior.get("value"), dict):
                value = behavior["value"]
                break
    return value


def _feishu_card_action_form_values(event):
    action = event.get("action") if isinstance(event.get("action"), dict) else {}
    candidates = [
        action.get("form_value"),
        action.get("formValue"),
        action.get("form_values"),
        action.get("formValues"),
        action.get("form_value_map"),
        action.get("formValueMap"),
        event.get("form_value"),
        event.get("formValue"),
    ]
    for candidate in candidates:
        if isinstance(candidate, dict):
            return candidate
    return {}


def _feishu_card_action_form_text(event, *names):
    values = _feishu_card_action_form_values(event)
    for name in names:
        if name in values:
            value = values.get(name)
            if isinstance(value, dict):
                value = value.get("value") or value.get("text") or value.get("content")
            if isinstance(value, list):
                value = "\n".join(str(item) for item in value if item is not None)
            text = str(value or "").strip()
            if text:
                return text
    return ""


def _record_feishu_card_action(body, event, value, outcome=None):
    record = {
        "id": str(uuid.uuid4()),
        "receivedAt": _exec_meeting_now(),
        "schema": str(body.get("schema") or ""),
        "type": str(body.get("type") or body.get("header", {}).get("event_type") or ""),
        "action": str(value.get("action") or value.get("action_category") or ""),
        "notificationId": str(value.get("notification_id") or ""),
        "requestId": str(value.get("request_id") or ""),
        "user": _feishu_card_action_user(event),
        "messageId": str(event.get("open_message_id") or event.get("message_id") or ""),
        "chatId": str(event.get("open_chat_id") or event.get("chat_id") or ""),
        "value": value,
    }
    if isinstance(outcome, dict):
        record["outcome"] = outcome
    os.makedirs(os.path.dirname(_feishu_card_action_log_path()), exist_ok=True)
    with open(_feishu_card_action_log_path(), "a", encoding="utf-8") as f:
        f.write(json.dumps(record, ensure_ascii=False, sort_keys=True) + "\n")
    return record


def _feishu_card_action_success(content):
    return {"type": "success", "content": content}


def _feishu_card_action_error(content):
    return {"type": "error", "content": content}


def _feishu_meeting_action_actor(event, fallback="feishu"):
    user = _feishu_card_action_user(event)
    return user.get("userId") or user.get("openId") or user.get("unionId") or fallback


def _dispatch_feishu_meeting_request_action(action, request_id, event):
    if action not in {"confirm_meeting_request", "reject_meeting_request"}:
        return {"handled": False}
    if not request_id:
        return {
            "handled": True,
            "ok": False,
            "businessStatus": "missing_request_id",
            "toast": _feishu_card_action_error("会议申请缺少 request_id，无法处理"),
        }
    actor = _feishu_meeting_action_actor(event)
    if action == "confirm_meeting_request":
        result = _handle_meeting_request_confirm(request_id, {
            "confirmedBy": actor,
            "idempotencyKey": f"feishu-confirm:{request_id}",
        })
        if result.get("ok"):
            idempotent = bool(result.get("idempotent"))
            meeting_id = str(result.get("meetingId") or "")
            run_result = None
            run_summary = {}
            if meeting_id:
                run_result = _handle_executable_meeting_run(meeting_id, {
                    "action": "start",
                    "actorId": actor,
                    "actorType": "user",
                })
                run_summary = {
                    "attempted": True,
                    "ok": bool(run_result.get("ok")) if isinstance(run_result, dict) else False,
                    "stage": ((run_result or {}).get("meeting") or {}).get("stage") if isinstance(run_result, dict) else "",
                    "error": (run_result or {}).get("error") if isinstance(run_result, dict) else "Meeting start failed",
                }
            if run_summary.get("attempted") and not run_summary.get("ok"):
                return {
                    "handled": True,
                    "ok": True,
                    "businessStatus": "confirmed_start_failed",
                    "businessError": str(run_summary.get("error") or "会议启动失败"),
                    "idempotent": idempotent,
                    "meetingId": meeting_id,
                    "run": run_summary,
                    "toast": _feishu_card_action_error(f"会议申请已同意，但启动会议失败：{run_summary.get('error') or '未知错误'}"),
                }
            return {
                "handled": True,
                "ok": True,
                "businessStatus": "confirmed_started" if run_summary.get("attempted") else "confirmed",
                "idempotent": idempotent,
                "meetingId": meeting_id,
                "run": run_summary,
                "toast": _feishu_card_action_success("会议申请已同意，会议已开始" + ("（已处理）" if idempotent else "")),
            }
        return {
            "handled": True,
            "ok": False,
            "businessStatus": str(result.get("code") or result.get("status") or "confirm_failed"),
            "businessError": str(result.get("error") or "会议申请无法同意"),
            "toast": _feishu_card_action_error(str(result.get("error") or "会议申请无法同意")),
        }
    result = _handle_meeting_request_reject(request_id, {
        "rejectedBy": actor,
        "reason": "Rejected from Feishu",
    })
    if result.get("ok"):
        idempotent = bool(result.get("idempotent"))
        return {
            "handled": True,
            "ok": True,
            "businessStatus": "rejected",
            "idempotent": idempotent,
            "toast": _feishu_card_action_success("会议申请已拒绝" + ("（已处理）" if idempotent else "")),
        }
    return {
        "handled": True,
        "ok": False,
        "businessStatus": str(result.get("code") or result.get("status") or "reject_failed"),
        "businessError": str(result.get("error") or "会议申请无法拒绝"),
        "toast": _feishu_card_action_error(str(result.get("error") or "会议申请无法拒绝")),
    }


def _dispatch_feishu_project_execution_action(action, value, event):
    if action not in {"project_execution_accept", "project_execution_rework"}:
        return {"handled": False}
    project_id = str(value.get("project_id") or value.get("projectId") or "").strip()
    task_id = str(value.get("task_id") or value.get("taskId") or "").strip()
    attempt_id = str(value.get("attempt_id") or value.get("attemptId") or "").strip()
    if not project_id or not task_id or not attempt_id:
        return {
            "handled": True,
            "ok": False,
            "businessStatus": "missing_project_execution_context",
            "toast": _feishu_card_action_error("项目任务验收缺少上下文，无法处理"),
        }
    actor = _feishu_meeting_action_actor(event)
    body = {
        "action": "accept" if action == "project_execution_accept" else "reject_and_rework",
        "attemptId": attempt_id,
        "actor": actor,
    }
    if action == "project_execution_rework":
        body["feedback"] = _feishu_card_action_form_text(event, "feedback", "rework_feedback", "reason") or _PROJECT_EXECUTION_FEISHU_REWORK_FEEDBACK
    result = _handle_project_execution_acceptance(project_id, task_id, body)
    if result.get("ok"):
        return {
            "handled": True,
            "ok": True,
            "businessStatus": str(result.get("status") or "accepted"),
            "toast": _feishu_card_action_success("项目任务已接受" if action == "project_execution_accept" else "已要求任务返工"),
        }
    return {
        "handled": True,
        "ok": False,
        "businessStatus": str(result.get("code") or result.get("status") or "project_execution_action_failed"),
        "businessError": str(result.get("error") or "项目任务验收操作失败"),
        "toast": _feishu_card_action_error(str(result.get("error") or "项目任务验收操作失败")),
    }


def _handle_feishu_card_action(body):
    if not isinstance(body, dict):
        return {"ok": False, "error": "Invalid Feishu callback body", "_status": 400}
    challenge = body.get("challenge")
    if isinstance(challenge, str) and challenge:
        return {"challenge": challenge}

    event = body.get("event") if isinstance(body.get("event"), dict) else body
    value = _feishu_card_action_value(event)
    action = str(value.get("action") or "").strip()
    meeting_outcome = _dispatch_feishu_meeting_request_action(action, str(value.get("request_id") or "").strip(), event)
    project_outcome = {"handled": False} if meeting_outcome.get("handled") else _dispatch_feishu_project_execution_action(action, value, event)
    outcome = meeting_outcome if meeting_outcome.get("handled") else (project_outcome if project_outcome.get("handled") else None)
    record = _record_feishu_card_action(body, event, value, outcome=outcome)
    if meeting_outcome.get("handled"):
        return {
            "ok": bool(meeting_outcome.get("ok")),
            "toast": meeting_outcome.get("toast") or _feishu_card_action_success("操作已收到"),
            "recordId": record["id"],
            "outcome": {k: v for k, v in meeting_outcome.items() if k not in {"toast"}},
        }
    if project_outcome.get("handled"):
        return {
            "ok": bool(project_outcome.get("ok")),
            "toast": project_outcome.get("toast") or _feishu_card_action_success("操作已收到"),
            "recordId": record["id"],
            "outcome": {k: v for k, v in project_outcome.items() if k not in {"toast"}},
        }
    return {
        "ok": True,
        "toast": {"type": "success", "content": "操作已收到"},
        "recordId": record["id"],
    }


def _get_feishu_long_connection_receiver():
    global _FEISHU_LONG_CONNECTION_RECEIVER
    return _FEISHU_LONG_CONNECTION_RECEIVER


def _get_feishu_chat_long_connection_receiver():
    global _FEISHU_CHAT_LONG_CONNECTION_RECEIVER
    return _FEISHU_CHAT_LONG_CONNECTION_RECEIVER


def _stop_feishu_chat_long_connection(status="disabled"):
    global _FEISHU_CHAT_LONG_CONNECTION_RECEIVER
    with _FEISHU_CHAT_LONG_CONNECTION_LOCK:
        existing = _FEISHU_CHAT_LONG_CONNECTION_RECEIVER
        _FEISHU_CHAT_LONG_CONNECTION_RECEIVER = None
    if existing:
        try:
            stopped = existing.stop()
            if isinstance(stopped, dict):
                stopped["status"] = status
                stopped["running"] = False
                stopped["enabled"] = False
                return stopped
        except Exception as exc:
            return {"enabled": False, "running": False, "status": "stop_error", "lastError": f"{type(exc).__name__}: {exc}"}
    return {"enabled": False, "running": False, "status": status}


def _start_feishu_long_connection():
    global _FEISHU_LONG_CONNECTION_RECEIVER
    cfg = VO_CONFIG.get("notifications", {}) or {}
    if cfg.get("feishuEnabled", True) is False:
        return {"enabled": False, "running": False, "status": "disabled"}
    app_id = str(cfg.get("feishuAppId") or "").strip()
    app_secret = str(cfg.get("feishuAppSecret") or "").strip()
    if not app_id or not app_secret:
        return {"enabled": False, "running": False, "status": "missing_app_credentials"}
    with _FEISHU_LONG_CONNECTION_LOCK:
        existing = _FEISHU_LONG_CONNECTION_RECEIVER
        if existing and existing.app_id == app_id and existing.app_secret == app_secret:
            return existing.start()
        _FEISHU_LONG_CONNECTION_RECEIVER = FeishuLongConnectionReceiver(
            app_id=app_id,
            app_secret=app_secret,
            action_handler=_handle_feishu_card_action,
        )
        return _FEISHU_LONG_CONNECTION_RECEIVER.start()


def _start_feishu_chat_long_connection():
    global _FEISHU_CHAT_LONG_CONNECTION_RECEIVER
    cfg = _feishu_chat_app_config()
    if cfg.get("enabled", False) is False:
        return _stop_feishu_chat_long_connection("disabled")
    app_id = str(cfg.get("appId") or "").strip()
    app_secret = str(cfg.get("appSecret") or "").strip()
    if not app_id or not app_secret:
        return _stop_feishu_chat_long_connection("missing_app_credentials")
    with _FEISHU_CHAT_LONG_CONNECTION_LOCK:
        existing = _FEISHU_CHAT_LONG_CONNECTION_RECEIVER
        if existing and existing.app_id == app_id and existing.app_secret == app_secret:
            return existing.start()
        callback_url = f"http://127.0.0.1:{PORT}/api/feishu-chat/inbound-worker"
        _FEISHU_CHAT_LONG_CONNECTION_RECEIVER = FeishuChatWorkerProcess(
            app_id=app_id,
            app_secret=app_secret,
            callback_url=callback_url,
            status_dir=STATUS_DIR,
        )
        return _FEISHU_CHAT_LONG_CONNECTION_RECEIVER.start()


