def _feishu_channel_lock(key):
    key = str(key or "default")
    with _FEISHU_CHANNEL_LOCKS_LOCK:
        lock = _FEISHU_CHANNEL_LOCKS.get(key)
        if not lock:
            lock = threading.Lock()
            _FEISHU_CHANNEL_LOCKS[key] = lock
        return lock


