def _archive_manager_file():
    return os.path.join(ARCHIVE_ROOM_DIR, "manager.json")


def _archive_manager_default_state():
    now = _proj_now()
    return {
        "agentId": ARCHIVE_MANAGER_AGENT_ID,
        "name": ARCHIVE_MANAGER_NAME,
        "emoji": ARCHIVE_MANAGER_EMOJI,
        "providerKind": "openclaw",
        "status": "missing",
        "label": "未接入",
        "phase": "phase-4",
        "paused": False,
        "autoCreated": False,
        "createdAt": None,
        "updatedAt": now,
        "lastAction": "",
        "lastError": "",
        "recentActivity": [],
    }


def _archive_manager_load_state():
    try:
        with open(_archive_manager_file(), "r", encoding="utf-8") as f:
            data = json.load(f)
        if not isinstance(data, dict):
            data = {}
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        data = {}
    state = _archive_manager_default_state()
    state.update({k: v for k, v in data.items() if k in state or k in {"workspace", "profileFiles", "profileVersion", "profileUpdatedAt"}})
    if not isinstance(state.get("recentActivity"), list):
        state["recentActivity"] = []
    return state


def _archive_manager_save_state(state):
    os.makedirs(ARCHIVE_ROOM_DIR, exist_ok=True)
    payload = dict(state or {})
    payload["recentActivity"] = (payload.get("recentActivity") or [])[-ARCHIVE_MANAGER_ACTIVITY_LIMIT:]
    payload["updatedAt"] = payload.get("updatedAt") or _proj_now()
    tmp = _archive_manager_file() + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(payload, f, ensure_ascii=False, indent=2)
        f.write("\n")
    os.replace(tmp, _archive_manager_file())
    try:
        os.chmod(_archive_manager_file(), 0o666)
    except OSError:
        pass
    return payload


def _archive_manager_append_activity(state, action, status="ok", message="", project_id=None, error=""):
    entry = {
        "id": _proj_uuid(),
        "action": action,
        "status": status,
        "message": message or "",
        "projectId": project_id or "",
        "error": error or "",
        "at": _proj_now(),
    }
    activity = state.get("recentActivity") if isinstance(state.get("recentActivity"), list) else []
    activity.append(entry)
    state["recentActivity"] = activity[-ARCHIVE_MANAGER_ACTIVITY_LIMIT:]
    state["lastAction"] = action
    state["lastError"] = error or ""
    state["updatedAt"] = entry["at"]
    return entry


def _archive_project_status(project):
    return str((project or {}).get("status") or "active").strip().lower() or "active"


def _archive_project_default_maintenance_enabled(project):
    return _archive_project_status(project) in {"active", "ongoing", "in_progress", "running"}


def _archive_project_maintenance_enabled(project):
    project = project or {}
    if "archiveMaintenanceEnabled" in project:
        return bool(project.get("archiveMaintenanceEnabled"))
    if "archiveMaintenance" in project and isinstance(project.get("archiveMaintenance"), dict):
        val = project["archiveMaintenance"].get("enabled")
        if val is not None:
            return bool(val)
    return _archive_project_default_maintenance_enabled(project)


def _archive_normalize_schedule_mode(mode, default=None):
    mode = str(mode or "").strip().lower()
    aliases = {
        "event": ARCHIVE_SCHEDULE_EVENT_ONLY,
        "event-only": ARCHIVE_SCHEDULE_EVENT_ONLY,
        "event_only": ARCHIVE_SCHEDULE_EVENT_ONLY,
        "events": ARCHIVE_SCHEDULE_EVENT_ONLY,
        "daily": ARCHIVE_SCHEDULE_DAILY,
        "day": ARCHIVE_SCHEDULE_DAILY,
        "weekly": ARCHIVE_SCHEDULE_WEEKLY,
        "week": ARCHIVE_SCHEDULE_WEEKLY,
        "custom": ARCHIVE_SCHEDULE_CUSTOM,
    }
    if not mode:
        return default
    return aliases.get(mode)


def _archive_maintenance_schedule_mode(project):
    maintenance = (project or {}).get("archiveMaintenance") if isinstance((project or {}).get("archiveMaintenance"), dict) else {}
    mode = maintenance.get("scheduleMode") or maintenance.get("frequency") or ""
    return _archive_normalize_schedule_mode(mode, ARCHIVE_DEFAULT_SCHEDULE_MODE)


def _archive_schedule_label(mode):
    return {
        ARCHIVE_SCHEDULE_EVENT_ONLY: "仅事件触发",
        ARCHIVE_SCHEDULE_DAILY: "事件触发 + 每日巡检",
        ARCHIVE_SCHEDULE_WEEKLY: "事件触发 + 每周巡检",
        ARCHIVE_SCHEDULE_CUSTOM: "事件触发 + 自定义巡检",
    }.get(mode or "", "事件触发 + 每日巡检")


def _archive_parse_dt(value):
    text = str(value or "").strip()
    if not text:
        return None
    try:
        return datetime.fromisoformat(text.replace("Z", "+00:00"))
    except Exception:
        return None


def _archive_iso_after(value, days=1):
    base = _archive_parse_dt(value) or datetime.now(timezone.utc)
    if base.tzinfo is None:
        base = base.replace(tzinfo=timezone.utc)
    return (base + timedelta(days=days)).isoformat()


def _archive_schedule_state(record):
    state = record.get("archiveMaintenanceSchedule") if isinstance(record.get("archiveMaintenanceSchedule"), dict) else {}
    record["archiveMaintenanceSchedule"] = state
    return state


def _archive_project_maintenance_meta(project, record=None):
    explicit = "archiveMaintenanceEnabled" in (project or {}) or (
        isinstance((project or {}).get("archiveMaintenance"), dict)
        and (project.get("archiveMaintenance") or {}).get("enabled") is not None
    )
    mode = _archive_maintenance_schedule_mode(project)
    schedule = {}
    if isinstance(record, dict):
        schedule = record.get("archiveMaintenanceSchedule") if isinstance(record.get("archiveMaintenanceSchedule"), dict) else {}
    last_scheduled = schedule.get("lastScheduledAt") or ((record or {}).get("inspections") or {}).get("lastDailyInspectionAt", "")
    if mode == ARCHIVE_SCHEDULE_EVENT_ONLY:
        next_scheduled = ""
    elif mode == ARCHIVE_SCHEDULE_WEEKLY:
        next_scheduled = schedule.get("nextScheduledAt") or _archive_iso_after(last_scheduled, 7)
    elif mode == ARCHIVE_SCHEDULE_CUSTOM:
        next_scheduled = schedule.get("nextScheduledAt") or ""
    else:
        next_scheduled = schedule.get("nextScheduledAt") or _archive_iso_after(last_scheduled, 1)
    project_maintenance = project.get("archiveMaintenance") if isinstance((project or {}).get("archiveMaintenance"), dict) else {}
    return {
        "enabled": _archive_project_maintenance_enabled(project),
        "defaultEnabled": _archive_project_default_maintenance_enabled(project),
        "explicit": bool(explicit),
        "status": _archive_project_status(project),
        "scheduleMode": mode,
        "frequency": mode,
        "frequencyLabel": _archive_schedule_label(mode),
        "nextScheduledAt": next_scheduled,
        "lastScheduledAt": schedule.get("lastScheduledAt") or "",
        "lastScheduledKind": schedule.get("lastScheduledKind") or "",
        "lastEventTriggeredAt": schedule.get("lastEventTriggeredAt") or "",
        "lastSkippedAt": schedule.get("lastSkippedAt") or "",
        "lastSkippedReason": schedule.get("lastSkippedReason") or "",
        "lastSkippedKind": schedule.get("lastSkippedKind") or "",
        "customIntervalHours": schedule.get("customIntervalHours") or project_maintenance.get("customIntervalHours"),
        "explanation": "计划巡检按频率执行；事件触发整理独立生效；关闭长期维护或暂停管理员时计划整理会跳过。"
    }


def _archive_source_ref(source_type, source_id="", title="", **extra):
    ref = {"type": source_type, "id": str(source_id or ""), "title": str(title or ""), "at": _proj_now()}
    for key, value in extra.items():
        if value not in (None, ""):
            ref[key] = value
    return ref


def _archive_event_key(project_id, event_type, source=None, fallback=""):
    source = source if isinstance(source, dict) else {}
    raw = "|".join([
        str(project_id or ""),
        str(event_type or ""),
        str(source.get("type") or ""),
        str(source.get("id") or ""),
        str(source.get("taskId") or ""),
        str(source.get("meetingId") or ""),
        str(source.get("path") or ""),
        str(fallback or ""),
    ])
    return hashlib.sha256(raw.encode("utf-8")).hexdigest()


def _archive_project_maintenance_records(record):
    items = record.get("managerMaintenance")
    if not isinstance(items, list):
        items = []
    record["managerMaintenance"] = items
    return items


def _archive_project_processed_events(record):
    processed = record.get("processedEvents")
    if not isinstance(processed, dict):
        processed = {}
    record["processedEvents"] = processed
    return processed


def _archive_append_project_maintenance(record, item):
    history = _archive_project_maintenance_records(record)
    history.append(item)
    record["managerMaintenance"] = history[-80:]
    return item


def _archive_update_schedule_state(record, *, kind="", status="", at="", reason=""):
    schedule = _archive_schedule_state(record)
    now = at or _proj_now()
    if status in {"ok", "no_update"} and kind in {"daily_inspection", "weekly_inspection", "custom_inspection"}:
        schedule["lastScheduledAt"] = now
        schedule["lastScheduledKind"] = kind
        if kind == "weekly_inspection":
            schedule["nextScheduledAt"] = _archive_iso_after(now, 7)
        elif kind == "custom_inspection":
            hours = int(schedule.get("customIntervalHours") or 0)
            schedule["nextScheduledAt"] = (datetime.now(timezone.utc) + timedelta(hours=hours)).isoformat() if hours > 0 else ""
        else:
            schedule["nextScheduledAt"] = _archive_iso_after(now, 1)
    elif status == "event":
        schedule["lastEventTriggeredAt"] = now
    elif status == "skipped":
        schedule["lastSkippedAt"] = now
        schedule["lastSkippedKind"] = kind
        schedule["lastSkippedReason"] = reason
    record["archiveMaintenanceSchedule"] = schedule
    return schedule


def _archive_inspection_schedule_decision(project, record, kind, force=False):
    if kind == "startup_inspection":
        return {"run": True, "scheduledKind": "startup_inspection", "reason": ""}
    mode = _archive_maintenance_schedule_mode(project)
    if mode == ARCHIVE_SCHEDULE_EVENT_ONLY:
        return {"run": False, "scheduledKind": "daily_inspection", "reason": "项目设置为仅事件触发，计划巡检已跳过。"}
    schedule = _archive_schedule_state(record)
    now = datetime.now(timezone.utc)
    if mode == ARCHIVE_SCHEDULE_WEEKLY:
        last = _archive_parse_dt(schedule.get("lastScheduledAt") or ((record.get("inspections") or {}).get("lastWeeklyInspectionAt")))
        if last and (now - last) < timedelta(days=7) and not force:
            return {"run": False, "scheduledKind": "weekly_inspection", "reason": "每周计划巡检尚未到期。"}
        return {"run": True, "scheduledKind": "weekly_inspection", "reason": ""}
    if mode == ARCHIVE_SCHEDULE_CUSTOM:
        hours = int(schedule.get("customIntervalHours") or ((project.get("archiveMaintenance") or {}).get("customIntervalHours") if isinstance(project.get("archiveMaintenance"), dict) else 0) or 0)
        if hours <= 0:
            return {"run": False, "scheduledKind": "custom_inspection", "reason": "自定义巡检间隔未配置。"}
        last = _archive_parse_dt(schedule.get("lastScheduledAt"))
        if last and (now - last) < timedelta(hours=hours) and not force:
            return {"run": False, "scheduledKind": "custom_inspection", "reason": "自定义计划巡检尚未到期。"}
        return {"run": True, "scheduledKind": "custom_inspection", "reason": ""}
    last = _archive_parse_dt(schedule.get("lastScheduledAt") or ((record.get("inspections") or {}).get("lastDailyInspectionAt")))
    if last and last.date() == now.date() and not force:
        return {"run": False, "scheduledKind": "daily_inspection", "reason": "每日计划巡检今日已完成。"}
    return {"run": True, "scheduledKind": "daily_inspection", "reason": ""}


def _archive_entry_from_event(event_key, title, text, confidence, source, stale=False, kind="event"):
    entry_id = f"{kind}-{event_key[:16]}"
    entry = _archive_entry(entry_id, title, text, confidence, source, stale=stale)
    entry["kind"] = kind
    entry["updatedAt"] = _proj_now()
    return entry


def _archive_upsert_entry(record, entry):
    entries = record.get("entries") if isinstance(record.get("entries"), list) else []
    entry_id = entry.get("id")
    replaced = False
    for idx, existing in enumerate(entries):
        if existing.get("id") == entry_id:
            entries[idx] = {**existing, **entry}
            replaced = True
            break
    if not replaced:
        entries.append(entry)
    record["entries"] = entries[-200:]
    return "updated" if replaced else "created"


def _archive_pending_priority(item):
    if not isinstance(item, dict):
        return 50
    status = str(item.get("status") or "")
    if status in {"deferred", ARCHIVE_AUTH_DEFERRED} or item.get("authority") == ARCHIVE_AUTH_DEFERRED:
        return 90
    if item.get("conflict") or item.get("conflictSummary"):
        return 0
    impact = str(item.get("impact") or "").lower()
    if impact in {"risk", "project_status", "task_conclusion", "risk_judgment"}:
        return 5
    if impact in {"state", "task"}:
        return 10
    kind = str(item.get("kind") or "").lower()
    title = str(item.get("title") or "").lower()
    if kind == "rule" or "rule" in title or "规则" in title:
        return 20
    return 40


def _archive_sort_pending_confirmations(pending):
    items = [p for p in pending or [] if isinstance(p, dict)]
    items.sort(key=lambda p: (_archive_pending_priority(p), p.get("createdAt") or "", p.get("id") or ""))
    return items


def _archive_processed_history(record):
    history = record.get("processedGovernance")
    if not isinstance(history, list):
        history = []
    record["processedGovernance"] = history
    return history


def _archive_add_governance_history(record, item):
    history = _archive_processed_history(record)
    history.append(item)
    record["processedGovernance"] = history[-200:]
    return item


def _archive_auto_governance_notices(record):
    notices = record.get("automaticGovernanceNotices")
    if not isinstance(notices, list):
        notices = []
    record["automaticGovernanceNotices"] = notices
    return notices


def _archive_add_auto_governance_notice(record, title, summary, action="auto_resolved", source_comparison=None):
    item = {
        "id": f"auto-governance-{_proj_uuid()}",
        "at": _proj_now(),
        "action": action,
        "title": title or "自动治理",
        "summary": summary or "",
        "sourceComparison": source_comparison or {},
        "actor": ARCHIVE_MANAGER_AGENT_ID,
    }
    notices = _archive_auto_governance_notices(record)
    notices.append(item)
    record["automaticGovernanceNotices"] = notices[-20:]
    _archive_add_governance_history(record, {
        "id": f"governance-{_proj_uuid()}",
        "pendingId": "",
        "action": action,
        "status": ARCHIVE_AUTH_MANAGER,
        "actor": ARCHIVE_MANAGER_AGENT_ID,
        "at": item["at"],
        "reason": summary or "",
        "title": title or "自动治理",
        "text": summary or "",
        "sourceComparison": source_comparison or {},
    })
    return item


def _archive_source_label(source):
    source = source if isinstance(source, dict) else {}
    return source.get("title") or source.get("id") or source.get("type") or source.get("sourceType") or ""


def _archive_source_comparison(old_entry, new_entry, judgment):
    old_sources = (old_entry or {}).get("sources") or []
    new_sources = (new_entry or {}).get("sources") or []
    old_source = old_sources[0] if old_sources and isinstance(old_sources[0], dict) else {}
    new_source = new_sources[0] if new_sources and isinstance(new_sources[0], dict) else {}
    return {
        "oldEntryId": (old_entry or {}).get("id") or "",
        "oldTitle": (old_entry or {}).get("title") or "",
        "oldText": (old_entry or {}).get("text") or "",
        "oldSource": old_source,
        "oldSourceLabel": _archive_source_label(old_source),
        "oldSourceType": old_source.get("type") or old_source.get("sourceType") or "",
        "oldSourceAt": old_source.get("at") or "",
        "newEntryId": (new_entry or {}).get("id") or "",
        "newTitle": (new_entry or {}).get("title") or "",
        "newText": (new_entry or {}).get("text") or "",
        "newSource": new_source,
        "newSourceLabel": _archive_source_label(new_source),
        "newSourceType": new_source.get("type") or new_source.get("sourceType") or "",
        "newSourceAt": new_source.get("at") or "",
        "managerJudgment": judgment or "",
    }


def _archive_find_non_human_superseded_entry(record, new_entry):
    title = str((new_entry or {}).get("title") or "").strip().lower()
    kind = str((new_entry or {}).get("kind") or "").strip().lower()
    text = str((new_entry or {}).get("text") or "").strip().lower()
    for entry in record.get("entries") or []:
        if not isinstance(entry, dict) or entry.get("id") == (new_entry or {}).get("id"):
            continue
        authority = _archive_normalize_authority(entry)
        if authority in {ARCHIVE_AUTH_HUMAN, ARCHIVE_AUTH_REJECTED, ARCHIVE_AUTH_PENDING_HUMAN, ARCHIVE_AUTH_DEFERRED}:
            continue
        if entry.get("stale"):
            continue
        same_title = title and title == str(entry.get("title") or "").strip().lower()
        same_kind = kind and kind == str(entry.get("kind") or "").strip().lower()
        overlapping_text = text and str(entry.get("text") or "").strip().lower() and (text in str(entry.get("text") or "").strip().lower() or str(entry.get("text") or "").strip().lower() in text)
        if same_title or (same_kind and overlapping_text):
            return entry
    return None


def _archive_mark_entry_stale(entry, replacement, reason, source_comparison=None):
    if not isinstance(entry, dict):
        return entry
    entry["stale"] = True
    entry["staleAt"] = _proj_now()
    entry["staleReason"] = reason or "Superseded by newer archive manager governance."
    entry["replacedBy"] = (replacement or {}).get("id") or ""
    entry["sourceComparison"] = source_comparison or entry.get("sourceComparison") or {}
    entry["updatedAt"] = _proj_now()
    return entry


def _archive_add_pending_confirmation(record, event_key, title, text, source, reason="", impact="state", conflict=None, kind="pending"):
    pending = record.get("pendingConfirmations")
    if not isinstance(pending, list):
        pending = []
    item_id = f"pending-{event_key[:16]}"
    existing = next((item for item in pending if item.get("id") == item_id), None)
    payload = {
        "id": item_id,
        "title": title,
        "text": text,
        "confidence": ARCHIVE_PENDING,
        "authority": ARCHIVE_AUTH_PENDING_HUMAN,
        "impact": impact,
        "reason": reason,
        "sources": [source] if source else [],
        "createdAt": (existing or {}).get("createdAt") or _proj_now(),
        "updatedAt": _proj_now(),
        "status": ARCHIVE_AUTH_PENDING_HUMAN,
        "kind": kind,
        "entryId": f"{kind}-{event_key[:16]}",
    }
    if isinstance(conflict, dict):
        payload["conflict"] = True
        payload["conflictSummary"] = conflict.get("summary") or reason or "New archive suggestion conflicts with confirmed content."
        payload["confirmedSide"] = conflict.get("confirmedSide") or {}
        payload["suggestedSide"] = conflict.get("suggestedSide") or {"title": title, "text": text}
    if existing:
        existing.update(payload)
    else:
        pending.append(payload)
    record["pendingConfirmations"] = _archive_sort_pending_confirmations(pending)[-100:]
    return payload


def _archive_manager_profile_files():
    try:
        with open(ARCHIVE_MANAGER_PROFILE_TEMPLATE, "r", encoding="utf-8") as f:
            template = f.read()
    except OSError as exc:
        raise RuntimeError(f"Archive manager profile template cannot be read: {exc}") from exc

    version = _archive_manager_profile_template_version(template)
    files = {}
    current_name = None
    current_lines = []
    marker_re = re.compile(r"^--- file:\s*([A-Za-z0-9_.-]+)\s*---\s*$")
    for line in template.splitlines():
        marker = marker_re.match(line)
        if marker:
            if current_name:
                files[current_name] = "\n".join(current_lines).strip() + "\n"
            current_name = marker.group(1)
            current_lines = []
            continue
        if current_name:
            current_lines.append(line)
    if current_name:
        files[current_name] = "\n".join(current_lines).strip() + "\n"

    replacements = {
        "{{ARCHIVE_MANAGER_NAME}}": ARCHIVE_MANAGER_NAME,
        "{{ARCHIVE_MANAGER_EMOJI}}": ARCHIVE_MANAGER_EMOJI,
        "{{ARCHIVE_MANAGER_AGENT_ID}}": ARCHIVE_MANAGER_AGENT_ID,
        "{{ARCHIVE_MANAGER_PROFILE_VERSION}}": version,
    }
    rendered = {}
    for filename, content in files.items():
        for token, value in replacements.items():
            content = content.replace(token, value)
        rendered[filename] = content

    required = {"IDENTITY.md", "SOUL.md", "AGENTS.md", "agent.md", "MEMORY.md", "HEARTBEAT.md"}
    missing = sorted(required - set(rendered))
    if missing:
        raise RuntimeError(f"Archive manager profile template missing files: {', '.join(missing)}")
    return rendered


def _archive_manager_profile_template_version(template=None):
    if template is None:
        try:
            with open(ARCHIVE_MANAGER_PROFILE_TEMPLATE, "r", encoding="utf-8") as f:
                template = f.read(4096)
        except OSError as exc:
            raise RuntimeError(f"Archive manager profile template cannot be read: {exc}") from exc
    for line in str(template or "").splitlines()[:20]:
        if line.lower().startswith("archive-manager-profile-version:"):
            version = line.split(":", 1)[1].strip()
            if version:
                return version
    raise RuntimeError("Archive manager profile template missing Archive-Manager-Profile-Version header")


def _archive_manager_roster_agent():
    refresh_agent_maps()
    for agent in get_roster():
        if str(agent.get("id") or "") == ARCHIVE_MANAGER_AGENT_ID or str(agent.get("statusKey") or "") == ARCHIVE_MANAGER_AGENT_ID:
            return agent
        if str(agent.get("name") or "").strip() == ARCHIVE_MANAGER_NAME:
            return agent
    return None


def _archive_manager_workspace(agent_id):
    safe_id = _sanitize_agent_id(agent_id or ARCHIVE_MANAGER_AGENT_ID)
    roster_agent = _archive_manager_roster_agent()
    workspace = ""
    if roster_agent and str(roster_agent.get("id") or "") == (agent_id or ARCHIVE_MANAGER_AGENT_ID):
        workspace = str(roster_agent.get("workspace") or "")
    if not workspace:
        workspace = os.path.join(WORKSPACE_BASE, f"workspace-{safe_id}")
    base = os.path.realpath(WORKSPACE_BASE)
    real_workspace = os.path.realpath(workspace)
    if not (real_workspace == base or real_workspace.startswith(base + os.sep)):
        raise ValueError("Archive manager workspace is outside OpenClaw home")
    return real_workspace


def _archive_manager_write_direct_profile_file(agent_id, filename, content):
    workspace = _archive_manager_workspace(agent_id)
    os.makedirs(workspace, exist_ok=True)
    path = os.path.realpath(os.path.join(workspace, filename))
    if not path.startswith(workspace + os.sep):
        raise ValueError("Archive manager profile path is outside workspace")
    tmp = path + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        f.write(content)
        if content and not content.endswith("\n"):
            f.write("\n")
    os.replace(tmp, path)
    try:
        os.chmod(path, 0o666)
    except OSError:
        pass
    return workspace


def _archive_manager_read_profile_file_version(workspace, filename):
    path = os.path.realpath(os.path.join(workspace, filename))
    real_workspace = os.path.realpath(workspace)
    if not path.startswith(real_workspace + os.sep):
        return ""
    try:
        with open(path, "r", encoding="utf-8") as f:
            head = f.read(512)
    except OSError:
        return ""
    match = ARCHIVE_MANAGER_PROFILE_VERSION_RE.search(head)
    return match.group(1).strip() if match else ""


def _archive_manager_profile_needs_update(agent_id, profile_files, target_version):
    try:
        workspace = _archive_manager_workspace(agent_id)
    except Exception:
        return True
    for filename in profile_files:
        if _archive_manager_read_profile_file_version(workspace, filename) != target_version:
            return True
    return False


def _archive_manager_write_profile_files(agent_id):
    try:
        profile_files = _archive_manager_profile_files()
        target_version = _archive_manager_profile_template_version()
    except Exception as exc:
        return {"ok": False, "error": str(exc)}
    if not _archive_manager_profile_needs_update(agent_id, profile_files, target_version):
        try:
            workspace = _archive_manager_workspace(agent_id)
        except Exception:
            workspace = ""
        return {"ok": True, "profileFiles": list(profile_files.keys()), "workspace": workspace, "profileVersion": target_version, "updated": False}
    written = []
    workspace = ""
    for filename, content in profile_files.items():
        try:
            workspace = _archive_manager_write_direct_profile_file(agent_id, filename, content)
            written.append(filename)
        except Exception as exc:
            return {"ok": False, "error": f"failed to write {filename}: {exc}"}
    return {"ok": True, "profileFiles": written, "workspace": workspace, "profileVersion": target_version, "updated": True}


def _archive_manager_create_if_missing():
    state = _archive_manager_load_state()
    existing = _archive_manager_roster_agent()
    if existing:
        profile_result = _archive_manager_write_profile_files(existing.get("id") or ARCHIVE_MANAGER_AGENT_ID)
        if not profile_result.get("ok"):
            state["agentId"] = existing.get("id") or ARCHIVE_MANAGER_AGENT_ID
            state["name"] = ARCHIVE_MANAGER_NAME
            state["providerKind"] = existing.get("providerKind", "openclaw")
            state["workspace"] = existing.get("workspace", "")
            state["status"] = "error"
            state["label"] = "档案管理员配置失败"
            state["lastError"] = profile_result.get("error", "")
            _archive_manager_append_activity(state, "profile_repair", "error", "档案管理员 profile 写入失败", error=state["lastError"])
            return _archive_manager_save_state(state)
        state["agentId"] = existing.get("id") or ARCHIVE_MANAGER_AGENT_ID
        state["name"] = ARCHIVE_MANAGER_NAME
        state["providerKind"] = existing.get("providerKind", "openclaw")
        state["workspace"] = profile_result.get("workspace") or existing.get("workspace", "")
        state["profileFiles"] = profile_result.get("profileFiles", [])
        state["profileVersion"] = profile_result.get("profileVersion", "")
        if profile_result.get("updated"):
            state["profileUpdatedAt"] = _proj_now()
            _archive_manager_append_activity(state, "profile_update", "ok", f"档案管理员 profile 已更新到版本 {state.get('profileVersion', '')}")
        state["status"] = "paused" if state.get("paused") else "idle"
        state["label"] = "已暂停" if state.get("paused") else ("已自动创建" if state.get("autoCreated") else "已接入")
        state["lastError"] = ""
        _archive_manager_save_state(state)
        return state

    now = _proj_now()
    workspace_dir = os.path.join(WORKSPACE_BASE, f"workspace-{ARCHIVE_MANAGER_AGENT_ID}")
    try:
        create_params = {
            "name": ARCHIVE_MANAGER_AGENT_ID,
            "workspace": workspace_dir,
            "emoji": ARCHIVE_MANAGER_EMOJI,
        }
        selected_model = _default_openclaw_agent_model()
        if selected_model:
            create_params["model"] = selected_model
        result = _gateway_rpc_call("agents.create", create_params, timeout=30)
        if not result.get("ok"):
            state["status"] = "error"
            state["label"] = "档案管理员创建失败"
            state["lastError"] = result.get("error", "OpenClaw agent creation failed")
            _archive_manager_append_activity(state, "auto_create", "error", "自动创建档案管理员失败", error=state["lastError"])
            return _archive_manager_save_state(state)

        agent_id = result.get("agentId") or ARCHIVE_MANAGER_AGENT_ID
        profile_result = _archive_manager_write_profile_files(agent_id)
        if not profile_result.get("ok"):
            state["status"] = "error"
            state["label"] = "档案管理员创建失败"
            state["agentId"] = agent_id
            state["lastError"] = profile_result.get("error", "")
            _archive_manager_append_activity(state, "auto_create", "error", "档案管理员已创建但 profile 写入失败", error=state["lastError"])
            return _archive_manager_save_state(state)

        global _discovered_at
        _discovered_at = 0
        refresh_agent_maps()
        state.update({
            "agentId": agent_id,
            "name": ARCHIVE_MANAGER_NAME,
            "providerKind": "openclaw",
            "status": "idle",
            "label": "已自动创建",
            "paused": False,
            "autoCreated": True,
            "createdAt": now,
            "workspace": profile_result.get("workspace") or workspace_dir,
            "profileFiles": profile_result.get("profileFiles", []),
            "profileVersion": profile_result.get("profileVersion", ""),
            "profileUpdatedAt": now if profile_result.get("updated") else None,
            "lastError": "",
        })
        _archive_manager_append_activity(state, "auto_create", "ok", "已自动创建档案管理员")
        return _archive_manager_save_state(state)
    except Exception as exc:
        state["status"] = "error"
        state["label"] = "档案管理员创建失败"
        state["lastError"] = str(exc)
        _archive_manager_append_activity(state, "auto_create", "error", "自动创建档案管理员失败", error=str(exc))
        return _archive_manager_save_state(state)


def _archive_manager_profile_check_on_startup():
    """Keep the built-in archive manager profile in sync with VO's template."""
    time.sleep(4)
    try:
        state = _archive_manager_create_if_missing()
        if state.get("status") == "error":
            print(f"[ARCHIVE MANAGER] profile check failed: {state.get('lastError') or 'unknown error'}")
            return
        version = state.get("profileVersion") or ""
        if version:
            print(f"[ARCHIVE MANAGER] profile ready: {state.get('agentId') or ARCHIVE_MANAGER_AGENT_ID} version={version}")
        else:
            print(f"[ARCHIVE MANAGER] profile ready: {state.get('agentId') or ARCHIVE_MANAGER_AGENT_ID}")
    except Exception as exc:
        print(f"[ARCHIVE MANAGER] startup profile check failed: {exc}")


def _archive_manager_public_state(ensure=True):
    state = _archive_manager_create_if_missing() if ensure else _archive_manager_load_state()
    if state.get("paused"):
        state["status"] = "paused"
        state["label"] = "已暂停"
    return {
        "agentId": state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID,
        "name": state.get("name") or ARCHIVE_MANAGER_NAME,
        "emoji": state.get("emoji") or ARCHIVE_MANAGER_EMOJI,
        "providerKind": state.get("providerKind", "openclaw"),
        "status": state.get("status", "missing"),
        "label": state.get("label", "未接入"),
        "phase": "phase-4",
        "paused": bool(state.get("paused")),
        "autoCreated": bool(state.get("autoCreated")),
        "createdAt": state.get("createdAt"),
        "updatedAt": state.get("updatedAt"),
        "profileVersion": state.get("profileVersion", ""),
        "profileUpdatedAt": state.get("profileUpdatedAt"),
        "lastAction": state.get("lastAction", ""),
        "lastError": state.get("lastError", ""),
        "recentActivity": (state.get("recentActivity") or [])[-12:],
    }


def _agent_archive_manager_meta(agent_id_or_key):
    state = _archive_manager_load_state()
    if not _is_archive_manager_agent(agent_id_or_key):
        return {}
    if state.get("status") == "missing" and str(agent_id_or_key or "") in {ARCHIVE_MANAGER_AGENT_ID, ARCHIVE_MANAGER_NAME}:
        state["status"] = "idle"
        state["label"] = "已接入"
        state["agentId"] = ARCHIVE_MANAGER_AGENT_ID
        state["name"] = ARCHIVE_MANAGER_NAME
    return {
        "systemRole": "archive_manager",
        "assignable": False,
        "archiveManager": True,
        "archiveManagerStatus": state.get("status", "missing"),
        "archiveManagerPaused": bool(state.get("paused")),
        "archiveManagerLabel": state.get("label", "未接入"),
    }


def _is_archive_manager_agent(agent_id_or_key):
    needle = str(agent_id_or_key or "")
    if needle in {ARCHIVE_MANAGER_AGENT_ID, ARCHIVE_MANAGER_NAME}:
        return True
    state = _archive_manager_load_state()
    return bool(needle and needle in {str(state.get("agentId") or ""), str(state.get("name") or "")})


def _is_archive_related_message(message):
    text = str(message or "").lower()
    keywords = [
        "档案", "归档", "档案室", "项目产物", "产物", "上下文", "入场包", "目录", "来源", "证据",
        "archive", "archives", "archival", "artifact", "artifacts", "onboarding", "context",
        "catalog", "source", "sources", "evidence", "summary", "summaries",
    ]
    return any(k in text for k in keywords)


def _archive_manager_out_of_scope_response():
    return (
        "我是档案管理员，只处理档案室、项目上下文、产物来源、入场包和归档维护相关问题。"
        "普通执行、编码、审查、闲聊或项目任务分配请转给对应执行 AI。"
    )


def _archive_manager_chat_guard(to_agent_id, message):
    if not _is_archive_manager_agent(to_agent_id):
        return None
    if _is_archive_related_message(message):
        return None
    return {
        "ok": True,
        "reply": _archive_manager_out_of_scope_response(),
        "status": "archive_manager_out_of_scope",
        "archiveManager": _archive_manager_public_state(ensure=False),
    }


def _handle_archive_manager_update(body):
    action = str((body or {}).get("action") or "").strip().lower()
    try:
        state = _archive_manager_create_if_missing()
    except Exception as exc:
        state = _archive_manager_load_state()
        state["status"] = "error"
        state["label"] = "档案管理员不可用"
        state["lastError"] = str(exc)
        _archive_manager_append_activity(state, f"auto_{event_type}", "error", "自动整理失败", project_id=project_id, error=str(exc))
        try:
            _archive_manager_save_state(state)
        except Exception:
            pass
        return {"ok": False, "status": "error", "error": str(exc), "eventType": event_type}
    if action == "pause":
        state["paused"] = True
        state["status"] = "paused"
        state["label"] = "已暂停"
        _archive_manager_append_activity(state, "pause", "ok", "档案管理员已暂停")
        gateway_presence.set_manual_override(state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID, "break", "Archive manager paused")
        saved = _archive_manager_save_state(state)
        return {"ok": True, "archiveManager": _archive_manager_public_state(ensure=False), "activity": (saved.get("recentActivity") or [])[-1]}
    if action == "resume":
        state["paused"] = False
        state["status"] = "idle"
        state["label"] = "已接入"
        _archive_manager_append_activity(state, "resume", "ok", "档案管理员已恢复")
        gateway_presence.set_manual_override(state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID, "idle", "")
        saved = _archive_manager_save_state(state)
        return {"ok": True, "archiveManager": _archive_manager_public_state(ensure=False), "activity": (saved.get("recentActivity") or [])[-1]}
    return {"error": "Unsupported archive manager action", "_status": 400}


def _handle_archive_manager_manual_maintain(project_id):
    data = _load_projects()
    project = next((p for p in data.get("projects", []) if isinstance(p, dict) and p.get("id") == project_id), None)
    if not project:
        return {"error": "Project not found", "_status": 404}
    try:
        state = _archive_manager_create_if_missing()
    except Exception as exc:
        state = _archive_manager_load_state()
        state["status"] = "error"
        state["label"] = "档案管理员不可用"
        state["lastError"] = str(exc)
        _archive_manager_append_activity(state, f"auto_{event_type}", "error", "自动整理失败", project_id=project_id, error=str(exc))
        try:
            _archive_manager_save_state(state)
        except Exception:
            pass
        return {"ok": False, "status": "error", "error": str(exc), "eventType": event_type}
    if state.get("status") == "error":
        _archive_manager_append_activity(state, "manual_maintain", "error", "当前项目手动整理失败", project_id=project_id, error=state.get("lastError", "archive manager unavailable"))
        _archive_manager_save_state(state)
        return {"error": state.get("lastError") or "Archive manager unavailable", "archiveManager": _archive_manager_public_state(ensure=False), "_status": 409}
    started_at = _proj_now()
    state["status"] = "working"
    state["label"] = "整理中"
    _archive_manager_append_activity(state, "manual_maintain", "running", f"开始整理项目：{project.get('title', '')}", project_id=project_id)
    _archive_manager_save_state(state)
    record = _archive_room_derive_project(project)
    record.setdefault("managerMaintainedAt", started_at)
    record.setdefault("managerMaintenance", [])
    record["managerMaintenance"] = (record.get("managerMaintenance") or [])[-20:] + [{
        "at": started_at,
        "managerAgentId": state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID,
        "status": "ok",
        "summary": "Manual current-project archive maintenance completed.",
        "output": {
            "status": "ok",
            "projectId": project_id,
            "summary": "当前项目档案已根据现有项目、任务和产物记录刷新。",
            "sources": [{"type": "project", "id": project_id}],
            "updates": [{"kind": "summary", "confidence": ARCHIVE_INFERENCE, "text": record.get("summary", {}).get("currentState", "")}],
            "error": "",
        },
    }]
    _archive_room_save_project_record(project_id, record)
    state["status"] = "paused" if state.get("paused") else "idle"
    state["label"] = "已暂停" if state.get("paused") else "已接入"
    _archive_manager_append_activity(state, "manual_maintain", "ok", f"完成整理项目：{project.get('title', '')}", project_id=project_id)
    _archive_manager_save_state(state)
    return {"ok": True, "project": record, "archiveManager": _archive_manager_public_state(ensure=False)}


def _archive_manager_ai_refine_prompt(project, record):
    metrics = record.get("metrics") or {}
    entries = record.get("entries") if isinstance(record.get("entries"), list) else []
    pending = record.get("pendingConfirmations") if isinstance(record.get("pendingConfirmations"), list) else []
    artifacts = record.get("artifacts") if isinstance(record.get("artifacts"), list) else []
    compact_entries = [
        {
            "id": e.get("id"),
            "title": e.get("title"),
            "kind": e.get("kind"),
            "authority": _archive_normalize_authority(e),
            "stale": bool(e.get("stale")),
            "text": str(e.get("text") or "")[:600],
        }
        for e in entries[:20]
        if isinstance(e, dict)
    ]
    compact_pending = [
        {
            "id": item.get("id"),
            "title": item.get("title"),
            "impact": item.get("impact"),
            "reason": item.get("reason") or item.get("automationInsufficientReason"),
            "text": str(item.get("text") or "")[:500],
        }
        for item in pending[:10]
        if isinstance(item, dict)
    ]
    compact_artifacts = [
        {
            "path": a.get("path"),
            "kind": a.get("kind"),
            "sources": [
                {
                    "taskTitle": s.get("taskTitle"),
                    "agentId": s.get("agentId"),
                    "providerKind": s.get("providerKind"),
                    "capturedAt": s.get("capturedAt"),
                }
                for s in (a.get("sources") or [])[:3]
                if isinstance(s, dict)
            ],
        }
        for a in artifacts[:20]
        if isinstance(a, dict)
    ]
    payload = {
        "project": {
            "id": project.get("id"),
            "title": project.get("title"),
            "description": project.get("description"),
            "status": project.get("status"),
            "metrics": metrics,
            "currentTask": (_archive_current_task(project) or {}).get("title") or "",
        },
        "archive": {
            "summary": record.get("summary") or {},
            "entries": compact_entries,
            "pendingConfirmations": compact_pending,
            "artifacts": compact_artifacts,
            "archiveIntroduction": record.get("archiveIntroduction") or {},
            "projectBasicInfo": record.get("projectBasicInfo") or {},
        },
    }
    return (
        "你是 Virtual Office 的档案管理员 archive-manager。请对当前项目档案做一次精确整理和概括。\n"
        "工作边界：只整理档案室上下文，不执行普通项目任务，不修改项目代码，不创建会议。\n"
        "请基于输入中的项目、任务、产物、已有档案、待确认项和来源信息，产出稳定 JSON。不要输出 JSON 以外的文字。\n"
        "如果信息不足，请在 gaps 中说明，不要编造事实。stale 或 pending 内容不能当作已确认事实。\n\n"
        "必须返回如下 JSON 对象：\n"
        "{\n"
        "  \"status\": \"ok|needs_human|error\",\n"
        "  \"summary\": \"面向人类的项目档案精整摘要，2-4 句\",\n"
        "  \"currentState\": \"当前状态，一句话\",\n"
        "  \"nextStep\": \"建议下一步，一句话；不确定则写空字符串\",\n"
        "  \"highlights\": [\"关键事实或判断，最多 5 条\"],\n"
        "  \"risks\": [\"风险/冲突/待确认，最多 5 条\"],\n"
        "  \"gaps\": [\"缺失信息或需要人工确认的问题，最多 5 条\"],\n"
        "  \"archiveEntries\": [\n"
        "    {\"title\":\"条目标题\",\"kind\":\"summary|risk|decision|artifact|context\",\"text\":\"条目内容\",\"confidence\":\"ai_inference|manager_confirmed\"}\n"
        "  ]\n"
        "}\n\n"
        "输入数据：\n"
        f"{json.dumps(payload, ensure_ascii=False, indent=2)}"
    )


def _archive_apply_ai_refinement(record, parsed, source, now):
    if not isinstance(parsed, dict):
        return []
    summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
    if parsed.get("currentState"):
        summary["currentState"] = str(parsed.get("currentState") or "").strip()
    if parsed.get("nextStep") is not None:
        summary["nextStep"] = str(parsed.get("nextStep") or "").strip()
    if parsed.get("summary"):
        summary["goal"] = summary.get("goal") or str(parsed.get("summary") or "").strip()
    record["summary"] = summary
    updates = []
    for idx, item in enumerate(parsed.get("archiveEntries") or []):
        if not isinstance(item, dict):
            continue
        title = str(item.get("title") or "").strip()
        text = str(item.get("text") or "").strip()
        if not title or not text:
            continue
        entry = _archive_entry(
            f"ai-refine-{hashlib.sha1((title + text).encode('utf-8')).hexdigest()[:16]}",
            title,
            text,
            item.get("confidence") or ARCHIVE_INFERENCE,
            source,
        )
        entry["kind"] = str(item.get("kind") or "summary").strip() or "summary"
        entry["updatedAt"] = now
        _archive_apply_authority(entry, ARCHIVE_AUTH_MANAGER, actor=ARCHIVE_MANAGER_AGENT_ID)
        _archive_upsert_entry(record, entry)
        updates.append(entry)
        if len(updates) >= 8:
            break
    return updates


def _archive_validate_ai_refinement(parsed, raw_reply=""):
    if str(raw_reply or "").startswith("[ERROR]"):
        return "档案管理员调用失败，未产生有效精整结果。"
    if not isinstance(parsed, dict):
        return "档案管理员未返回可解析的稳定 JSON。"
    if parsed.get("runId") or parsed.get("timeoutPhase") or parsed.get("providerStarted"):
        return "档案管理员调用超时或被中断，未产生有效精整结果。"
    status = str(parsed.get("status") or "").strip()
    if status not in {"ok", "needs_human", "error"}:
        return "档案管理员返回的 JSON status 不符合约定。"
    if status == "error":
        return str(parsed.get("summary") or parsed.get("error") or "档案管理员返回精整失败。")
    content_keys = ("summary", "currentState", "nextStep", "highlights", "risks", "gaps", "archiveEntries")
    if not any(parsed.get(k) for k in content_keys):
        return "档案管理员返回的 JSON 缺少可入档内容。"
    return ""


def _handle_archive_manager_ai_refine(project_id, body=None):
    data = _load_projects()
    project = next((p for p in data.get("projects", []) if isinstance(p, dict) and p.get("id") == project_id), None)
    if not project:
        return {"error": "Project not found", "_status": 404}
    try:
        state = _archive_manager_create_if_missing()
    except Exception as exc:
        return {"error": str(exc), "archiveManager": _archive_manager_public_state(ensure=False), "_status": 409}
    if state.get("status") == "error":
        return {"error": state.get("lastError") or "Archive manager unavailable", "archiveManager": _archive_manager_public_state(ensure=False), "_status": 409}
    if state.get("paused") and not (body or {}).get("allowWhenPaused"):
        return {"error": "档案管理员已暂停，不能执行 AI 精整。", "archiveManager": _archive_manager_public_state(ensure=False), "_status": 409}
    now = _proj_now()
    state["status"] = "working"
    state["label"] = "精整中"
    _archive_manager_append_activity(state, "ai_refine", "running", f"开始 AI 精整项目档案：{project.get('title', '')}", project_id=project_id)
    _archive_manager_save_state(state)
    record = _archive_room_derive_project(project)
    prompt = _archive_manager_ai_refine_prompt(project, record)
    reply = _wf_call_agent(state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID, prompt, timeout=int((body or {}).get("timeoutSec") or 600), project_id=project_id, task_id="archive-ai-refine")
    parsed = _meeting_parse_json_object(reply)
    source = _archive_source_ref("archive_manager_ai_refine", f"ai-refine:{now}", title="档案管理员 AI 精整", agentId=state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID)
    status = "ok"
    error = _archive_validate_ai_refinement(parsed, reply)
    updates = []
    if error:
        status = "error"
    else:
        updates = _archive_apply_ai_refinement(record, parsed, source, now)
    record.setdefault("managerMaintainedAt", now)
    item = {
        "id": _proj_uuid(),
        "at": now,
        "managerAgentId": state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID,
        "status": status,
        "eventType": "ai_refine",
        "triggerType": "manual_ai_refine",
        "projectId": project_id,
        "summary": (parsed or {}).get("summary") if isinstance(parsed, dict) else ("档案管理员 AI 精整失败" if status == "error" else "档案管理员 AI 精整完成"),
        "prompt": prompt,
        "rawReply": reply,
        "output": {
            "status": status,
            "projectId": project_id,
            "summary": (parsed or {}).get("summary") if isinstance(parsed, dict) else "",
            "parsed": parsed or {},
            "sources": [source],
            "updates": updates,
            "error": error,
        },
        "error": error,
    }
    _archive_append_project_maintenance(record, item)
    record["archiveUpdatedAt"] = now
    _archive_room_save_project_record(project_id, record)
    state["status"] = "paused" if state.get("paused") else "idle"
    state["label"] = "已暂停" if state.get("paused") else "已接入"
    _archive_manager_append_activity(state, "ai_refine", status, "完成 AI 精整项目档案" if status == "ok" else "AI 精整项目档案失败", project_id=project_id, error=error)
    _archive_manager_save_state(state)
    derived = _archive_room_derive_project(project)
    return {"ok": status == "ok", "status": status, "project": derived, "archiveManager": _archive_manager_public_state(ensure=False), "maintenance": item, "error": error, "_status": 200 if status == "ok" else 502}


def _archive_maintenance_trigger(project_id, event_type, source=None, title="", summary="", value_level=None, reason="", impact="", allow_when_paused=False):
    source = source if isinstance(source, dict) else {}
    event_type = str(event_type or "").strip()
    if event_type not in ARCHIVE_TRIGGER_EVENT_TYPES and event_type not in ARCHIVE_INSPECTION_KINDS:
        return {"ok": False, "status": "error", "error": "Unsupported archive maintenance event", "eventType": event_type}
    data = _load_projects()
    project = next((p for p in data.get("projects", []) if isinstance(p, dict) and p.get("id") == project_id), None)
    if not project:
        return {"ok": False, "status": "error", "error": "Project not found", "_status": 404}
    try:
        state = _archive_manager_create_if_missing()
    except Exception as exc:
        state = _archive_manager_load_state()
        state["status"] = "error"
        state["label"] = "档案管理员不可用"
        state["lastError"] = str(exc)
        _archive_manager_append_activity(state, f"auto_{event_type}", "error", "自动整理失败", project_id=project_id, error=str(exc))
        try:
            _archive_manager_save_state(state)
        except Exception:
            pass
        return {"ok": False, "status": "error", "error": str(exc), "eventType": event_type}
    event_key = _archive_event_key(project_id, event_type, source, fallback=summary or title)
    high_value = event_type in ARCHIVE_HIGH_VALUE_EVENTS or value_level == "high"
    routine = event_type in ARCHIVE_INSPECTION_KINDS
    maintenance = _archive_project_maintenance_meta(project)
    record = _archive_room_derive_project(project)
    now = _proj_now()

    def save_outcome(status, message, entry=None, noisy=True, error=""):
        if status == "skipped" and routine:
            _archive_update_schedule_state(record, kind=source.get("scheduleKind") or event_type, status="skipped", at=now, reason=message)
        item = {
            "id": _proj_uuid(),
            "at": now,
            "managerAgentId": state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID,
            "status": status,
            "eventType": event_type,
            "triggerType": event_type,
            "projectId": project_id,
            "source": source,
            "summary": message,
            "classificationReason": reason or "",
            "valueLevel": "high" if high_value else (value_level or "normal"),
            "eventKey": event_key,
            "error": error or "",
            "output": {
                "status": status,
                "projectId": project_id,
                "summary": message,
                "sources": [source] if source else [],
                "updates": [entry] if entry else [],
                "error": error or "",
            },
        }
        if noisy:
            _archive_append_project_maintenance(record, item)
        _archive_room_save_project_record(project_id, record)
        _archive_manager_append_activity(state, f"auto_{event_type}", status, message, project_id=project_id, error=error)
        _archive_manager_save_state(state)
        return {"ok": status not in {"error"}, "status": status, "project": record, "activity": item, "archiveManager": _archive_manager_public_state(ensure=False)}

    if state.get("status") == "error":
        return save_outcome("error", "自动整理失败：档案管理员不可用", error=state.get("lastError", "archive manager unavailable"))
    if state.get("paused") and not allow_when_paused:
        return save_outcome("skipped", "档案管理员已暂停，自动整理已跳过。", noisy=True)
    if not maintenance.get("enabled") and not high_value:
        return save_outcome("skipped", "项目未开启长期维护，低价值事件已跳过。", noisy=False)
    processed = _archive_project_processed_events(record)
    if processed.get(event_key):
        return save_outcome("skipped", "该来源事件已整理，已幂等跳过。", noisy=False)

    if routine:
        inspection_key = "lastStartupInspectionAt" if event_type == "startup_inspection" else "lastDailyInspectionAt"
        record.setdefault("inspections", {})[inspection_key] = now
        schedule_kind = source.get("scheduleKind") or ("startup_inspection" if event_type == "startup_inspection" else "daily_inspection")
        if schedule_kind == "weekly_inspection":
            record.setdefault("inspections", {})["lastWeeklyInspectionAt"] = now
        _archive_update_schedule_state(record, kind=schedule_kind, status="no_update", at=now)
        record["archiveUpdatedAt"] = now
        processed[event_key] = {"eventType": event_type, "processedAt": now, "status": "no_update"}
        return save_outcome("no_update", "巡检完成，未发现需要更新的档案内容。", noisy=False)

    objective_events = {"task_completed", "important_artifact", "project_status_changed"}
    manager_confirmed_events = {"important_message", "important_chat_classification", "ai_stage_summary"}
    confidence = ARCHIVE_CONFIRMED if event_type in objective_events else ARCHIVE_INFERENCE
    text = summary or title or f"Archive maintenance event: {event_type}"
    entry_title = title or event_type.replace("_", " ").title()
    high_impact = (impact or "").strip().lower() in {"state", "task", "risk", "project_status", "task_conclusion", "risk_judgment"}
    human_conflict = event_type == "conflict_reminder" and any(
        _archive_normalize_authority(e) == ARCHIVE_AUTH_HUMAN
        for e in record.get("entries", []) if isinstance(e, dict)
    )
    owner_decision_terms = ["owner", "人类", "human", "approval", "批准", "规则", "rule", "policy", "策略"]
    owner_decision = high_impact and any(term in (text + " " + entry_title + " " + reason).lower() for term in owner_decision_terms)
    archive_manager_first_auto = event_type in {"meeting_conclusion", "conflict_reminder"} and not human_conflict and not owner_decision
    requires_human_confirmation = event_type not in objective_events and not archive_manager_first_auto and (
        event_type in {"meeting_conclusion", "conflict_reminder"} or high_impact or confidence == ARCHIVE_PENDING
    )
    entry = _archive_entry_from_event(event_key, entry_title, text, confidence, source, kind=event_type)
    if event_type in objective_events:
        _archive_apply_authority(entry, ARCHIVE_AUTH_SYSTEM if event_type == "project_status_changed" else ARCHIVE_AUTH_SOURCE)
        entry["confirmedBy"] = "system"
        entry["confirmedAt"] = now
        entry["confirmationReason"] = "Objective VO source event."
    elif requires_human_confirmation:
        _archive_apply_authority(entry, ARCHIVE_AUTH_PENDING_HUMAN)
    elif archive_manager_first_auto:
        _archive_apply_authority(entry, ARCHIVE_AUTH_MANAGER, actor=state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID)
        entry["confirmedAt"] = now
        entry["confirmationReason"] = reason or "Archive manager automatically resolved non-human-confirmed governance."
    elif event_type in manager_confirmed_events and not high_value and (impact or "").strip().lower() not in {"state", "task", "risk", "project_status", "task_conclusion", "risk_judgment"}:
        _archive_apply_authority(entry, ARCHIVE_AUTH_MANAGER, actor=state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID)
        entry["confirmedAt"] = now
        entry["confirmationReason"] = reason or "Archive manager judged this source-backed summary low risk."
    else:
        _archive_apply_authority(entry, ARCHIVE_AUTH_MANAGER, actor=state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID)
    superseded = None
    source_comparison = None
    if archive_manager_first_auto:
        superseded = _archive_find_non_human_superseded_entry(record, entry)
        if superseded:
            source_comparison = _archive_source_comparison(superseded, entry, reason or "新来源更强，档案管理员自动更新非人工确认内容。")
            entry["sourceComparison"] = source_comparison
            entry["replaces"] = superseded.get("id") or ""
            _archive_mark_entry_stale(superseded, entry, "新来源更强，档案管理员自动标记旧内容过期。", source_comparison)
    change = _archive_upsert_entry(record, entry)
    if archive_manager_first_auto:
        _archive_add_auto_governance_notice(
            record,
            entry_title,
            "档案管理员已自动处理非人工确认内容。" + (" 旧内容已标记过期。" if superseded else ""),
            action="auto_governance_resolved",
            source_comparison=source_comparison,
        )
    pending_item = None
    if requires_human_confirmation:
        conflict = None
        if event_type == "conflict_reminder":
            confirmed_side = next((e for e in record.get("entries", []) if _archive_normalize_authority(e) == ARCHIVE_AUTH_HUMAN), None)
            source_comparison = _archive_source_comparison(confirmed_side or {}, entry, reason or "新建议与人工确认内容冲突，需要 owner 判断。")
            conflict = {
                "summary": reason or text or "New suggestion conflicts with human-confirmed archive content.",
                "confirmedSide": confirmed_side or {},
                "suggestedSide": {"title": entry_title, "text": text, "sources": [source] if source else []},
                "sourceComparison": source_comparison,
            }
        pending_item = _archive_add_pending_confirmation(
            record,
            event_key,
            entry_title,
            text,
            source,
            reason=reason or "High-impact archive update requires human confirmation.",
            impact=impact or ("risk" if event_type == "conflict_reminder" else "state"),
            conflict=conflict,
            kind=event_type,
        )
        pending_item["managerJudgment"] = "档案管理员判断该事项需要人工确认。"
        pending_item["automationInsufficientReason"] = reason or ("涉及人工确认内容或 owner 级决策，不能自动处理。" if human_conflict or owner_decision else "高影响内容需要人工确认。")
        pending_item["humanDecisionNeeded"] = "请确认、编辑确认、暂缓或拒绝该档案建议。"
        if source_comparison:
            pending_item["sourceComparison"] = source_comparison
        record["pendingConfirmations"] = _archive_sort_pending_confirmations(record.get("pendingConfirmations") or [])
    record["archiveUpdatedAt"] = now
    _archive_update_schedule_state(record, status="event", at=now)
    processed[event_key] = {"eventType": event_type, "processedAt": now, "status": change, "source": source}
    if pending_item:
        entry["pendingConfirmationId"] = pending_item.get("id")
    return save_outcome("ok", f"自动整理完成：{entry_title}", entry=entry, noisy=True)


def _archive_run_inspection(kind="startup_inspection", force=False):
    if kind not in ARCHIVE_INSPECTION_KINDS:
        return {"ok": False, "error": "Unsupported inspection kind", "_status": 400}
    data = _load_projects()
    results = []
    today = datetime.now(timezone.utc).date().isoformat()
    for project in data.get("projects", []) if isinstance(data, dict) else []:
        if not isinstance(project, dict) or project.get("template"):
            continue
        record = _archive_room_load_project_record(project.get("id"))
        if not _archive_project_maintenance_enabled(project):
            if kind == "daily_inspection":
                _archive_update_schedule_state(record, kind="daily_inspection", status="skipped", reason="项目长期维护已关闭，计划巡检已跳过。")
                _archive_room_save_project_record(project.get("id"), record)
            continue
        decision = _archive_inspection_schedule_decision(project, record, kind, force=force)
        if not decision.get("run"):
            _archive_update_schedule_state(record, kind=decision.get("scheduledKind") or kind, status="skipped", reason=decision.get("reason") or "计划巡检已跳过。")
            _archive_room_save_project_record(project.get("id"), record)
            results.append({"ok": True, "status": "skipped", "projectId": project.get("id"), "eventType": kind, "scheduleKind": decision.get("scheduledKind"), "reason": decision.get("reason")})
            continue
        schedule_kind = decision.get("scheduledKind") or kind
        source = _archive_source_ref("inspection", f"{kind}:{schedule_kind}:{today if kind == 'daily_inspection' else 'startup'}", title=kind, scheduleKind=schedule_kind)
        if kind == "daily_inspection":
            last = ((record.get("inspections") or {}).get("lastDailyInspectionAt") or "")[:10]
            if schedule_kind == "daily_inspection" and last == today and not force:
                continue
        results.append(_archive_maintenance_trigger(
            project.get("id"),
            kind,
            source=source,
            title="Archive inspection",
            summary="Scheduled archive inspection completed.",
            value_level="routine",
        ))
    return {"ok": True, "kind": kind, "results": results, "checkedProjectCount": len(results)}


def _archive_manager_startup_inspection():
    time.sleep(6)
    try:
        _archive_run_inspection("startup_inspection")
    except Exception as exc:
        state = _archive_manager_load_state()
        _archive_manager_append_activity(state, "startup_inspection", "error", "启动巡检失败", error=str(exc))
        _archive_manager_save_state(state)


def _handle_archive_project_maintenance_update(project_id, body):
    data = _load_projects()
    project = next((p for p in data.get("projects", []) if isinstance(p, dict) and p.get("id") == project_id), None)
    if not project:
        return {"error": "Project not found", "_status": 404}
    body = body or {}
    current = project.get("archiveMaintenance") if isinstance(project.get("archiveMaintenance"), dict) else {}
    enabled = bool(body.get("enabled")) if "enabled" in body else _archive_project_maintenance_enabled(project)
    schedule_mode = current.get("scheduleMode") or current.get("frequency") or ARCHIVE_DEFAULT_SCHEDULE_MODE
    if "scheduleMode" in body or "frequency" in body:
        requested = _archive_normalize_schedule_mode(body.get("scheduleMode", body.get("frequency")))
        if requested not in ARCHIVE_SCHEDULE_MODES:
            return {"error": "Unsupported archive maintenance schedule mode", "_status": 400}
        schedule_mode = requested
    custom_hours = current.get("customIntervalHours")
    if "customIntervalHours" in body:
        try:
            custom_hours = max(1, int(body.get("customIntervalHours") or 0))
        except Exception:
            return {"error": "customIntervalHours must be a positive integer", "_status": 400}
    project["archiveMaintenanceEnabled"] = enabled
    project["archiveMaintenance"] = {
        **current,
        "enabled": enabled,
        "scheduleMode": schedule_mode,
        "frequency": schedule_mode,
        "customIntervalHours": custom_hours,
        "updatedAt": _proj_now(),
        "updatedBy": str((body or {}).get("by") or "user"),
    }
    project["updatedAt"] = _proj_now()
    _save_projects(data)
    record = _archive_room_derive_project(project)
    schedule = _archive_schedule_state(record)
    if schedule_mode != ARCHIVE_SCHEDULE_CUSTOM:
        schedule.pop("customIntervalHours", None)
    elif custom_hours:
        schedule["customIntervalHours"] = custom_hours
    record["archiveMaintenanceSchedule"] = schedule
    _archive_room_save_project_record(project_id, record)
    return {"ok": True, "project": project, "archive": record, "maintenance": _archive_project_maintenance_meta(project, record)}


def _handle_archive_daily_inspection(body=None):
    return _archive_run_inspection("daily_inspection", force=bool((body or {}).get("force")))


def _handle_archive_mark_important_message(body):
    project_id = str((body or {}).get("projectId") or "").strip()
    text = str((body or {}).get("text") or (body or {}).get("message") or "").strip()
    message_id = str((body or {}).get("messageId") or uuid.uuid4()).strip()
    if not project_id:
        return {"error": "projectId is required", "_status": 400}
    if not text:
        return {"error": "text is required", "_status": 400}
    source = _archive_source_ref("chat", message_id, title="Important message", conversationId=(body or {}).get("conversationId"))
    result = _archive_maintenance_trigger(
        project_id,
        "important_message",
        source=source,
        title="Important message",
        summary=text,
        value_level="normal",
        reason="User marked this message as important.",
        impact=str((body or {}).get("impact") or "context"),
    )
    return result


def _archive_trigger_task_completed(project_id, task):
    if not project_id or not isinstance(task, dict):
        return None
    return _archive_maintenance_trigger(
        project_id,
        "task_completed",
        source=_archive_source_ref("task", task.get("id"), title=task.get("title", ""), taskId=task.get("id")),
        title=f"Task completed: {task.get('title', '')}",
        summary=f"Task completed: {task.get('title', '')}",
        value_level="high",
        impact="task",
    )


def _archive_trigger_task_blocker(project_id, task):
    if not project_id or not isinstance(task, dict):
        return None
    reason = task.get("blockedReason") or task.get("lastError") or ""
    if not reason and str(task.get("executionState") or "").lower() != "blocked":
        return None
    return _archive_maintenance_trigger(
        project_id,
        "blocker",
        source=_archive_source_ref("task", task.get("id"), title=task.get("title", ""), taskId=task.get("id")),
        title=f"Task blocker: {task.get('title', '')}",
        summary=reason or "Task is blocked.",
        value_level="high",
        impact="risk",
    )


def _archive_trigger_meeting_conclusion(meeting):
    if not isinstance(meeting, dict):
        return None
    project_id = str(meeting.get("projectId") or "").strip()
    if not project_id:
        return None
    result = meeting.get("result") if isinstance(meeting.get("result"), dict) else {}
    summary = result.get("summary") or result.get("decision") or meeting.get("topic") or "Meeting completed."
    return _archive_maintenance_trigger(
        project_id,
        "meeting_conclusion",
        source=_archive_source_ref("meeting", meeting.get("id"), title=meeting.get("topic", ""), meetingId=meeting.get("id")),
        title=f"Meeting conclusion: {meeting.get('topic', '')}",
        summary=summary,
        value_level="high",
        reason="Meeting completed with a project-linked conclusion.",
        impact="state",
    )


def _archive_room_project_file(project_id):
    safe = _safe_agent_workspace_key(project_id or "project")
    return os.path.join(ARCHIVE_ROOM_PROJECTS_DIR, f"{safe}.json")


def _archive_room_load_project_record(project_id):
    path = _archive_room_project_file(project_id)
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        return {}


def _archive_room_save_project_record(project_id, record):
    os.makedirs(ARCHIVE_ROOM_PROJECTS_DIR, exist_ok=True)
    path = _archive_room_project_file(project_id)
    tmp = path + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(record, f, ensure_ascii=False, indent=2)
        f.write("\n")
    os.replace(tmp, path)
    try:
        os.chmod(path, 0o666)
    except OSError:
        pass


def _archive_entry(entry_id, title, text, confidence=ARCHIVE_INFERENCE, source=None, stale=False):
    authority = _archive_authority_for_confidence(confidence)
    return {
        "id": entry_id,
        "title": title,
        "text": text or "",
        "confidence": confidence,
        "authority": authority,
        "status": authority,
        "stale": bool(stale),
        "sources": [source] if source else [],
    }


def _archive_authority_for_confidence(confidence):
    if confidence == ARCHIVE_CONFIRMED:
        return ARCHIVE_AUTH_SOURCE
    if confidence == ARCHIVE_PENDING:
        return ARCHIVE_AUTH_PENDING_HUMAN
    return ARCHIVE_AUTH_MANAGER


def _archive_normalize_authority(item, default=None):
    item = item if isinstance(item, dict) else {}
    status = str(item.get("status") or "").strip()
    authority = str(item.get("authority") or "").strip()
    confidence = item.get("confidence")
    if authority:
        return authority
    if status in {
        ARCHIVE_AUTH_SYSTEM,
        ARCHIVE_AUTH_SOURCE,
        ARCHIVE_AUTH_MANAGER,
        ARCHIVE_AUTH_HUMAN,
        ARCHIVE_AUTH_PENDING_HUMAN,
        ARCHIVE_AUTH_DEFERRED,
        ARCHIVE_AUTH_REJECTED,
    }:
        return status
    if status == "pending":
        return ARCHIVE_AUTH_PENDING_HUMAN
    if status == "deferred":
        return ARCHIVE_AUTH_DEFERRED
    if status == "rejected":
        return ARCHIVE_AUTH_REJECTED
    if confidence == ARCHIVE_CONFIRMED:
        return default or ARCHIVE_AUTH_SOURCE
    if confidence == ARCHIVE_PENDING:
        return ARCHIVE_AUTH_PENDING_HUMAN
    return default or ARCHIVE_AUTH_MANAGER


def _archive_apply_authority(item, authority=None, actor=None):
    if not isinstance(item, dict):
        return item
    auth = authority or _archive_normalize_authority(item)
    item["authority"] = auth
    item["status"] = auth
    if auth == ARCHIVE_AUTH_HUMAN:
        item["confidence"] = ARCHIVE_CONFIRMED
    elif auth in {ARCHIVE_AUTH_SYSTEM, ARCHIVE_AUTH_SOURCE}:
        item["confidence"] = ARCHIVE_CONFIRMED
    elif auth == ARCHIVE_AUTH_PENDING_HUMAN:
        item["confidence"] = ARCHIVE_PENDING
    elif auth == ARCHIVE_AUTH_DEFERRED:
        item["confidence"] = ARCHIVE_PENDING
    elif auth == ARCHIVE_AUTH_REJECTED:
        item["confidence"] = ARCHIVE_PENDING
    else:
        item["confidence"] = item.get("confidence") or ARCHIVE_INFERENCE
    if actor and not item.get("confirmedBy"):
        item["confirmedBy"] = actor
    return item


def _archive_task_counts(project):
    tasks = project.get("tasks", []) or []
    total = len(tasks)
    done = sum(1 for t in tasks if _project_task_is_done(t))
    active_states = {"validating", "executing", "reviewing", "reworking", "running"}
    active_ai = sorted({
        str(t.get("executorAgentId") or t.get("assignee") or "").strip()
        for t in tasks
        if (t.get("executionState") in active_states) and (t.get("executorAgentId") or t.get("assignee"))
    })
    blockers = [
        t for t in tasks
        if t.get("blockedReason") or str(t.get("executionState") or "").lower() == "blocked" or t.get("lastError")
    ]
    pending = [
        t for t in tasks
        if t.get("requiresUserAcceptance") and t.get("completedAt") and not t.get("acceptedAt")
    ]
    return {
        "total": total,
        "done": done,
        "completionRate": round((done / total) * 100) if total else 0,
        "activeAi": [a for a in active_ai if a],
        "riskCount": len(blockers) + len(_project_cron_alerts(project, limit=1000)),
        "pendingConfirmationCount": len(pending),
    }


def _archive_display_value(value, missing="未记录"):
    text = str(value or "").strip()
    return text if text else missing


def _archive_project_brief(project, limit=36):
    title = _archive_display_value(project.get("title"), "项目")
    description = str(project.get("description") or "").strip()
    text = " ".join(description.split()) if description else f"{title} 的项目背景与目标概览"
    text = text.strip(" \t\r\n#*-·。；;，,")
    if len(text) > limit:
        text = text[:limit].rstrip(" \t\r\n#*-·。；;，,") + "..."
    return text or f"{title} 的项目背景与目标概览"


def _archive_tasks(project):
    tasks = project.get("tasks") if isinstance(project.get("tasks"), list) else []
    return [t for t in tasks if isinstance(t, dict)]


def _archive_task_is_done(task):
    return bool(task.get("completedAt")) or str(task.get("status") or "").lower() in {"done", "completed"}


def _archive_task_is_current(task):
    state = str(task.get("executionState") or task.get("status") or "").lower()
    if state in {"executing", "running", "validating", "reviewing", "reworking", "blocked", "todo", "in_progress"}:
        return True
    return not _archive_task_is_done(task)


def _archive_current_task(project):
    for task in _archive_tasks(project):
        if _archive_task_is_current(task):
            return task
    tasks = _archive_tasks(project)
    return tasks[-1] if tasks else None


def _archive_entry_kind(entry):
    kind = str((entry or {}).get("kind") or "").strip()
    if kind:
        return kind
    title = str((entry or {}).get("title") or "").lower()
    if "risk" in title or "blocker" in title:
        return "risk"
    if "decision" in title:
        return "decision"
    if "rule" in title:
        return "rule"
    return "summary"


def _archive_source_types(entries, artifacts=None, pending=None):
    types = set()
    for entry in entries or []:
        for source in entry.get("sources") or []:
            if isinstance(source, dict) and (source.get("type") or source.get("sourceType")):
                types.add(str(source.get("type") or source.get("sourceType")))
    for artifact in artifacts or []:
        for source in artifact.get("sources") or []:
            if isinstance(source, dict) and (source.get("sourceType") or source.get("type")):
                types.add(str(source.get("sourceType") or source.get("type")))
    for item in pending or []:
        for source in item.get("sources") or []:
            if isinstance(source, dict) and (source.get("type") or source.get("sourceType")):
                types.add(str(source.get("type") or source.get("sourceType")))
    return sorted(types)


def _archive_content_presence(project, entries, artifacts, pending):
    tasks = _archive_tasks(project)
    kinds = {_archive_entry_kind(entry) for entry in entries or []}
    meeting_sources = any(
        any(isinstance(s, dict) and s.get("type") == "meeting" for s in entry.get("sources") or [])
        for entry in entries or []
    )
    important_messages = "important_message" in kinds or any(
        any(isinstance(s, dict) and s.get("type") == "chat" for s in entry.get("sources") or [])
        for entry in entries or []
    )
    items = [
        ("basic_info", "基础信息", bool(project.get("title") or project.get("description") or project.get("status")), "项目名称、描述、状态和进度"),
        ("tasks", "任务", bool(tasks), f"{len(tasks)} 个任务"),
        ("artifacts", "产物", bool(artifacts), f"{len(artifacts or [])} 个产物"),
        ("decisions", "决策", bool({"decision", "meeting_conclusion"} & kinds), "关键决策和会议结论"),
        ("risks", "风险", bool({"risk", "blocker", "conflict_reminder"} & kinds), "风险、阻塞和冲突"),
        ("meetings", "会议", meeting_sources or "meeting_conclusion" in kinds, "项目相关会议结论"),
        ("important_messages", "重要消息", important_messages, "被标记或识别的重要上下文"),
        ("pending_confirmations", "待确认", bool(pending), f"{len(pending or [])} 个待确认项"),
    ]
    return [
        {"key": key, "label": label, "present": present, "summary": summary if present else "暂无记录"}
        for key, label, present, summary in items
    ]


def _archive_usage_map(project, counts, artifact_count, pending_count):
    return [
        {"key": "human_review", "label": "人类验收", "available": True, "summary": "查看项目状态、产物和维护记录。"},
        {"key": "handoff", "label": "交接", "available": True, "summary": "用基础信息、上下文目录和入场包快速交接。"},
        {"key": "ai_onboarding", "label": "AI 入场", "available": True, "summary": "为新 AI 提供项目目标、状态、规则、风险和来源。"},
        {"key": "task_context", "label": "任务上下文", "available": counts.get("total", 0) > 0, "summary": "围绕当前任务加载相关决策、风险和产物。"},
        {"key": "risk_governance", "label": "风险治理", "available": counts.get("riskCount", 0) > 0 or pending_count > 0, "summary": "追踪风险、冲突、缺失和待确认内容。"},
        {"key": "artifact_browsing", "label": "产物浏览", "available": artifact_count > 0, "summary": "按来源或路径查看项目产物。"},
    ]


def _archive_archive_introduction(project, counts, entries, artifacts, pending):
    title = _archive_display_value(project.get("title"), "未命名项目")
    artifact_count = len(artifacts or [])
    pending_count = len(pending or [])
    present = [item["label"] for item in _archive_content_presence(project, entries, artifacts, pending) if item["present"]]
    missing = [item["label"] for item in _archive_content_presence(project, entries, artifacts, pending) if not item["present"]]
    return {
        "title": f"{title} 的项目档案",
        "brief": _archive_project_brief(project),
        "purpose": "这个档案用于沉淀项目长期上下文，帮助人类验收、追踪和交接，也帮助新加入的 AI 快速获得项目背景。",
        "currentlyContains": present,
        "missingOrSparse": missing,
        "futureContent": ["关键决策", "风险/阻塞", "会议结论", "重要消息", "任务结果", "产物来源", "待确认项"],
        "humanUse": "人类可以用它理解项目状态、检查产物、查看维护记录和识别待补充信息。",
        "aiUse": "AI 可以用它获取项目入场包、任务上下文、来源引用和风险提醒，而不需要读取全部原始历史。",
        "readiness": {
            "label": "可用" if (counts.get("total", 0) or artifact_count or entries) else "待补充",
            "summary": f"{counts.get('done', 0)} / {counts.get('total', 0)} 个任务完成，{artifact_count} 个产物，{pending_count} 个待确认项。",
        },
    }


def _archive_project_basic_info(project, counts, artifact_count, pending_count, source_types):
    maintenance = _archive_project_maintenance_meta(project)
    participants = sorted(set([a for a in counts.get("activeAi", []) if a]))
    return {
        "name": _archive_display_value(project.get("title"), "未命名项目"),
        "description": _archive_display_value(project.get("description")),
        "status": _archive_display_value(project.get("status"), "active"),
        "taskProgress": f"{counts.get('done', 0)} / {counts.get('total', 0)}",
        "completionRate": counts.get("completionRate", 0),
        "updatedAt": project.get("updatedAt") or project.get("createdAt") or "",
        "maintenanceEnabled": maintenance.get("enabled"),
        "maintenanceLabel": "长期维护已开启" if maintenance.get("enabled") else "长期维护已关闭",
        "activeAi": participants,
        "participantsLabel": "、".join(participants) if participants else "暂无活跃 AI",
        "artifactCount": artifact_count,
        "pendingConfirmationCount": pending_count,
        "sourceTypes": source_types,
        "sourceTypesLabel": "、".join(source_types) if source_types else "暂无来源记录",
    }


def _archive_entry_brief(entry):
    authority = _archive_normalize_authority(entry)
    return {
        "id": entry.get("id") or "",
        "title": entry.get("title") or entry.get("id") or "未命名条目",
        "summary": entry.get("text") or "",
        "kind": _archive_entry_kind(entry),
        "confidence": entry.get("confidence") or ARCHIVE_INFERENCE,
        "authority": authority,
        "status": entry.get("status") or authority,
        "sources": entry.get("sources") or [],
    }


def _archive_task_brief(task):
    return {
        "id": task.get("id") or "",
        "title": task.get("title") or "未命名任务",
        "summary": task.get("description") or task.get("blockedReason") or task.get("lastError") or "",
        "status": task.get("executionState") or task.get("status") or ("done" if _archive_task_is_done(task) else "todo"),
        "priority": task.get("priority") or "",
        "assignee": task.get("executorAgentId") or task.get("assignee") or "",
    }


def _archive_artifact_brief(artifact):
    sources = artifact.get("sources") or []
    first_source = sources[0] if sources and isinstance(sources[0], dict) else {}
    source_label = first_source.get("taskTitle") or first_source.get("agentId") or first_source.get("sourceType") or ""
    return {
        "path": artifact.get("path") or "",
        "title": artifact.get("name") or artifact.get("path") or "未命名产物",
        "summary": source_label or artifact.get("path") or "",
        "kind": artifact.get("kind") or artifact.get("extension") or "file",
        "sources": sources[:3],
    }


def _archive_index_highlights(project, entries, artifacts, pending):
    entries = entries or []
    artifacts = artifacts or []
    pending = pending or []
    current_task = _archive_current_task(project)
    decisions = [e for e in entries if _archive_entry_kind(e) in {"decision", "meeting_conclusion", "rule"}]
    risks = [e for e in entries if _archive_entry_kind(e) in {"risk", "blocker", "conflict_reminder"}]
    important = [e for e in entries if _archive_entry_kind(e) in {"important_message", "meeting_conclusion"}]
    pending_items = [p for p in pending if isinstance(p, dict)]
    attention = []
    if pending_items:
        attention.append({"level": "pending", "label": "待确认", "text": f"{len(pending_items)} 个待确认项需要人工判断。"})
    if risks:
        attention.append({"level": "risk", "label": "风险", "text": f"{len(risks)} 条风险/冲突记录会影响后续执行。"})
    if artifacts:
        source_count = len({
            src.get("taskId") or src.get("agentId") or src.get("sourceType") or ""
            for artifact in artifacts
            for src in (artifact.get("sources") or [])
            if isinstance(src, dict)
        })
        attention.append({"level": "artifact", "label": "产物", "text": f"{len(artifacts)} 个产物" + (f"，来自 {source_count} 个来源。" if source_count else "。")})
    if current_task:
        attention.append({"level": "task", "label": "当前任务", "text": current_task.get("title") or "未命名任务"})
    sections = [
        {"key": "current_task", "label": "当前任务", "emptyText": "暂无明确当前任务", "items": [_archive_task_brief(current_task)] if current_task else []},
        {"key": "decisions", "label": "关键决策", "emptyText": "暂无关键决策", "items": [_archive_entry_brief(e) for e in decisions[:3]]},
        {"key": "risks", "label": "风险/冲突", "emptyText": "暂无风险或冲突记录", "items": [_archive_entry_brief(e) for e in risks[:3]]},
        {
            "key": "pending",
            "label": "待确认",
            "emptyText": "暂无待确认项",
            "items": [
                {
                    "id": item.get("id") or "",
                    "title": item.get("title") or "待确认项",
                    "summary": item.get("text") or "",
                    "kind": "pending",
                    "confidence": item.get("confidence") or ARCHIVE_PENDING,
                    "sources": item.get("sources") or [],
                }
                for item in pending_items[:3]
            ],
        },
        {"key": "artifacts", "label": "关键产物", "emptyText": "暂无关联产物", "items": [_archive_artifact_brief(a) for a in artifacts[:4]]},
        {"key": "important", "label": "重要消息/会议", "emptyText": "暂无重要消息或会议结论", "items": [_archive_entry_brief(e) for e in important[:3]]},
    ]
    return {
        "attention": attention[:4],
        "sections": sections,
        "footer": "这些索引由项目任务、产物、档案条目和待确认项实时派生；完整内容仍在下方上下文目录和产物浏览中查看。",
    }


def _archive_relevant_entries(entries, limit=8):
    priority = {
        ARCHIVE_CONFIRMED: 0,
        ARCHIVE_PENDING: 1,
        ARCHIVE_INFERENCE: 2,
    }
    items = list(entries or [])
    items.sort(key=lambda e: (priority.get(e.get("confidence"), 3), 1 if e.get("stale") else 0, e.get("updatedAt") or ""), reverse=False)
    return items[:limit]


def _archive_context_item(entry):
    authority = _archive_normalize_authority(entry)
    return {
        "id": entry.get("id"),
        "kind": _archive_entry_kind(entry),
        "title": entry.get("title") or entry.get("id") or "",
        "text": entry.get("text") or "",
        "confidence": entry.get("confidence") or ARCHIVE_INFERENCE,
        "authority": authority,
        "status": entry.get("status") or authority,
        "trustLevel": _archive_context_trust_level(authority),
        "stale": bool(entry.get("stale")),
        "staleReason": entry.get("staleReason") or "",
        "replacedBy": entry.get("replacedBy") or entry.get("supersededBy") or "",
        "replaces": entry.get("replaces") or "",
        "sourceComparison": entry.get("sourceComparison") or {},
        "pending": authority in {ARCHIVE_AUTH_PENDING_HUMAN, ARCHIVE_AUTH_DEFERRED} or entry.get("confidence") == ARCHIVE_PENDING or bool(entry.get("pendingConfirmationId")),
        "sources": entry.get("sources") or [],
    }


def _archive_context_trust_level(authority):
    if authority == ARCHIVE_AUTH_HUMAN:
        return "highest"
    if authority in {ARCHIVE_AUTH_SYSTEM, ARCHIVE_AUTH_SOURCE}:
        return "objective"
    if authority == ARCHIVE_AUTH_MANAGER:
        return "source_backed"
    if authority in {ARCHIVE_AUTH_PENDING_HUMAN, ARCHIVE_AUTH_DEFERRED}:
        return "unconfirmed"
    if authority == ARCHIVE_AUTH_REJECTED:
        return "rejected"
    return "inference"


def _archive_project_characteristics(project, entries, artifacts):
    description = str(project.get("description") or "").strip()
    background = description or f"项目名称：{project.get('title') or '未命名项目'}。业务背景未记录。"
    decisions = [e for e in entries or [] if _archive_entry_kind(e) in {"decision", "meeting_conclusion", "rule"}]
    risks = [e for e in entries or [] if _archive_entry_kind(e) in {"risk", "blocker", "conflict_reminder"}]
    artifact_names = [a.get("name") or a.get("path") for a in (artifacts or [])[:5]]
    return {
        "businessBackground": background,
        "goals": [description] if description else [],
        "confirmedRules": [e.get("text", "") for e in decisions if _archive_normalize_authority(e) == ARCHIVE_AUTH_HUMAN][:5],
        "decisionStyle": "优先依据已确认来源和项目档案；缺失或冲突内容进入待确认。",
        "userPreferences": [],
        "importantHistory": [e.get("text", "") for e in decisions[:5]],
        "risks": [e.get("text", "") for e in risks[:5]],
        "artifacts": [name for name in artifact_names if name],
        "boundary": "以下内容只是项目/任务补充上下文，不改写 AI 的全局身份、安全边界或通用工具规则。",
    }


def _archive_missing_context_reminders(project, entries):
    reminders = []
    if not str(project.get("description") or "").strip():
        reminders.append({"severity": "missing", "message": "项目描述未记录，AI 需要谨慎推断业务目标。", "proactive": False})
    if not any(_archive_entry_kind(e) == "rule" for e in entries or []):
        reminders.append({"severity": "missing", "message": "暂无已确认长期规则，执行时不要把推断当作规则。", "proactive": False})
    if any(e.get("stale") for e in entries or []):
        reminders.append({"severity": "stale", "message": "档案中存在 stale 条目，使用前需要确认是否仍有效。", "proactive": False})
    return reminders


def _archive_severe_conflict_reminders(entries, pending):
    reminders = []
    for item in pending or []:
        impact = str(item.get("impact") or "").lower()
        if impact in {"risk", "state", "project_status", "task", "task_conclusion", "risk_judgment"}:
            reminders.append({
                "severity": "severe_conflict",
                "message": item.get("text") or item.get("title") or "存在高影响待确认内容。",
                "proactive": True,
                "sources": item.get("sources") or [],
            })
    for entry in entries or []:
        if _archive_entry_kind(entry) == "conflict_reminder":
            reminders.append({
                "severity": "severe_conflict",
                "message": entry.get("text") or "存在冲突提醒。",
                "proactive": True,
                "sources": entry.get("sources") or [],
            })
    return reminders[:8]


def _archive_build_context_package(project, record=None, task=None, artifacts=None):
    record = record or _archive_room_derive_project(project)
    entries = record.get("entries") if isinstance(record.get("entries"), list) else []
    artifacts = artifacts if isinstance(artifacts, list) else []
    pending = record.get("pendingConfirmations") if isinstance(record.get("pendingConfirmations"), list) else []
    active_entries = [e for e in entries if _archive_normalize_authority(e) != ARCHIVE_AUTH_REJECTED and not e.get("stale")]
    relevant = [_archive_context_item(e) for e in _archive_relevant_entries(active_entries)]
    task_info = {}
    if isinstance(task, dict):
        task_info = {
            "id": task.get("id"),
            "title": task.get("title") or "",
            "description": task.get("description") or "",
            "status": task.get("status") or task.get("executionState") or "",
            "sources": [{"type": "task", "id": task.get("id"), "title": task.get("title", "")}],
        }
    characteristics = _archive_project_characteristics(project, entries, artifacts)
    reminders = _archive_missing_context_reminders(project, entries) + _archive_severe_conflict_reminders(entries, pending)
    conclusions = []
    if task_info:
        conclusions.append(f"当前任务：{task_info.get('title') or '未命名任务'}。")
    conclusions.extend([
        f"项目：{record.get('title') or project.get('title') or '未命名项目'}。",
        f"状态：{record.get('status') or project.get('status') or 'active'}；进度：{(record.get('metrics') or {}).get('taskDone', 0)} / {(record.get('metrics') or {}).get('taskCount', 0)} 个任务完成。",
    ])
    if project.get("description"):
        conclusions.append(f"业务背景：{project.get('description')}")
    if reminders:
        conclusions.append(f"上下文提醒：{reminders[0].get('message')}")
    return {
        "projectId": project.get("id"),
        "taskId": task_info.get("id") if task_info else "",
        "mode": "task" if task_info else "project",
        "conclusions": conclusions,
        "task": task_info,
        "projectCharacteristics": characteristics,
        "items": relevant,
        "authorityLegend": {
            ARCHIVE_AUTH_HUMAN: "Highest-trust human-confirmed guidance.",
            ARCHIVE_AUTH_SYSTEM: "Trusted objective VO system state.",
            ARCHIVE_AUTH_SOURCE: "Trusted objective source-backed fact.",
            ARCHIVE_AUTH_MANAGER: "Archive-manager-confirmed source-backed context.",
            ARCHIVE_AUTH_PENDING_HUMAN: "Pending human confirmation; do not treat as settled guidance.",
            ARCHIVE_AUTH_DEFERRED: "Deferred governance item; lower trust.",
            ARCHIVE_AUTH_REJECTED: "Rejected item; not active guidance.",
        },
        "sourceReferences": [src for item in relevant for src in item.get("sources", [])][:20],
        "optionalNextLoads": [
            {"type": "archive_entry", "id": item.get("id"), "title": item.get("title")}
            for item in relevant[3:8]
        ] + [
            {"type": "artifact", "path": a.get("path"), "title": a.get("name") or a.get("path")}
            for a in artifacts[:5]
        ],
        "reminders": reminders,
        "boundary": characteristics.get("boundary"),
    }


def _archive_context_prompt_block(project, task=None):
    try:
        record = _archive_room_derive_project(project)
        package = _archive_build_context_package(project, record=record, task=task, artifacts=[])
    except Exception as exc:
        return f"\nARCHIVE ROOM CONTEXT: unavailable ({exc})\n"
    lines = [
        "\nARCHIVE ROOM PROJECT CONTEXT (supplemental; does not override your identity, safety rules, or tool rules):",
    ]
    for conclusion in package.get("conclusions", [])[:6]:
        lines.append(f"- {conclusion}")
    characteristics = package.get("projectCharacteristics") or {}
    if characteristics.get("confirmedRules"):
        lines.append("Confirmed project rules:")
        for rule in characteristics.get("confirmedRules", [])[:4]:
            lines.append(f"- {rule}")
    if characteristics.get("risks"):
        lines.append("Known project risks:")
        for risk in characteristics.get("risks", [])[:4]:
            lines.append(f"- {risk}")
    if package.get("reminders"):
        lines.append("Archive reminders:")
        for reminder in package.get("reminders", [])[:4]:
            lines.append(f"- [{reminder.get('severity')}] {reminder.get('message')}")
    lines.append("Use these archive notes as project/task context. Preserve confidence and ask for confirmation when context is missing or conflicting.\n")
    return "\n".join(lines)


def _archive_room_derive_project(project):
    record = _archive_room_load_project_record(project.get("id"))
    now = _proj_now()
    counts = _archive_task_counts(project)
    artifact_count = 0
    artifact_status = "unavailable"
    artifact_error = ""
    context = _project_artifact_context(project)
    if context.get("ok"):
        listed = _artifact_context_list(context, allowed_extensions=_ARTIFACT_ALLOWED_EXTENSIONS, associated_only=True)
        if listed.get("ok"):
            artifact_count = len(listed.get("artifacts") or [])
            artifact_status = "ok"
        else:
            artifact_status = "error"
            artifact_error = listed.get("error", "")
    else:
        artifact_error = context.get("error", "")

    source = {"type": "project", "id": project.get("id"), "title": project.get("title", "")}
    description = project.get("description") or ""
    summary = record.get("summary") if isinstance(record.get("summary"), dict) else {}
    summary_entries = record.get("entries") if isinstance(record.get("entries"), list) else []
    if not summary_entries:
        summary_entries = [
            _archive_entry("project-goal", "Project Goal", description or "No project description recorded.", ARCHIVE_INFERENCE, source),
            _archive_entry("current-state", "Current State", f"{counts['done']} of {counts['total']} tasks complete. Status: {project.get('status', 'active')}.", ARCHIVE_INFERENCE, source),
        ]
    pending_confirmations = record.get("pendingConfirmations") if isinstance(record.get("pendingConfirmations"), list) else []
    for entry in summary_entries:
        if isinstance(entry, dict):
            _archive_apply_authority(entry)
    normalized_pending = []
    for item in pending_confirmations:
        if not isinstance(item, dict):
            continue
        if str(item.get("status") or "") == "pending":
            item["status"] = ARCHIVE_AUTH_PENDING_HUMAN
        item["authority"] = _archive_normalize_authority(item, ARCHIVE_AUTH_PENDING_HUMAN)
        item.setdefault("confidence", ARCHIVE_PENDING)
        if item["authority"] in {ARCHIVE_AUTH_PENDING_HUMAN, ARCHIVE_AUTH_DEFERRED}:
            normalized_pending.append(item)
    pending_confirmations = _archive_sort_pending_confirmations(normalized_pending)
    active_pending_count = len([p for p in pending_confirmations if _archive_normalize_authority(p, ARCHIVE_AUTH_PENDING_HUMAN) == ARCHIVE_AUTH_PENDING_HUMAN])
    artifact_preview = []
    if context.get("ok"):
        listed_preview = _artifact_context_list(context, allowed_extensions=_ARTIFACT_ALLOWED_EXTENSIONS, associated_only=True)
        if listed_preview.get("ok"):
            artifact_preview = listed_preview.get("artifacts", [])
    source_types = _archive_source_types(summary_entries, artifact_preview, pending_confirmations)
    archive_introduction = _archive_archive_introduction(project, counts, summary_entries, artifact_preview, pending_confirmations)
    project_basic_info = _archive_project_basic_info(project, counts, artifact_count, active_pending_count, source_types)
    index_highlights = _archive_index_highlights(project, summary_entries, artifact_preview, pending_confirmations)
    content_map = _archive_content_presence(project, summary_entries, artifact_preview, pending_confirmations)
    usage_map = _archive_usage_map(project, counts, artifact_count, len(pending_confirmations))
    onboarding = record.get("onboardingPackage") if isinstance(record.get("onboardingPackage"), dict) else {}
    context_package = _archive_build_context_package(project, record={**record, "entries": summary_entries, "pendingConfirmations": pending_confirmations, "metrics": {
        "taskCount": counts["total"],
        "taskDone": counts["done"],
        "completionRate": counts["completionRate"],
        "riskCount": counts["riskCount"],
        "pendingConfirmationCount": active_pending_count,
        "activeAi": counts["activeAi"],
        "artifactCount": artifact_count,
    }, "title": project.get("title", ""), "status": project.get("status", "active")}, task=_archive_current_task(project), artifacts=artifact_preview)
    onboarding = {
        **onboarding,
        "title": f"AI 入场包：{project.get('title', 'project')}",
        "confidence": onboarding.get("confidence") or ARCHIVE_INFERENCE,
        "contextPackage": context_package,
        "copyText": "\n".join([
            f"项目：{project.get('title', '') or '未命名项目'}",
            f"状态：{project.get('status', 'active')}；进度：{counts['done']} / {counts['total']} 个任务完成",
            f"项目目标/背景：{description or '未记录，需要谨慎推断。'}",
            f"当前任务：{(_archive_current_task(project) or {}).get('title') or '暂无明确当前任务'}",
            f"风险/阻塞：{counts['riskCount']}",
            f"待确认：{active_pending_count}",
            f"产物：{artifact_count}",
            "项目特征：",
            f"- 决策风格：{context_package.get('projectCharacteristics', {}).get('decisionStyle', '')}",
            f"- 上下文边界：{context_package.get('boundary', '')}",
            "相关结论：",
            *[f"- {item}" for item in context_package.get("conclusions", [])[:6]],
            "可继续加载：",
            *[f"- {item.get('type')}: {item.get('title') or item.get('id') or item.get('path')}" for item in context_package.get("optionalNextLoads", [])[:8]],
        ]),
    }
    derived = {
        "projectId": project.get("id"),
        "title": project.get("title", ""),
        "description": description,
        "status": project.get("status", "active"),
        "updatedAt": project.get("updatedAt") or project.get("createdAt") or now,
        "archiveUpdatedAt": record.get("archiveUpdatedAt") or now,
        "metrics": {
            "taskCount": counts["total"],
            "taskDone": counts["done"],
            "completionRate": counts["completionRate"],
            "riskCount": counts["riskCount"],
            "pendingConfirmationCount": active_pending_count,
            "activeAi": counts["activeAi"],
            "artifactCount": artifact_count,
        },
        "artifactStatus": artifact_status,
        "artifactError": artifact_error,
        "archiveManager": _archive_manager_public_state(ensure=False),
        "archiveMaintenance": _archive_project_maintenance_meta(project, record),
        "inspections": record.get("inspections") if isinstance(record.get("inspections"), dict) else {},
        "pendingConfirmations": pending_confirmations,
        "processedGovernance": record.get("processedGovernance") if isinstance(record.get("processedGovernance"), list) else [],
        "automaticGovernanceNotices": (record.get("automaticGovernanceNotices") if isinstance(record.get("automaticGovernanceNotices"), list) else [])[-5:],
        "processedEventCount": len(record.get("processedEvents") or {}) if isinstance(record.get("processedEvents"), dict) else 0,
        "archiveIntroduction": archive_introduction,
        "projectBasicInfo": project_basic_info,
        "archiveIndexHighlights": index_highlights,
        "archiveContentMap": content_map,
        "archiveUsageMap": usage_map,
        "contextPackage": context_package,
        "summary": {
            "goal": summary.get("goal") or description,
            "currentState": summary.get("currentState") or f"{counts['done']} of {counts['total']} tasks complete.",
            "nextStep": summary.get("nextStep") or "",
        },
        "entries": summary_entries,
        "onboardingPackage": onboarding,
    }
    record.update(derived)
    _archive_room_save_project_record(project.get("id"), record)
    return record


def _archive_room_project_summary(record):
    metrics = record.get("metrics") or {}
    attention = int(metrics.get("riskCount") or 0) * 1000 + int(metrics.get("pendingConfirmationCount") or 0) * 100
    return {
        "id": record.get("projectId"),
        "title": record.get("title", ""),
        "description": record.get("description", ""),
        "status": record.get("status", "active"),
        "updatedAt": record.get("updatedAt", ""),
        "archiveUpdatedAt": record.get("archiveUpdatedAt", ""),
        "metrics": metrics,
        "artifactStatus": record.get("artifactStatus", "unavailable"),
        "artifactError": record.get("artifactError", ""),
        "archiveManager": record.get("archiveManager", {}),
        "archiveMaintenance": record.get("archiveMaintenance", {}),
        "inspections": record.get("inspections", {}),
        "automaticGovernanceNotices": (record.get("automaticGovernanceNotices") if isinstance(record.get("automaticGovernanceNotices"), list) else [])[-5:],
        "pendingConfirmationCount": len(record.get("pendingConfirmations") or []) if isinstance(record.get("pendingConfirmations"), list) else 0,
        "attentionScore": attention,
    }


def _handle_archive_room_overview():
    data = _load_projects()
    manager = _archive_manager_public_state(ensure=True)
    projects = []
    for project in data.get("projects", []) if isinstance(data, dict) else []:
        if not isinstance(project, dict) or project.get("template"):
            continue
        projects.append(_archive_room_project_summary(_archive_room_derive_project(project)))
    projects.sort(key=lambda p: (p.get("attentionScore") or 0, p.get("updatedAt") or ""), reverse=True)
    return {
        "ok": True,
        "archiveManager": manager,
        "projects": projects,
    }


def _handle_archive_room_audit_count():
    data = _load_projects()
    projects_data = [p for p in (data.get("projects", []) if isinstance(data, dict) else []) if isinstance(p, dict) and not p.get("template") and p.get("id")]
    try:
        state = _archive_manager_create_if_missing()
    except Exception as exc:
        state = _archive_manager_load_state()
        state["status"] = "error"
        state["label"] = "档案管理员不可用"
        state["lastError"] = str(exc)
        _archive_manager_append_activity(state, "audit_archive_count", "error", "档案数目检查失败", error=str(exc))
        try:
            _archive_manager_save_state(state)
        except Exception:
            pass
        return {"error": str(exc), "archiveManager": _archive_manager_public_state(ensure=False), "_status": 409}

    now = _proj_now()
    existing_ids = []
    missing_projects = []
    for project in projects_data:
        project_id = project.get("id")
        record_path = _archive_room_project_file(project_id)
        record = _archive_room_load_project_record(project_id)
        if os.path.exists(record_path) and record.get("projectId") == project_id:
            existing_ids.append(project_id)
        else:
            missing_projects.append(project)

    state["status"] = "working"
    state["label"] = "检查中"
    _archive_manager_append_activity(
        state,
        "audit_archive_count",
        "running",
        f"开始检查档案数目：项目 {len(projects_data)} 个，已有档案 {len(existing_ids)} 份",
    )
    _archive_manager_save_state(state)

    repaired = []
    for project in missing_projects:
        record = _archive_room_derive_project(project)
        record["archiveUpdatedAt"] = record.get("archiveUpdatedAt") or now
        record["managerMaintainedAt"] = now
        item = {
            "id": _proj_uuid(),
            "at": now,
            "managerAgentId": state.get("agentId") or ARCHIVE_MANAGER_AGENT_ID,
            "status": "ok",
            "eventType": "archive_count_repair",
            "triggerType": "audit_archive_count",
            "projectId": project.get("id"),
            "summary": "档案数目检查发现该项目缺少档案，已创建基础项目档案。",
            "output": {
                "status": "ok",
                "projectId": project.get("id"),
                "summary": "已创建基础项目档案。",
            },
        }
        _archive_append_project_maintenance(record, item)
        _archive_room_save_project_record(project.get("id"), record)
        repaired.append({"projectId": project.get("id"), "title": project.get("title", "")})

    status = "ok"
    message = f"档案数目检查完成：项目 {len(projects_data)} 个，已有档案 {len(existing_ids)} 份，补齐 {len(repaired)} 份。"
    state["status"] = "paused" if state.get("paused") else "idle"
    state["label"] = "已暂停" if state.get("paused") else "已接入"
    state["lastError"] = ""
    _archive_manager_append_activity(state, "audit_archive_count", status, message)
    _archive_manager_save_state(state)

    overview = _handle_archive_room_overview()
    return {
        "ok": True,
        "audit": {
            "projectCount": len(projects_data),
            "archiveCountBefore": len(existing_ids),
            "missingCount": len(missing_projects),
            "repairedCount": len(repaired),
            "repaired": repaired,
            "checkedAt": now,
            "message": message,
        },
        "archiveManager": _archive_manager_public_state(ensure=False),
        "projects": overview.get("projects", []),
    }


def _handle_archive_room_project(project_id):
    data = _load_projects()
    project = next((p for p in data.get("projects", []) if isinstance(p, dict) and p.get("id") == project_id), None)
    if not project:
        return {"error": "Project not found", "_status": 404}
    record = _archive_room_derive_project(project)
    artifacts = []
    context = _project_artifact_context(project)
    if context.get("ok"):
        listed = _artifact_context_list(context, allowed_extensions=_ARTIFACT_ALLOWED_EXTENSIONS, associated_only=True)
        if listed.get("ok"):
            artifacts = listed.get("artifacts", [])
    record["artifacts"] = artifacts
    return {"ok": True, "project": record}


def _handle_archive_room_context(project_id, query_string=""):
    data = _load_projects()
    project = next((p for p in data.get("projects", []) if isinstance(p, dict) and p.get("id") == project_id), None)
    if not project:
        return {"error": "Project not found", "_status": 404}
    params = urllib.parse.parse_qs(query_string or "")
    task_id = (params.get("taskId") or params.get("task") or [""])[0]
    task = None
    if task_id:
        task = next((t for t in _archive_tasks(project) if str(t.get("id") or "") == task_id), None)
        if not task:
            return {"error": "Task not found", "_status": 404}
    else:
        task = _archive_current_task(project)
    record = _archive_room_derive_project(project)
    artifacts = []
    context = _project_artifact_context(project)
    if context.get("ok"):
        listed = _artifact_context_list(context, allowed_extensions=_ARTIFACT_ALLOWED_EXTENSIONS, associated_only=True)
        if listed.get("ok"):
            artifacts = listed.get("artifacts", [])
    package = _archive_build_context_package(project, record=record, task=task, artifacts=artifacts)
    return {"ok": True, "projectId": project_id, "taskId": (task or {}).get("id") or "", "context": package}


def _handle_archive_governance_action(project_id, item_id, body):
    action = str((body or {}).get("action") or "").strip().lower()
    if action not in ARCHIVE_GOVERNANCE_ACTIONS:
        return {"error": "Unsupported governance action", "_status": 400}
    data = _load_projects()
    project = next((p for p in data.get("projects", []) if isinstance(p, dict) and p.get("id") == project_id), None)
    if not project:
        return {"error": "Project not found", "_status": 404}
    record = _archive_room_derive_project(project)
    pending = record.get("pendingConfirmations") if isinstance(record.get("pendingConfirmations"), list) else []
    idx = next((i for i, item in enumerate(pending) if isinstance(item, dict) and str(item.get("id") or "") == item_id), -1)
    if idx < 0:
        return {"error": "Pending confirmation not found", "_status": 404}
    item = pending[idx]
    now = _proj_now()
    actor = str((body or {}).get("actor") or "human").strip() or "human"
    reason = str((body or {}).get("reason") or "").strip()
    edited_text = str((body or {}).get("text") or (body or {}).get("editedText") or "").strip()
    original = json.loads(json.dumps(item, ensure_ascii=False))

    if action == "defer":
        item["status"] = ARCHIVE_AUTH_DEFERRED
        item["authority"] = ARCHIVE_AUTH_DEFERRED
        item["deferredAt"] = now
        item["deferredBy"] = actor
        if reason:
            item["deferReason"] = reason
        item["updatedAt"] = now
        pending[idx] = item
        record["pendingConfirmations"] = _archive_sort_pending_confirmations(pending)
        history_status = ARCHIVE_AUTH_DEFERRED
    else:
        pending.pop(idx)
        record["pendingConfirmations"] = _archive_sort_pending_confirmations(pending)
        history_status = ARCHIVE_AUTH_REJECTED if action == "reject" else ARCHIVE_AUTH_HUMAN

    confirmed_entry = None
    linked_entry_id = item.get("entryId") or ""
    if action in {"confirm", "edit_confirm"}:
        confirmed_text = edited_text if action == "edit_confirm" and edited_text else item.get("text", "")
        entry_id = f"human-confirmed-{item_id.replace('pending-', '')}"
        linked_entry_id = linked_entry_id or f"{item.get('kind') or 'event'}-{item_id.replace('pending-', '')}"
        source = (item.get("sources") or [None])[0]
        confirmed_entry = _archive_entry(entry_id, item.get("title") or "Human confirmed archive item", confirmed_text, ARCHIVE_CONFIRMED, source, stale=False)
        confirmed_entry.update({
            "kind": item.get("kind") or "human_confirmed",
            "authority": ARCHIVE_AUTH_HUMAN,
            "status": ARCHIVE_AUTH_HUMAN,
            "confirmedAt": now,
            "confirmedBy": actor,
            "confirmationReason": reason,
            "originalSuggestion": original,
            "updatedAt": now,
        })
        _archive_upsert_entry(record, confirmed_entry)
    elif action == "reject":
        linked_entry_id = linked_entry_id or f"{item.get('kind') or 'event'}-{item_id.replace('pending-', '')}"
        item["status"] = ARCHIVE_AUTH_REJECTED
        item["authority"] = ARCHIVE_AUTH_REJECTED
        item["rejectedAt"] = now
        item["rejectedBy"] = actor
        if reason:
            item["rejectReason"] = reason
    if action in {"confirm", "edit_confirm", "reject"} and linked_entry_id:
        for entry in record.get("entries") or []:
            if isinstance(entry, dict) and entry.get("id") == linked_entry_id:
                if action == "reject":
                    _archive_apply_authority(entry, ARCHIVE_AUTH_REJECTED)
                    entry["rejectedAt"] = now
                    entry["rejectedBy"] = actor
                    entry["rejectReason"] = reason
                else:
                    entry["supersededBy"] = (confirmed_entry or {}).get("id", "")
                    entry["status"] = "superseded_by_human_confirmed"
                entry["updatedAt"] = now
                break

    history_item = {
        "id": f"governance-{_proj_uuid()}",
        "pendingId": item_id,
        "action": action,
        "status": history_status,
        "actor": actor,
        "at": now,
        "reason": reason,
        "title": item.get("title") or "",
        "text": edited_text if action == "edit_confirm" and edited_text else item.get("text", ""),
        "originalSuggestion": original,
        "confirmedEntryId": (confirmed_entry or {}).get("id", ""),
        "sources": item.get("sources") or [],
    }
    _archive_add_governance_history(record, history_item)
    record["archiveUpdatedAt"] = now
    _archive_room_save_project_record(project_id, record)
    updated = _archive_room_derive_project(project)
    return {"ok": True, "action": action, "item": history_item, "project": updated}


def _project_execution_build_prompt(project, task, attempt, workspace):
    checklist = _project_execution_acceptance_checklist(task)
    checklist_text = "\n".join(f"- [{'x' if item.get('done') else ' '}] {item.get('text', '')}" for item in checklist) or "- No checklist supplied"
    rework_feedback = task.get("reworkFeedback") or attempt.get("reworkFeedback") or ""
    archive_context = _archive_context_prompt_block(project, task)
    meeting_action_block = ""
    if attempt.get("meetingActionPhase"):
        pending_actions = [
            a for a in (task.get("meetingActionItems") or [])
            if isinstance(a, dict) and a.get("requiredForResume") is True and a.get("status") == "pending"
        ]
        action_lines = []
        for item in pending_actions:
            detail = item.get("description") or ""
            owner = item.get("owner") or task.get("executorAgentId") or task.get("assignee") or ""
            action_lines.append(f"- {item.get('title', '')}" + (f" — {detail}" if detail else "") + (f" (owner: {owner})" if owner else ""))
        decision_lines = []
        for decision in (task.get("meetingDecisionHistory") or [])[-3:]:
            if isinstance(decision, dict) and decision.get("decision"):
                decision_lines.append(f"- {decision.get('decision')}")
        meeting_action_block = (
            "\nMEETING ACTION ITEM PHASE:\n"
            "Complete ONLY the meeting-created action items listed below. Do not continue the original task yet.\n"
            "After completing them, return a concise summary of what was done and any remaining risk.\n"
            "Pending meeting action items:\n"
            + ("\n".join(action_lines) if action_lines else "- No pending meeting action items")
            + "\nMeeting decision context:\n"
            + ("\n".join(decision_lines) if decision_lines else "- No meeting decision context")
            + "\n"
        )
    return (
        "You are the execution agent for a Virtual Office project task.\n"
        f"WORKSPACE: {workspace}\nWork only inside this workspace. Do not review or mark the task complete.\n"
        "EXPECTED WORKFLOW:\n"
        "1. First read the task and determine what content or deliverable must be produced. Write the task/deliverable acceptance criteria into the task checklist. The checklist is only for deliverable acceptance criteria, not a meeting action-item queue. If the task checklist is empty, include the created acceptance criteria in checklistUpdates and, when possible, persist them with PUT /api/projects/{projectId}/tasks/{taskId}.\n"
        "2. Execute the task. For any Virtual Office operation, first use the vo-operating-guidelines skill to detect the VO environment, choose the correct VO skill, and follow its boundaries. If you discover an issue that requires alignment, use vo-operating-guidelines to decide whether a formal AI meeting is appropriate; when it is, proactively request a meeting with POST /api/projects/{projectId}/tasks/{taskId}/meeting-requests. Do not confirm or reject meetings yourself. Add the corresponding action items and discussion points as meeting/task context. Do not put those meeting action items or risks into the checklist or comments.\n"
        "3. Before finishing, inspect whether every checklist item is complete. Mark completed checklist items done; if any item is unfinished, continue working until it is complete.\n"
        "FINAL RESPONSE FORMAT (strict):\n"
        "- First output a human-visible Markdown summary under 1200 characters. It may include short bullets for changed files, tests run, and remaining risks.\n"
        "- Then output exactly one fenced ```json block containing a single object with these optional fields: checklistUpdates, meetingDiscussionPoints, tests.\n"
        "- Do not print raw JSON outside the fenced json block. Do not put escaped JSON inside the Markdown summary.\n"
        "- tests must be an array of short strings only, each under 180 characters. Do not put full logs, full API responses, raw tool output, source material, or nested objects in tests.\n"
        "- checklistUpdates is an array of {id, text, done, evidence}; set done=true only for checklist items you actually verified as complete.\n"
        "- meetingDiscussionPoints is an array of {kind, title, text, meetingId, requestId} for meeting conclusions, risks, and discussion notes that belong in the task details.\n\n"
        f"PROJECT: {project.get('title', '')}\nPROJECT DESCRIPTION: {project.get('description', '')}\n"
        f"PROJECT_ID: {project.get('id', '')}\nTASK_ID: {task.get('id', '')}\nTASK: {task.get('title', '')}\nTASK DESCRIPTION: {task.get('description', '')}\nATTEMPT: {attempt.get('id')}\n"
        f"REWORK FEEDBACK: {rework_feedback}\nCHECKLIST:\n{checklist_text}\n"
        f"{meeting_action_block}"
        f"{archive_context}\n"
    )


def _project_execution_test_evidence(result):
    explicit = result.get("tests")
    if isinstance(explicit, list):
        evidence = []
        for item in explicit[:50]:
            if isinstance(item, dict):
                label = item.get("name") or item.get("title") or item.get("command") or item.get("text") or item.get("summary") or item.get("status")
                status = item.get("status") or item.get("result") or item.get("outcome")
                text = " · ".join(str(part).strip() for part in (label, status) if str(part or "").strip())
            else:
                text = str(item or "")
            compact = _project_execution_compact_evidence_line(text)
            if compact:
                evidence.append(compact)
        return evidence
    lines = []
    parsed = _project_execution_extract_json(result.get("reply") or "")
    if isinstance(parsed, dict):
        for key in ("tests", "testResults", "checks", "validation", "checkResults"):
            value = parsed.get(key)
            if not isinstance(value, list):
                continue
            for item in value[:50]:
                if isinstance(item, dict):
                    label = item.get("name") or item.get("title") or item.get("command") or item.get("text") or item.get("summary") or item.get("id")
                    status = item.get("status") or item.get("result") or item.get("outcome")
                    text = " · ".join(str(part).strip() for part in (label, status) if str(part or "").strip())
                else:
                    text = str(item or "")
                compact = _project_execution_compact_evidence_line(text)
                if compact:
                    lines.append(compact)
            if lines:
                return lines[:50]
    for line in str(result.get("reply") or "").splitlines():
        stripped = line.strip()
        if not stripped or (stripped.startswith("{") and stripped.endswith("}")) or (stripped.startswith("[") and stripped.endswith("]")):
            continue
        if re.search(r"(?i)\b(test|pytest|npm test|unittest|passed|failed)\b", line):
            compact = _project_execution_compact_evidence_line(stripped)
            if compact:
                lines.append(compact)
    return lines[:50]


def _project_execution_call_executor(executor, prompt, workspace, attempt_id, project_id=None, task_id=None, timeout=600):
    agent_id = executor.get("id")
    provider_kind = executor.get("providerKind")
    if provider_kind == "codex":
        return _handle_codex_chat({"agentId": agent_id, "message": prompt, "conversationId": attempt_id, "timeoutSec": timeout, "workspace": workspace, "fromType": "agent"})
    if provider_kind == "hermes":
        return _handle_hermes_chat({"agentId": agent_id, "message": prompt, "conversationId": attempt_id, "timeoutSec": timeout, "fromType": "agent"})
    if provider_kind == "claude-code":
        return _handle_claude_code_chat({"agentId": agent_id, "message": prompt, "conversationId": attempt_id, "timeoutSec": timeout, "workspace": workspace, "fromType": "agent"})
    reply = _wf_call_agent(agent_id, prompt, timeout=timeout, project_id=project_id, task_id=attempt_id or task_id)
    reply_text = str(reply or "")
    delivered_only = reply_text.startswith("[DELIVERED]")
    ok = bool(reply) and not reply_text.startswith("[ERROR]") and not delivered_only
    if delivered_only:
        return {
            "ok": False,
            "reply": reply_text,
            "error": "OpenClaw message was delivered but no final execution result was returned.",
            "status": "execution_pending_result",
        }
    return {"ok": ok, "reply": reply, "error": None if ok else reply, "status": "completed" if ok else "execution_failed"}


def _project_execution_latest_attempt(task):
    attempts = task.get("attempts") or []
    evidence_attempt = (task.get("evidence") or {}).get("attemptId")
    if evidence_attempt:
        found = _project_execution_attempt(task, evidence_attempt)
        if found:
            return found
    return attempts[-1] if attempts else None


def _project_execution_build_review_prompt(project, task, attempt):
    evidence = attempt.get("evidence") or task.get("evidence") or {}
    checklist = _project_execution_acceptance_checklist(task)
    checklist_text = "\n".join(f"- [{'x' if item.get('done') else ' '}] {item.get('text', '')}" for item in checklist) or "- No checklist supplied"
    changed = "\n".join(f"- {name}" for name in (evidence.get("changedFiles") or [])[:100]) or "- No changed files reported"
    tests = "\n".join(f"- {line}" for line in (evidence.get("testResults") or [])[:50]) or "- No test evidence reported"
    feedback = task.get("reworkFeedback") or ""
    return (
        "You are the independent read-only reviewer for a Virtual Office Project Execution task.\n"
        "Review only the evidence below. Do not modify files, run tools that write files, or mark the task done.\n"
        "The checklist contains deliverable acceptance criteria only; meeting action items and risks are context, not acceptance checklist items.\n"
        "Return one JSON object with fields: status, summary, rationale, items.\n"
        "status must be one of: pass, needs_more_work, blocked.\n\n"
        f"PROJECT: {project.get('title', '')}\nPROJECT DESCRIPTION: {project.get('description', '')}\n"
        f"TASK: {task.get('title', '')}\nTASK DESCRIPTION: {task.get('description', '')}\n"
        f"ATTEMPT: {attempt.get('id')}\nPRIOR USER FEEDBACK: {feedback}\nCHECKLIST:\n{checklist_text}\n\n"
        f"EXECUTOR SUMMARY:\n{_project_execution_redact(evidence.get('executorSummary') or '')}\n\n"
        f"CHANGED FILES:\n{changed}\n\nTEST EVIDENCE:\n{tests}\n\n"
        f"PROVIDER STATUS: {evidence.get('providerStatus') or ''}\nERROR: {_project_execution_redact(evidence.get('error') or '')}\n"
    )


def _project_execution_call_reviewer(reviewer, prompt, review_id, project_id=None, task_id=None, timeout=600):
    agent_id = reviewer.get("id")
    provider_kind = reviewer.get("providerKind")
    if provider_kind == "codex":
        return _handle_codex_chat({"agentId": agent_id, "message": prompt, "conversationId": review_id, "timeoutSec": timeout, "fromType": "agent"})
    if provider_kind == "hermes":
        return _handle_hermes_chat({"agentId": agent_id, "message": prompt, "conversationId": review_id, "timeoutSec": timeout, "fromType": "agent"})
    if provider_kind == "claude-code":
        return _handle_claude_code_chat({"agentId": agent_id, "message": prompt, "conversationId": review_id, "timeoutSec": timeout, "fromType": "agent"})
    reply = _wf_call_agent(agent_id, prompt, timeout=timeout, project_id=project_id, task_id=review_id or task_id)
    ok = not str(reply).startswith("[ERROR]")
    return {"ok": ok, "reply": reply, "error": None if ok else reply, "status": "completed" if ok else "review_failed"}


def _project_execution_review_feedback(review):
    parts = [review.get("summary") or "", review.get("rationale") or ""]
    for item in review.get("items") or []:
        if isinstance(item, str):
            parts.append(item)
        elif isinstance(item, dict):
            parts.append(item.get("text") or item.get("summary") or json.dumps(item, ensure_ascii=False))
    return _project_execution_redact("\n".join(part for part in parts if part).strip() or "Reviewer requested more work.")


def _project_execution_extract_json(text):
    raw = str(text or "").strip()
    if not raw:
        return None
    try:
        return json.loads(raw)
    except Exception:
        pass
    match = re.search(r"\{.*\}", raw, re.S)
    if match:
        try:
            return json.loads(match.group(0))
        except Exception:
            return None
    return None


def _project_execution_normalize_review(result, reviewer, attempt_id, review_id):
    explicit = result.get("review") if isinstance(result, dict) else None
    parsed = explicit if isinstance(explicit, dict) else _project_execution_extract_json(result.get("reply") if isinstance(result, dict) else "")
    if not isinstance(parsed, dict):
        parsed = {}
    status = str(parsed.get("status") or "").strip().lower()
    schema_ok = all(key in parsed for key in ("status", "summary", "rationale", "items")) and isinstance(parsed.get("items"), list)
    if status not in {"pass", "needs_more_work", "blocked"}:
        status = "blocked"
    if not schema_ok:
        status = "blocked"
    items = parsed.get("items") if isinstance(parsed.get("items"), list) else []
    return {
        "id": review_id,
        "attemptId": attempt_id,
        "status": status,
        "summary": _project_execution_redact(parsed.get("summary") or result.get("reply") or ""),
        "rationale": _project_execution_redact(parsed.get("rationale") or result.get("error") or ""),
        "items": items[:50],
        "reviewer": {"providerKind": reviewer.get("providerKind"), "agentId": reviewer.get("id")},
        "providerStatus": result.get("status") or ("completed" if result.get("ok") else "review_failed"),
        "raw": _project_execution_redact(result.get("reply") or ""),
        "reviewedAt": _proj_now(),
    }


def _project_execution_run_review(project_id, task_id, attempt_id, review_id):
    try:
        data, project, task = _project_execution_find(project_id, task_id)
        if not project or not task:
            return
        attempt = _project_execution_attempt(task, attempt_id)
        if not attempt or task.get("activeAttemptId") != review_id:
            return
        reviewer = attempt.get("reviewer") or {}
        result = _project_execution_call_reviewer(reviewer, _project_execution_build_review_prompt(project, task, attempt), review_id, project_id=project_id, task_id=task_id)
        data, project, task = _project_execution_find(project_id, task_id)
        if not project or not task:
            return
        attempt = _project_execution_attempt(task, attempt_id)
        if not attempt or task.get("activeAttemptId") != review_id:
            return
        review = _project_execution_normalize_review(result, reviewer, attempt_id, review_id)
        attempt["review"] = review
        attempt["reviewedAt"] = review["reviewedAt"]
        task.setdefault("reviewHistory", []).append(review)
        task["reviewHistory"] = task["reviewHistory"][-50:]
        task["reviewResult"] = review
        task["activeAttemptId"] = None
        project.update({"workflowActive": False, "activeTaskId": None, "activeAgent": None})
        if review["status"] == "pass":
            task.update({"blockedReason": None, "lastError": None})
            attempt["status"] = "review_passed"
            if _project_execution_attempt_requires_user_acceptance(task, attempt):
                project["projectExecutionFlowActive"] = False
                project["projectExecutionFlowStopReason"] = "awaiting_user_acceptance"
                _project_execution_transition(project, task, "awaiting_user_acceptance", reviewer.get("id") or "reviewer", "Reviewer passed; waiting for explicit user acceptance.", attempt_id)
                _send_project_execution_acceptance_notification(project, task, attempt_id, "Reviewer passed; waiting for explicit user acceptance.")
            else:
                done_result = _project_execution_mark_done(project, task, reviewer.get("id") or "reviewer", "Reviewer passed; task does not require user acceptance.", attempt_id)
                if not done_result.get("ok"):
                    continued = _project_execution_continue_for_incomplete_checklist(data, project_id, task_id, project, task, attempt_id, reviewer.get("id") or "reviewer", done_result)
                    if continued.get("continued"):
                        return
                    task["blockedReason"] = done_result.get("error")
                    _project_execution_transition(project, task, "blocked", "system", task["blockedReason"], attempt_id)
                    _send_project_execution_intervention_notification(project, task, task["blockedReason"], attempt_id, event="blocked", kind="warning")
                elif attempt.get("projectFlow") or project.get("projectExecutionFlowActive"):
                    project["projectExecutionFlowActive"] = True
                    project["projectExecutionFlowStopReason"] = None
                    _project_execution_schedule_continue(project_id, "review_passed")
        elif review["status"] == "needs_more_work":
            attempt["status"] = "review_needs_more_work"
            prior_reworks = int(task.get("reworkCount") or 0)
            feedback = _project_execution_review_feedback(review)
            if prior_reworks >= 3:
                task["blockedReason"] = "Reviewer still requested more work after three rework cycles."
                task["reworkFeedback"] = feedback
                _project_execution_transition(project, task, "blocked", reviewer.get("id") or "reviewer", task["blockedReason"], attempt_id)
                _send_project_execution_intervention_notification(project, task, task["blockedReason"], attempt_id, event="blocked", kind="warning")
            else:
                task["reworkCount"] = prior_reworks + 1
                task["blockedReason"] = None
                task["lastError"] = None
                task["reworkFeedback"] = feedback
                roles = _project_execution_resolve_roles(project, task)
                workspace = _project_execution_validate_workspace(project.get("workspacePath"))
                if not roles.get("ok") or not workspace.get("ok"):
                    task["blockedReason"] = roles.get("error") if not roles.get("ok") else workspace.get("error")
                    _project_execution_transition(project, task, "blocked", "system", task["blockedReason"], attempt_id)
                    _send_project_execution_intervention_notification(project, task, task["blockedReason"], attempt_id, event="blocked", kind="warning")
                else:
                    rework_attempt_id = str(uuid.uuid4())
                    rework_attempt = {
                        "id": rework_attempt_id,
                        "status": "reworking",
                        "startedAt": _proj_now(),
                        "workspacePath": workspace["path"],
                        "workspaceKind": workspace["kind"],
                        "dirtyConfirmed": False,
                        "dirtyFingerprint": "",
                        "executor": roles["executor"],
                        "reviewer": roles["reviewer"],
                        "baseline": _project_execution_git_snapshot(workspace["path"]),
                        "rework": True,
                        "reworkCycle": task["reworkCount"],
                        "reworkFromAttemptId": attempt_id,
                        "reworkFromReviewId": review_id,
                        "reworkFeedback": feedback,
                        "autoReviewAfterExecution": True,
                    }
                    task.setdefault("attempts", []).append(rework_attempt)
                    task["attempts"] = task["attempts"][-20:]
                    task.update({"activeAttemptId": rework_attempt_id, "executorAgentId": roles["executor"]["id"], "reviewerAgentId": roles["reviewer"]["id"]})
                    project.update({"workflowActive": True, "workflowPhase": "reworking", "activeTaskId": task_id, "activeAgent": roles["executor"]["id"]})
                    _project_execution_transition(project, task, "reworking", reviewer.get("id") or "reviewer", feedback, rework_attempt_id)
                    cancel_flag = threading.Event()
                    with _PROJECT_EXECUTION_LOCK:
                        _PROJECT_EXECUTION_CANCEL_FLAGS[rework_attempt_id] = cancel_flag
                    project["workflowPhase"] = task["executionState"]
                    _save_projects(data)
                    threading.Thread(target=_project_execution_run_attempt, args=(project_id, task_id, rework_attempt_id, cancel_flag), daemon=True).start()
                    return
        else:
            attempt["status"] = "review_blocked"
            task["blockedReason"] = review["summary"] or "Reviewer marked the task blocked."
            _project_execution_transition(project, task, "blocked", reviewer.get("id") or "reviewer", task["blockedReason"], attempt_id)
            _send_project_execution_intervention_notification(project, task, task["blockedReason"], attempt_id, event="blocked", kind="warning")
        project["workflowPhase"] = task["executionState"]
        _save_projects(data)
    finally:
        with _PROJECT_EXECUTION_LOCK:
            _PROJECT_EXECUTION_REVIEW_FLAGS.discard(review_id)


def _project_execution_run_attempt(project_id, task_id, attempt_id, cancel_flag):
    data, project, task = _project_execution_find(project_id, task_id)
    if not project or not task:
        return
    attempt = _project_execution_attempt(task, attempt_id)
    if not attempt:
        return
    workspace = attempt.get("workspacePath")
    executor = attempt.get("executor") or {}
    started = time.time()
    result = _project_execution_call_executor(executor, _project_execution_build_prompt(project, task, attempt, workspace), workspace, attempt_id, project_id=project_id, task_id=task_id)
    final_snapshot = _project_execution_git_snapshot(workspace)
    data, project, task = _project_execution_find(project_id, task_id)
    if not project or not task:
        return
    attempt = _project_execution_attempt(task, attempt_id)
    if not attempt or (task.get("activeAttemptId") != attempt_id and attempt.get("status") != "cancelling"):
        return
    checklist_changed = _project_execution_apply_checklist_updates(task, result)
    discussion_points_changed = _project_execution_apply_meeting_discussion_points(task, result)
    cancelled = cancel_flag.is_set() or result.get("status") == "cancelled"
    evidence = {
        "attemptId": attempt_id,
        "executorSummary": _project_execution_redact(result.get("reply") or ""),
        "changedFiles": sorted(set(final_snapshot.get("files", [])) | set(result.get("modifiedFiles") or []))[:200],
        "workspaceBefore": attempt.get("baseline", {}), "workspaceAfter": final_snapshot,
        "checklist": _project_execution_acceptance_checklist(task),
        "providerStatus": result.get("status") or ("completed" if result.get("ok") else "execution_failed"),
        "error": _project_execution_redact(result.get("error") or ""), "durationMs": int((time.time() - started) * 1000), "capturedAt": _proj_now(),
        "testResults": _project_execution_test_evidence(result),
        "checklistUpdated": checklist_changed,
        "meetingDiscussionUpdated": discussion_points_changed,
        "providerRef": {"providerKind": executor.get("providerKind"), "agentId": executor.get("id"), "attemptId": attempt_id},
    }
    attempt.update({"evidence": evidence, "finishedAt": _proj_now()})
    task.update({"evidence": evidence, "activeAttemptId": None})
    project.update({"workflowActive": False, "activeTaskId": None, "activeAgent": None})
    if cancelled:
        attempt["status"] = "cancelled"
        task["blockedReason"] = "Execution was cancelled. Existing workspace changes were not rolled back."
        _project_execution_transition(project, task, "blocked", "user", task["blockedReason"], attempt_id)
        _send_project_execution_intervention_notification(project, task, task["blockedReason"], attempt_id, event="blocked", kind="warning")
    elif result.get("ok"):
        attempt["status"] = "execution_complete"
        task.update({"blockedReason": None, "lastError": None})
        if attempt.get("meetingActionPhase"):
            _project_execution_mark_meeting_actions_completed(project, task, attempt_id, executor.get("id") or "executor")
            attempt["status"] = "meeting_action_items_completed"
            task["reviewResult"] = {}
            task["evidence"] = evidence
            _project_execution_transition(project, task, "backlog", executor.get("id") or "executor", "Meeting action items completed; original task can resume.", attempt_id)
            _project_execution_move_task_to_column(project, task, _wf_get_backlog_col(project))
            project.update({
                "workflowActive": False,
                "workflowPhase": "meeting_action_items_completed",
                "activeTaskId": None,
                "activeAgent": None,
                "projectExecutionFlowActive": project.get("projectExecutionStartMode") == "continuous",
                "projectExecutionFlowStopReason": None,
                "updatedAt": _proj_now(),
            })
            _save_projects(data)
            with _PROJECT_EXECUTION_LOCK:
                _PROJECT_EXECUTION_CANCEL_FLAGS.pop(attempt_id, None)
            if not _project_execution_has_pending_meeting_actions(task):
                threading.Thread(target=lambda: _handle_project_execution_start(project_id, task_id, {"projectStart": True, "mode": project.get("projectExecutionStartMode") or "continuous", "autoReviewAfterExecution": True, "by": "meeting-action-items"}), daemon=True).start()
            return
        if attempt.get("skipReview"):
            task["reviewResult"] = {
                "id": f"skipped-{attempt_id}",
                "attemptId": attempt_id,
                "status": "skipped",
                "summary": "Independent review skipped after user confirmation because no reviewer was configured.",
                "rationale": attempt.get("skipReviewReason") or "reviewer_missing",
                "items": [],
                "reviewedAt": _proj_now(),
            }
            task.setdefault("reviewHistory", []).append(task["reviewResult"])
            task["reviewHistory"] = task["reviewHistory"][-50:]
            if _project_execution_attempt_requires_user_acceptance(task, attempt):
                attempt["status"] = "review_skipped_waiting_acceptance"
                project["projectExecutionFlowActive"] = False
                project["projectExecutionFlowStopReason"] = "awaiting_user_acceptance"
                _project_execution_transition(project, task, "awaiting_user_acceptance", "system", "Review skipped by user confirmation; waiting for user acceptance.", attempt_id)
                _send_project_execution_acceptance_notification(project, task, attempt_id, "Review skipped by user confirmation; waiting for user acceptance.")
            else:
                done_result = _project_execution_mark_done(project, task, "system", "Review skipped by user confirmation; task does not require user acceptance.", attempt_id)
                if not done_result.get("ok"):
                    continued = _project_execution_continue_for_incomplete_checklist(data, project_id, task_id, project, task, attempt_id, "system", done_result)
                    if continued.get("continued"):
                        with _PROJECT_EXECUTION_LOCK:
                            _PROJECT_EXECUTION_CANCEL_FLAGS.pop(attempt_id, None)
                        return
                    task["blockedReason"] = done_result.get("error")
                    _project_execution_transition(project, task, "blocked", "system", task["blockedReason"], attempt_id)
                    _send_project_execution_intervention_notification(project, task, task["blockedReason"], attempt_id, event="blocked", kind="warning")
                elif attempt.get("projectFlow") or project.get("projectExecutionFlowActive"):
                    project["projectExecutionFlowActive"] = True
                    project["projectExecutionFlowStopReason"] = None
                    _project_execution_schedule_continue(project_id, "review_skipped")
        else:
            _project_execution_transition(project, task, "execution_complete", executor.get("id") or "executor", "Execution completed; Independent review has not started.", attempt_id)
    else:
        transient_reason = _project_execution_transient_failure_reason(result)
        if transient_reason and not cancelled and _project_execution_schedule_transient_retry(data, project_id, task_id, project, task, attempt, evidence, transient_reason):
            with _PROJECT_EXECUTION_LOCK:
                _PROJECT_EXECUTION_CANCEL_FLAGS.pop(attempt_id, None)
            return
        attempt["status"] = "blocked"
        task["lastError"] = evidence["error"] or "Executor failed"
        task["blockedReason"] = task["lastError"]
        _project_execution_transition(project, task, "blocked", executor.get("id") or "executor", task["blockedReason"], attempt_id)
        _send_project_execution_intervention_notification(project, task, task["blockedReason"], attempt_id, event="blocked", kind="error")
    project["workflowPhase"] = task["executionState"]
    _save_projects(data)
    with _PROJECT_EXECUTION_LOCK:
        _PROJECT_EXECUTION_CANCEL_FLAGS.pop(attempt_id, None)
    if result.get("ok") and attempt.get("autoReviewAfterExecution"):
        _handle_project_execution_review_start(project_id, task_id, {"attemptId": attempt_id})


def _handle_project_execution_start(project_id, task_id, body):
    body = body or {}
    data, project, task = _project_execution_find(project_id, task_id)
    if not project or not task:
        return {"error": "Project or task not found", "_status": 404}
    if not _project_execution_enabled(project):
        return {"error": "Project Execution is not enabled for this project", "_status": 409}
    workspace = _project_execution_validate_workspace(project.get("workspacePath"))
    if not workspace.get("ok"):
        project["workspaceStatus"] = workspace
        _send_project_execution_intervention_notification(project, task, workspace.get("error") or "Project workspace is not available.", task.get("activeAttemptId"), event="start_failed", kind="error")
        _save_projects(data)
        return {**workspace, "_status": 409}
    roles = _project_execution_resolve_start_roles(
        project,
        task,
        allow_skip_reviewer=bool(body.get("skipReviewConfirmed")) or task.get("allowReviewerlessExecution") is True,
    )
    if not roles.get("ok"):
        payload = {**roles, "_status": 409}
        _send_project_execution_intervention_notification(project, task, roles.get("error") or "Project Execution role configuration needs user attention.", task.get("activeAttemptId"), event="start_failed", kind="error")
        _save_projects(data)
        if roles.get("confirmationRequired"):
            payload.update({
                "taskId": task_id,
                "startMode": _project_execution_start_mode(project, body) if body.get("projectStart") else "single",
                "requiresUserAcceptance": _project_execution_requires_user_acceptance(task),
            })
        return payload
    active = _project_execution_active_task(project)
    if active:
        return {"error": "Another task is already active for this project", "activeTaskId": active.get("id"), "_status": 409}
    snapshot = _project_execution_git_snapshot(workspace["path"])
    start_mode = _project_execution_start_mode(project, body) if body.get("projectStart") else "single"
    project_flow = bool(body.get("projectStart")) and start_mode == "continuous"
    if snapshot.get("dirty") and str(body.get("dirtyFingerprint") or "") != snapshot.get("fingerprint"):
        return {"ok": False, "confirmationRequired": True, "code": "dirty_worktree_confirmation_required", "taskId": task_id, "startMode": start_mode, "requiresUserAcceptance": _project_execution_requires_user_acceptance(task), "dirtyFingerprint": snapshot.get("fingerprint"), "dirtyFiles": snapshot.get("files", [])[:50], "truncated": snapshot.get("truncated", False), "_status": 409}
    if snapshot.get("dirty"):
        project.setdefault("executionDirtyConfirmations", []).append(snapshot.get("fingerprint"))
        project["executionDirtyConfirmations"] = project["executionDirtyConfirmations"][-100:]
    reopened_completed_task = False
    if task.get("completedAt"):
        if task.get("scheduledRepeatEnabled") is not True:
            return {
                "ok": False,
                "error": "Task is completed and repeat triggering is not enabled",
                "code": "task_completed_repeat_disabled",
                "taskId": task_id,
                "_status": 409,
            }
        reopened_completed_task = _project_execution_reopen_completed_task(project, task, actor=str(body.get("by") or "user"))
    if body.get("resetExecutionContext") is True:
        _project_execution_clear_restart_bindings(task, _proj_now(), str(body.get("by") or "user"), "manual task restart")
    attempt_id = str(uuid.uuid4())
    project["projectExecutionStartMode"] = start_mode if body.get("projectStart") else project.get("projectExecutionStartMode", "continuous")
    project["projectExecutionFlowActive"] = project_flow
    project["projectExecutionFlowStopReason"] = None
    meeting_action_phase = _project_execution_has_pending_meeting_actions(task)
    attempt_status = "meeting_action_items" if meeting_action_phase else "executing"
    attempt = {"id": attempt_id, "status": attempt_status, "startedAt": _proj_now(), "workspacePath": workspace["path"], "workspaceKind": workspace["kind"], "dirtyConfirmed": bool(snapshot.get("dirty")), "dirtyFingerprint": snapshot.get("fingerprint") if snapshot.get("dirty") else "", "executor": roles["executor"], "reviewer": roles.get("reviewer"), "skipReview": bool(roles.get("skipReview")), "skipReviewReason": roles.get("skipReviewReason"), "baseline": snapshot, "startMode": start_mode, "projectFlow": project_flow, "requiresUserAcceptance": _project_execution_requires_user_acceptance(task), "autoReviewAfterExecution": bool(body.get("autoReviewAfterExecution")) and not roles.get("skipReview"), "meetingActionPhase": meeting_action_phase}
    task.setdefault("attempts", []).append(attempt)
    task["attempts"] = task["attempts"][-20:]
    if not task.get("assignee"):
        task["assignee"] = roles["executor"]["id"]
    task.update({"activeAttemptId": attempt_id, "executorAgentId": roles["executor"]["id"], "reviewerAgentId": (roles.get("reviewer") or {}).get("id"), "blockedReason": None, "lastError": None})
    project.update({"workspaceStatus": workspace, "workflowActive": True, "workflowPhase": "executing", "activeTaskId": task_id, "activeAgent": roles["executor"]["id"]})
    transition_reason = "Meeting action item phase started" if meeting_action_phase else "Project Execution task started"
    _project_execution_transition(project, task, "executing", "user", transition_reason, attempt_id)
    _save_projects(data)
    cancel_flag = threading.Event()
    with _PROJECT_EXECUTION_LOCK:
        _PROJECT_EXECUTION_CANCEL_FLAGS[attempt_id] = cancel_flag
    threading.Thread(target=_project_execution_run_attempt, args=(project_id, task_id, attempt_id, cancel_flag), daemon=True).start()
    return {"ok": True, "status": "started", "taskId": task_id, "attemptId": attempt_id, "startMode": start_mode, "requiresUserAcceptance": _project_execution_requires_user_acceptance(task), "reopenedCompletedTask": reopened_completed_task}


def _handle_project_execution_project_start(project_id, body=None):
    body = body or {}
    data, project, _ = _project_execution_find(project_id)
    if not project:
        return {"error": "Project not found", "_status": 404}
    if not _project_execution_enabled(project):
        return {"error": "Project Execution is not enabled for this project", "_status": 409}
    active = _project_execution_active_task(project)
    if active:
        return {"error": "Another task is already active for this project", "activeTaskId": active.get("id"), "_status": 409}
    restart_pipeline = body.get("restartPipeline") is True
    reset_result = None
    if restart_pipeline:
        if not _project_execution_all_tasks_repeatable(project):
            return {
                "ok": False,
                "error": "Project pipeline can only be restarted when every task allows retriggering",
                "code": "project_restart_requires_all_tasks_repeatable",
                "_status": 409,
            }
        reset_result = _project_execution_reset_project_tasks_for_restart(project, actor=str(body.get("by") or "user"))
        if not reset_result.get("ok"):
            return reset_result
        _save_projects(data)
    task = _project_execution_next_task(project)
    if not task:
        project["projectExecutionFlowActive"] = False
        project["projectExecutionFlowStopReason"] = "no_eligible_task"
        project["workflowActive"] = False
        project["workflowPhase"] = "no_eligible_task"
        project["updatedAt"] = _proj_now()
        _send_project_execution_project_complete_notification(project, "Project Execution 已完成，当前没有可继续执行的任务。")
        _save_projects(data)
        return {"error": "No eligible task to start", "code": "no_eligible_task", "_status": 409}
    mode = _project_execution_start_mode(project, body)
    result = _handle_project_execution_start(project_id, task.get("id"), {**body, "mode": mode, "projectStart": True, "autoReviewAfterExecution": True})
    if restart_pipeline and isinstance(result, dict):
        result["restartPipeline"] = True
        result["resetTaskCount"] = (reset_result or {}).get("resetTaskCount", 0)
    if result.get("ok") or result.get("confirmationRequired"):
        result["selectedTask"] = {"id": task.get("id"), "title": task.get("title", "")}
    if result.get("confirmationRequired") or (not result.get("ok") and result.get("error")):
        data, project, _ = _project_execution_find(project_id)
        if project:
            project["projectExecutionStartMode"] = mode
            project["projectExecutionFlowActive"] = False
            project["projectExecutionFlowStopReason"] = result.get("code") or result.get("error")
            project["workflowActive"] = False
            project["workflowPhase"] = result.get("code") or "start_failed"
            project["updatedAt"] = _proj_now()
            _save_projects(data)
        result["selectedTask"] = {"id": task.get("id"), "title": task.get("title", "")}
    return result


def _project_execution_schedule_continue(project_id, reason="continue"):
    def run():
        time.sleep(0.05)
        result = _handle_project_execution_project_start(project_id, {"mode": "continuous", "by": "system", "flowReason": reason})
        if result.get("ok"):
            return
        data, project, _ = _project_execution_find(project_id)
        if not project:
            return
        project["projectExecutionFlowActive"] = False
        project["projectExecutionFlowStopReason"] = result.get("code") or result.get("error") or reason
        if not project.get("workflowActive"):
            project["workflowPhase"] = result.get("code") or "stopped"
        project["updatedAt"] = _proj_now()
        _save_projects(data)
    threading.Thread(target=run, daemon=True).start()


def _handle_project_execution_status(project_id, task_id=None):
    data, project, task = _project_execution_find(project_id, task_id)
    if not project or (task_id and not task):
        return {"error": "Project or task not found", "_status": 404}
    targets = [task] if task else project.get("tasks", [])
    changed = False
    for item in targets:
        if item and item.get("executionState") in {"validating", "executing", "reviewing", "reworking"}:
            attempt_id = item.get("activeAttemptId")
            with _PROJECT_EXECUTION_LOCK:
                live = bool(attempt_id and (attempt_id in _PROJECT_EXECUTION_CANCEL_FLAGS or attempt_id in _PROJECT_EXECUTION_REVIEW_FLAGS))
            if not live:
                item["activeAttemptId"] = None
                item["blockedReason"] = "previous_execution_not_resumable"
                _project_execution_transition(project, item, "blocked", "system", item["blockedReason"], attempt_id)
                changed = True
    if changed:
        project.update({"workflowActive": False, "activeTaskId": None, "activeAgent": None, "workflowPhase": "blocked"})
        _save_projects(data)
    return {
        "ok": True,
        "active": bool(project.get("workflowActive")),
        "phase": project.get("workflowPhase") or "idle",
        "currentTaskId": project.get("activeTaskId"),
        "startMode": project.get("projectExecutionStartMode") or "continuous",
        "flowActive": bool(project.get("projectExecutionFlowActive")),
        "flowStopReason": project.get("projectExecutionFlowStopReason"),
        "task": task,
    }


def _handle_project_execution_cancel(project_id, task_id, body=None):
    data, project, task = _project_execution_find(project_id, task_id)
    if not project or not task:
        return {"error": "Task not found", "_status": 404}
    attempt_id = str((body or {}).get("attemptId") or task.get("activeAttemptId") or "")
    if not attempt_id or task.get("activeAttemptId") != attempt_id:
        return {"error": "No matching active attempt", "_status": 409}
    with _PROJECT_EXECUTION_LOCK:
        flag = _PROJECT_EXECUTION_CANCEL_FLAGS.get(attempt_id)
        if flag:
            flag.set()
    attempt = _project_execution_attempt(task, attempt_id) or {}
    attempt["status"] = "cancelling"
    task["activeAttemptId"] = None
    task["blockedReason"] = "Execution was stopped by user. Existing workspace changes were not rolled back."
    task["lastError"] = None
    _project_execution_transition(project, task, "blocked", "user", task["blockedReason"], attempt_id)
    _send_project_execution_intervention_notification(project, task, task["blockedReason"], attempt_id, event="blocked", kind="warning")
    project.update({
        "workflowActive": False,
        "workflowPhase": "blocked",
        "activeTaskId": None,
        "activeAgent": None,
        "projectExecutionFlowActive": False,
        "projectExecutionFlowStopReason": "user_stopped_execution",
        "updatedAt": _proj_now(),
    })
    _save_projects(data)
    executor = attempt.get("executor") or {}
    if executor.get("providerKind") == "codex":
        _handle_codex_cancel({"agentId": executor.get("id"), "conversationId": attempt_id, "workspace": attempt.get("workspacePath")})
    elif executor.get("providerKind") == "openclaw":
        raw_session_key = _wf_task_session_key(executor.get("id"), project_id, attempt_id or task_id)
        _wf_abort_task_session(_openclaw_gateway_session_key(executor.get("id"), raw_session_key))
    return {"ok": True, "status": "blocked", "attemptId": attempt_id, "task": task}


def _handle_project_execution_review_start(project_id, task_id, body=None):
    data, project, task = _project_execution_find(project_id, task_id)
    if not project or not task:
        return {"error": "Project or task not found", "_status": 404}
    if not _project_execution_enabled(project):
        return {"error": "Project Execution is not enabled for this project", "_status": 409}
    if task.get("executionState") != "execution_complete":
        return {"error": "Task must be execution_complete before reviewer handoff", "_status": 409}
    attempt = _project_execution_latest_attempt(task)
    if not attempt or not (attempt.get("evidence") or task.get("evidence")):
        return {"error": "Execution evidence is required before review", "_status": 409}
    requested_attempt = str((body or {}).get("attemptId") or attempt.get("id"))
    if requested_attempt != attempt.get("id"):
        return {"error": "Stale or mismatched attempt cannot be reviewed", "_status": 409}
    roles = _project_execution_resolve_roles(project, task)
    if not roles.get("ok"):
        return {**roles, "_status": 409}
    active = _project_execution_active_task(project)
    if active:
        return {"error": "Another task is already active for this project", "activeTaskId": active.get("id"), "_status": 409}
    review_id = str(uuid.uuid4())
    attempt["reviewer"] = roles["reviewer"]
    attempt["reviewStartedAt"] = _proj_now()
    task.update({"activeAttemptId": review_id, "reviewerAgentId": roles["reviewer"]["id"], "reviewResult": {}, "blockedReason": None, "lastError": None})
    project.update({"workflowActive": True, "workflowPhase": "reviewing", "activeTaskId": task_id, "activeAgent": roles["reviewer"]["id"]})
    _project_execution_transition(project, task, "reviewing", "user", "Independent reviewer handoff started", attempt.get("id"))
    _save_projects(data)
    with _PROJECT_EXECUTION_LOCK:
        _PROJECT_EXECUTION_REVIEW_FLAGS.add(review_id)
    threading.Thread(target=_project_execution_run_review, args=(project_id, task_id, attempt.get("id"), review_id), daemon=True).start()
    return {"ok": True, "status": "reviewing", "taskId": task_id, "attemptId": attempt.get("id"), "reviewId": review_id}


def _handle_project_execution_acceptance(project_id, task_id, body=None):
    body = body or {}
    data, project, task = _project_execution_find(project_id, task_id)
    if not project or not task:
        return {"error": "Project or task not found", "_status": 404}
    if not _project_execution_enabled(project):
        return {"error": "Project Execution is not enabled for this project", "_status": 409}
    action = str(body.get("action") or "").strip()
    if action not in {"accept", "reject_and_rework", "mark_blocked"}:
        return {"error": "Invalid acceptance action", "_status": 400}
    review = task.get("reviewResult") or {}
    attempt_id = str(body.get("attemptId") or "")
    if action == "accept":
        if task.get("executionState") != "awaiting_user_acceptance" or review.get("status") not in {"pass", "skipped"}:
            return {"error": "Reviewer pass or skipped review confirmation is required before user acceptance", "_status": 409}
        if not attempt_id or attempt_id != review.get("attemptId"):
            return {"error": "Stale or mismatched acceptance attempt", "_status": 409}
        done_col = _wf_get_done_col(project)
        if not done_col:
            return {"error": "Done column not found", "_status": 409}
        done_reason = "User accepted skipped review result" if review.get("status") == "skipped" else "User accepted reviewer pass"
        done_result = _project_execution_mark_done(
            project,
            task,
            "user",
            done_reason,
            attempt_id,
            allow_empty_checklist=body.get("allowEmptyChecklist") is True,
        )
        if not done_result.get("ok"):
            return done_result
        task.setdefault("acceptanceHistory", []).append({"action": "accept", "attemptId": attempt_id, "at": _proj_now(), "by": "user"})
        task["acceptanceHistory"] = task["acceptanceHistory"][-50:]
        should_continue = project.get("projectExecutionStartMode") == "continuous"
        project.update({"workflowActive": False, "workflowPhase": "done", "activeTaskId": None, "activeAgent": None, "updatedAt": _proj_now(), "projectExecutionFlowActive": should_continue, "projectExecutionFlowStopReason": None if should_continue else "user_acceptance_completed"})
        _log_activity(project, "project_execution_user_accepted", "user", f"User accepted Project Execution task '{task.get('title', '')}'", task_id)
        _save_projects(data)
        if should_continue:
            _project_execution_schedule_continue(project_id, "user_accepted")
        return {"ok": True, "status": "done", "task": task, "flowContinues": should_continue}
    feedback = str(body.get("feedback") or "").strip()
    if not feedback:
        return {"error": "Feedback is required", "_status": 400}
    if task.get("executionState") != "awaiting_user_acceptance" or review.get("status") not in {"pass", "skipped"}:
        return {"error": "A current reviewer pass or skipped review result is required before this acceptance action", "_status": 409}
    if attempt_id and attempt_id != review.get("attemptId"):
        return {"error": "Stale or mismatched acceptance attempt", "_status": 409}
    task.setdefault("acceptanceHistory", []).append({"action": action, "attemptId": review.get("attemptId"), "feedback": _project_execution_redact(feedback), "at": _proj_now(), "by": "user"})
    task["acceptanceHistory"] = task["acceptanceHistory"][-50:]
    task["reviewResult"] = {}
    task["reworkFeedback"] = _project_execution_redact(feedback)
    if action == "reject_and_rework":
        workspace = _project_execution_validate_workspace(project.get("workspacePath"))
        if not workspace.get("ok"):
            task["blockedReason"] = workspace.get("error") or "Project workspace is not available for rework."
            _project_execution_transition(project, task, "blocked", "system", task["blockedReason"], review.get("attemptId"))
            _send_project_execution_intervention_notification(project, task, task["blockedReason"], review.get("attemptId"), event="blocked", kind="error")
            project.update({"workspaceStatus": workspace, "workflowActive": False, "workflowPhase": "blocked", "activeTaskId": None, "activeAgent": None, "updatedAt": _proj_now()})
            _save_projects(data)
            return {**workspace, "_status": 409}
        active = _project_execution_active_task(project)
        if active:
            return {"error": "Another task is already active for this project", "activeTaskId": active.get("id"), "_status": 409}
        roles = _project_execution_resolve_start_roles(
            project,
            task,
            allow_skip_reviewer=task.get("allowReviewerlessExecution") is True or review.get("status") == "skipped",
        )
        if not roles.get("ok"):
            return {**roles, "_status": 409}
        task["reworkCount"] = int(task.get("reworkCount") or 0) + 1
        task["blockedReason"] = None
        rejected_source = "skipped review result" if review.get("status") == "skipped" else "reviewer pass"
        rework_attempt_id = str(uuid.uuid4())
        rework_attempt = {
            "id": rework_attempt_id,
            "status": "reworking",
            "startedAt": _proj_now(),
            "workspacePath": workspace["path"],
            "workspaceKind": workspace["kind"],
            "dirtyConfirmed": False,
            "dirtyFingerprint": "",
            "executor": roles["executor"],
            "reviewer": roles.get("reviewer"),
            "skipReview": bool(roles.get("skipReview")),
            "skipReviewReason": roles.get("skipReviewReason"),
            "baseline": _project_execution_git_snapshot(workspace["path"]),
            "startMode": "single",
            "projectFlow": False,
            "requiresUserAcceptance": _project_execution_requires_user_acceptance(task),
            "rework": True,
            "reworkCycle": task["reworkCount"],
            "reworkFromAttemptId": review.get("attemptId"),
            "reworkFeedback": task["reworkFeedback"],
            "autoReviewAfterExecution": not roles.get("skipReview"),
        }
        task.setdefault("attempts", []).append(rework_attempt)
        task["attempts"] = task["attempts"][-20:]
        task.update({"activeAttemptId": rework_attempt_id, "executorAgentId": roles["executor"]["id"], "reviewerAgentId": (roles.get("reviewer") or {}).get("id"), "lastError": None})
        project.update({"workspaceStatus": workspace, "projectExecutionFlowActive": False, "projectExecutionFlowStopReason": None, "workflowActive": True, "workflowPhase": "reworking", "activeTaskId": task_id, "activeAgent": roles["executor"]["id"], "updatedAt": _proj_now()})
        _project_execution_transition(project, task, "reworking", "user", f"User rejected {rejected_source}: {feedback}", rework_attempt_id)
        _save_projects(data)
        cancel_flag = threading.Event()
        with _PROJECT_EXECUTION_LOCK:
            _PROJECT_EXECUTION_CANCEL_FLAGS[rework_attempt_id] = cancel_flag
        threading.Thread(target=_project_execution_run_attempt, args=(project_id, task_id, rework_attempt_id, cancel_flag), daemon=True).start()
        return {"ok": True, "status": "reworking", "task": task, "attemptId": rework_attempt_id}
    task["blockedReason"] = _project_execution_redact(feedback)
    _project_execution_transition(project, task, "blocked", "user", feedback, review.get("attemptId"))
    _send_project_execution_intervention_notification(project, task, task["blockedReason"], review.get("attemptId"), event="blocked", kind="warning")
    project.update({"workflowActive": False, "workflowPhase": "blocked", "activeTaskId": None, "activeAgent": None, "updatedAt": _proj_now()})
    _save_projects(data)
    return {"ok": True, "status": "blocked", "task": task}


def _handle_project_execution_meeting_blocker_action(project_id, task_id, body=None):
    body = body or {}
    action = str(body.get("action") or "").strip()
    if action not in {"continue_execution", "mark_blocked", "reopen_meeting"}:
        return {"error": "Invalid meeting blocker action", "_status": 400}
    data, project, task = _project_execution_find(project_id, task_id)
    if not project or not task:
        return {"error": "Project or task not found", "_status": 404}
    if task.get("executionState") != "awaiting_meeting_resolution":
        return {"error": "Task is not waiting for meeting resolution", "_status": 409}
    blocker = task.get("meetingBlocker") if isinstance(task.get("meetingBlocker"), dict) else {}
    if not _project_execution_meeting_blocker_unresolved(blocker):
        return {"error": "Task has no unresolved meeting blocker", "_status": 409}
    now = _proj_now()
    feedback = _project_execution_redact(str(body.get("feedback") or body.get("reason") or "").strip())
    blocker["userAction"] = action
    blocker["userActionReason"] = feedback
    blocker["resolvedAt"] = now
    blocker["updatedAt"] = now
    task["meetingBlocker"] = blocker
    task.setdefault("meetingBlockerHistory", []).append(dict(blocker))
    task["meetingBlockerHistory"] = task["meetingBlockerHistory"][-50:]
    if action == "mark_blocked":
        blocker["status"] = "blocked"
        _meeting_request_resolve_task_blocker(blocker.get("requestId"), "blocked", {"userAction": action})
        task["blockedReason"] = feedback or "User marked task blocked while waiting for meeting resolution."
        _project_execution_transition(project, task, "blocked", "user", task["blockedReason"], blocker.get("requestId"))
        project.update({"workflowActive": False, "workflowPhase": "blocked", "activeTaskId": None, "activeAgent": None, "projectExecutionFlowActive": False, "projectExecutionFlowStopReason": "meeting_user_blocked", "updatedAt": now})
        _save_projects(data)
        return {"ok": True, "status": "blocked", "task": task}
    blocker["status"] = "cleared"
    _meeting_request_resolve_task_blocker(blocker.get("requestId"), "cleared", {"userAction": action})
    task["blockedReason"] = None
    task["lastError"] = None
    if action == "reopen_meeting":
        _project_execution_transition(project, task, "backlog", "user", feedback or "User cleared meeting blocker to request a new meeting.", blocker.get("requestId"))
        _project_execution_move_task_to_column(project, task, _wf_get_backlog_col(project))
        project.update({"workflowActive": False, "workflowPhase": "meeting_reopen_ready", "activeTaskId": None, "activeAgent": None, "projectExecutionFlowActive": False, "projectExecutionFlowStopReason": "meeting_reopen_requested", "updatedAt": now})
        _save_projects(data)
        return {"ok": True, "status": "meeting_reopen_ready", "task": task}
    _project_execution_transition(project, task, "backlog", "user", feedback or "User chose to continue execution despite unresolved meeting blocker.", blocker.get("requestId"))
    _project_execution_move_task_to_column(project, task, _wf_get_backlog_col(project))
    project.update({"workflowActive": False, "workflowPhase": "meeting_override_continue", "activeTaskId": None, "activeAgent": None, "projectExecutionFlowActive": project.get("projectExecutionStartMode") == "continuous", "projectExecutionFlowStopReason": None, "updatedAt": now})
    _save_projects(data)
    start_result = _handle_project_execution_start(project_id, task_id, {"projectStart": True, "mode": project.get("projectExecutionStartMode") or "continuous", "autoReviewAfterExecution": True, "by": "user"})
    if start_result.get("ok"):
        _, _, refreshed_task = _project_execution_find(project_id, task_id)
        return {"ok": True, "status": "started", "task": refreshed_task or task, "startResult": start_result}
    data, project, task = _project_execution_find(project_id, task_id)
    if project and task:
        task["lastError"] = start_result.get("error") or start_result.get("code") or "Failed to restart task after meeting override"
        project.update({
            "workflowActive": False,
            "workflowPhase": start_result.get("code") or "start_failed",
            "activeTaskId": None,
            "activeAgent": None,
            "projectExecutionFlowActive": False,
            "projectExecutionFlowStopReason": "meeting_override_start_failed",
            "updatedAt": _proj_now(),
        })
        _save_projects(data)
    return {"ok": False, "status": "start_failed", "task": task, "startResult": start_result, "error": start_result.get("error") or start_result.get("code") or "Failed to restart task after meeting override", "code": start_result.get("code"), "_status": start_result.get("_status", 409)}


# ─── PROJECT WORKFLOW ENGINE ──────────────────────────────────────────────────
# Background thread-based workflow: Backlog → In Progress → Review → Done
# Uses `openclaw agent` CLI or Gateway HTTP API to dispatch tasks and reviews to agents.
##############################################################################


# Global workflow state: { projectId: { "active": bool, "autoMode": bool, "currentTaskId": str, "phase": str, "thread": Thread, "stopFlag": Event } }
_WORKFLOW_STATE = {}
_WORKFLOW_LOCK = threading.Lock()

# Legacy task markdown files directory (kept for backward compatibility if present)
TASK_FILES_DIR = os.path.join(STATUS_DIR, "project-tasks")

def _wf_find_column(project, title_lower):
    """Find a column by title (case-insensitive). Tries exact match first, then contains."""
    cols = project.get("columns", [])
    # Exact match first
    for col in cols:
        if col.get("title", "").lower() == title_lower:
            return col
    # Fallback: column title contains the keyword (e.g. "Code Review" matches "review")
    for col in cols:
        if title_lower in col.get("title", "").lower():
            return col
    return None

def _wf_get_backlog_col(project):
    """Find the backlog/source column. Tries 'backlog' first, then common alternatives."""
    col = _wf_find_column(project, "backlog")
    if col:
        return col
    # Try common alternative names for the first/source column
    for alt in ("to do", "todo", "ideas", "reported"):
        col = _wf_find_column(project, alt)
        if col:
            return col
    # Last resort: use the first column by order
    cols = project.get("columns", [])
    if cols:
        sorted_cols = sorted(cols, key=lambda c: c.get("order", 0))
        return sorted_cols[0]
    return None

def _wf_get_inprogress_col(project):
    """Find the in-progress/work column. Tries common names, falls back to second column."""
    for name in ("in progress", "in_progress", "sprint", "creating", "writing", "working"):
        col = _wf_find_column(project, name)
        if col:
            return col
    # Fallback: second column by order (between backlog and review)
    cols = sorted(project.get("columns", []), key=lambda c: c.get("order", 0))
    if len(cols) >= 3:
        return cols[1]
    return None

def _wf_get_review_col(project):
    """Find the review column. Tries common names, falls back to second-to-last column."""
    for name in ("review", "code review", "qa", "editing", "testing"):
        col = _wf_find_column(project, name)
        if col:
            return col
    # Fallback: second-to-last column by order
    cols = sorted(project.get("columns", []), key=lambda c: c.get("order", 0))
    if len(cols) >= 3:
        return cols[-2]
    return None

def _wf_get_done_col(project):
    """Find the done/final column. Tries 'done' first, then common alternatives."""
    col = _wf_find_column(project, "done")
    if col:
        return col
    for alt in ("completed", "verified", "published", "fixed", "closed"):
        col = _wf_find_column(project, alt)
        if col:
            return col
    # Last resort: use the last column by order
    cols = project.get("columns", [])
    if cols:
        sorted_cols = sorted(cols, key=lambda c: c.get("order", 0))
        return sorted_cols[-1]
    return None

def _wf_next_backlog_task(project):
    """Get highest priority task from backlog column."""
    backlog = _wf_get_backlog_col(project)
    if not backlog:
        return None
    tasks = [t for t in project.get("tasks", []) if t.get("columnId") == backlog["id"]]
    if not tasks:
        return None
    priority_order = {"critical": 0, "high": 1, "medium": 2, "low": 3}
    tasks.sort(key=lambda t: (priority_order.get(t.get("priority", "medium"), 2), t.get("order", 0)))
    return tasks[0]


def _wf_get_active_task(project):
    """Find a task currently in-progress or in review that still needs work.

    This prevents backlog tasks from jumping ahead of tasks that were sent
    back for rework after a failed review cycle.  Only assigned tasks are
    considered (unassigned ones can't be worked by the pipeline).
    """
    inprogress_col = _wf_get_inprogress_col(project)
    review_col = _wf_get_review_col(project)
    active_col_ids = set()
    if inprogress_col:
        active_col_ids.add(inprogress_col["id"])
    if review_col:
        active_col_ids.add(review_col["id"])
    if not active_col_ids:
        return None

    for t in project.get("tasks", []):
        if t.get("columnId") in active_col_ids and t.get("assignee"):
            return t
    return None

def _wf_move_task(project_id, task_id, target_col_id, by="workflow"):
    """Move a task to a target column and persist."""
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if not p:
        return None
    task = next((t for t in p["tasks"] if t["id"] == task_id), None)
    if not task:
        return None
    old_col = next((c["title"] for c in p.get("columns", []) if c["id"] == task.get("columnId")), "?")
    new_col = next((c["title"] for c in p.get("columns", []) if c["id"] == target_col_id), "?")
    task["columnId"] = target_col_id
    # Max order in target column
    col_tasks = [t for t in p["tasks"] if t.get("columnId") == target_col_id and t["id"] != task_id]
    task["order"] = max((t.get("order", 0) for t in col_tasks), default=-1) + 1
    task["updatedAt"] = _proj_now()
    p["updatedAt"] = _proj_now()
    # Handle done column — match common "final" column names
    done_cols = [c["id"] for c in p.get("columns", []) if c.get("title", "").lower() in ("done", "completed", "verified", "published", "fixed", "closed")]
    if target_col_id in done_cols and not task.get("completedAt"):
        task["completedAt"] = _proj_now()
        # Award points
        assignee = task.get("assignee")
        if assignee:
            pts = SCORE_TASK_COMPLETED
            pri = task.get("priority", "medium")
            if pri == "critical": pts += SCORE_CRITICAL_BONUS
            elif pri == "high": pts += SCORE_HIGH_BONUS
            elif pri == "medium": pts += SCORE_MEDIUM_BONUS
            chk = task.get("checklist", [])
            done_items = sum(1 for c in chk if c.get("done"))
            pts += done_items * SCORE_CHECKLIST_BONUS
            _award_points(assignee, pts, f"Completed: {task.get('title','')}")
    elif target_col_id not in done_cols:
        task["completedAt"] = None
    _log_activity(p, "task_moved", by, f"Moved '{task['title']}' from {old_col} to {new_col}", task_id)
    _save_projects(data)
    return task

def _wf_update_task_field(project_id, task_id, field, value):
    """Update a single field on a task and persist."""
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if not p:
        return None
    task = next((t for t in p["tasks"] if t["id"] == task_id), None)
    if not task:
        return None
    task[field] = value
    task["updatedAt"] = _proj_now()
    p["updatedAt"] = _proj_now()
    _save_projects(data)
    return task


def _wf_sync_project_workflow_meta(project_id, *, active=None, phase=None, current_task_id=None, active_agent=None):
    """Mirror live workflow metadata onto the project payload for UI consumers."""
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if not p:
        return None
    if active is not None:
        p["workflowActive"] = active
    if phase is not None:
        p["workflowPhase"] = phase
    if current_task_id is not None or current_task_id is None:
        p["activeTaskId"] = current_task_id
    if active_agent is not None or active_agent is None:
        p["activeAgent"] = active_agent
    p["updatedAt"] = _proj_now()
    _save_projects(data)
    return p

def _wf_write_task_file(project_id, task, status_text, review_results=None, work_log_entry=None):
    """Update canonical markdown-backed task state, preserving compatibility with workflow logging."""
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if not p:
        return
    live_task = next((t for t in p.get("tasks", []) if t.get("id") == task.get("id")), None)
    if not live_task:
        return
    if review_results is not None:
        live_task["reviewCheck"] = review_results
    if work_log_entry:
        comments = live_task.setdefault("comments", [])
        comments.append({
            "id": _proj_uuid(),
            "author": "workflow",
            "text": work_log_entry,
            "createdAt": _proj_now(),
        })
        if len(comments) > 200:
            live_task["comments"] = comments[-200:]
    live_task["updatedAt"] = _proj_now()
    p["updatedAt"] = _proj_now()
    _save_projects(data)


def _wf_read_task_file(project_id, task_id):
    """Read canonical task content from the markdown-backed store and render it into prompt-friendly markdown."""
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if not p:
        return None
    task = next((t for t in p.get("tasks", []) if t.get("id") == task_id), None)
    if not task:
        return None
    lines = [
        f"# Task: {task.get('title', 'Untitled')}",
        f"**Assignee:** {task.get('assignee', 'unassigned')} | **Priority:** {task.get('priority', 'medium')}",
        "",
        "## Description",
        task.get("description", "_No description_") or "_No description_",
        "",
        "## Checklist",
    ]
    checklist = task.get("checklist", [])
    if checklist:
        review_map = {item.get('text', ''): item.get('status', '') for item in (task.get('reviewCheck') or [])}
        for item in checklist:
            check = "x" if item.get("done") else " "
            suffix = f" — {review_map.get(item.get('text', ''), '')}" if review_map.get(item.get('text', '')) else ""
            lines.append(f"- [{check}] {item.get('text', '')}{suffix}")
    else:
        lines.append("- No checklist items")
    comments = task.get("comments", [])
    if comments:
        lines.extend(["", "## Work Log"])
        for comment in comments[-20:]:
            lines.append(f"### {comment.get('createdAt', '')} — {comment.get('author', 'user')}")
            lines.append(comment.get("text", ""))
            lines.append("")
    return "\n".join(lines).strip() + "\n"


# Track workflow sessions for cleanup: { project_id: { task_id: set(session_keys) } }
def _wf_safe_session_part(value, fallback="task", max_len=8):
    text = re.sub(r"[^a-zA-Z0-9_-]+", "-", str(value or "").strip()).strip("-")
    text = (text or fallback)[:max_len].strip("-")
    return text or fallback[:max_len]


def _wf_task_session_key(agent_id, project_id, task_id):
    """Return a stable session key for a workflow task.

    All calls for the same task (work, review, rework) reuse one session.
    This means the agent keeps context across the full task lifecycle,
    prompt caching kicks in, and only ONE session is created per task.
    """
    agent_part = _wf_safe_session_part(agent_id, "agent", max_len=24)
    project_part = _wf_safe_session_part(project_id, "project")
    task_part = _wf_safe_session_part(task_id, "task")
    return f"agent-{agent_part}-openai-wf-{project_part}-{task_part}"


def _wf_browser_exec_action_desc(command):
    """Infer browser verification activity from exec-driven browser automation.

    This keeps workflow review validation compatible with environments where
    visual verification happens through a browser CLI (for example
    `agent-browser ...`) instead of the first-class `browser` tool.
    """
    if not command:
        return None
    cmd = command.strip()
    cmd_lower = cmd.lower()

    browser_markers = (
        "agent-browser ",
        " agent-browser",
        "agent-browser\n",
        "playwright ",
        " npx playwright",
    )
    if not any(marker in cmd_lower for marker in browser_markers):
        return None

    action_map = [
        (" screenshot", "screenshot"),
        (" snapshot", "snapshot"),
        (" open ", "open"),
        (" navigate ", "navigate"),
        (" click ", "click"),
        (" fill ", "fill"),
        (" type ", "type"),
        (" eval ", "eval"),
        (" close", "close"),
        (" wait ", "wait"),
    ]
    action = "browser-cli"
    for needle, label in action_map:
        if needle in cmd_lower:
            action = label
            break

    return f"{action} (exec)"


def _wf_extract_session_activity(agent_id, project_id, task_id):
    if _is_hermes_agent(agent_id):
        agent = _get_hermes_agent(agent_id) or {}
        profile = agent.get("profile") or agent.get("providerAgentId") or "default"
        messages = _load_hermes_history(profile)[-12:]
        return [{"type": "message", "summary": (m.get("text") or "")[:300], "ts": m.get("ts", 0)} for m in messages if m.get("text")]
    if _is_codex_agent(agent_id):
        messages = _load_comm_history(limit=24, conversation_id=task_id)
        return [{"type": "message", "summary": (m.get("text") or "")[:300], "ts": m.get("ts", 0)} for m in messages if m.get("text")]

    """Extract file activity and tool usage from a workflow task's session JSONL.

    Returns a dict with:
      files_read: list of file paths read
      files_edited: list of file paths edited/written
      files_written: list of file paths created/written
      exec_commands: list of commands run
      browser_actions: list of browser actions taken
      tool_call_count: total number of tool calls
    """
    home_path = VO_CONFIG.get("openclaw", {}).get("homePath", os.path.expanduser("~/.openclaw"))
    sessions_dir = os.path.join(home_path, "agents", agent_id, "sessions")
    sessions_json_path = os.path.join(sessions_dir, "sessions.json")
    session_key = _wf_task_session_key(agent_id, project_id, task_id)

    activity = {
        "files_read": [],
        "files_edited": [],
        "files_written": [],
        "exec_commands": [],
        "browser_actions": [],
        "tool_call_count": 0,
    }

    try:
        if not os.path.exists(sessions_json_path):
            return activity
        with open(sessions_json_path, "r") as f:
            sessions_data = json.load(f)
        session_info, _ = _openclaw_get_session_info(sessions_data, agent_id, session_key)
        if not session_info:
            return activity
        session_id = session_info.get("sessionId", "")
        jsonl_path = session_info.get("sessionFile") or (os.path.join(sessions_dir, f"{session_id}.jsonl") if session_id else "")
        if not os.path.exists(jsonl_path):
            return activity

        seen_files_read = set()
        seen_files_edit = set()
        seen_files_write = set()
        seen_browser_actions = set()

        with open(jsonl_path, "r") as f:
            for line in f:
                try:
                    entry = json.loads(line)
                except json.JSONDecodeError:
                    continue
                msg = entry.get("message", entry)
                content = msg.get("content", [])
                if not isinstance(content, list):
                    continue
                for c in content:
                    if not isinstance(c, dict):
                        continue
                    if c.get("type") != "toolCall":
                        continue
                    activity["tool_call_count"] += 1
                    name = c.get("name", "")
                    args = c.get("arguments", {})
                    # Extract file path from various param names
                    fpath = args.get("path") or args.get("file") or args.get("filePath") or args.get("file_path") or ""

                    if name.lower() in ("read",):
                        if fpath and fpath not in seen_files_read:
                            seen_files_read.add(fpath)
                            activity["files_read"].append(fpath)
                    elif name.lower() in ("edit",):
                        if fpath and fpath not in seen_files_edit:
                            seen_files_edit.add(fpath)
                            activity["files_edited"].append(fpath)
                    elif name.lower() in ("write",):
                        if fpath and fpath not in seen_files_write:
                            seen_files_write.add(fpath)
                            activity["files_written"].append(fpath)
                    elif name.lower() == "exec":
                        cmd = args.get("command", "")
                        if cmd:
                            activity["exec_commands"].append(cmd[:200])
                            browser_desc = _wf_browser_exec_action_desc(cmd)
                            if browser_desc and browser_desc not in seen_browser_actions:
                                seen_browser_actions.add(browser_desc)
                                activity["browser_actions"].append(browser_desc)
                    elif name.lower() == "browser":
                        action = args.get("action", "")
                        url = args.get("url", "")
                        if action:
                            desc = action
                            if url:
                                desc += f" → {url}"
                            desc = desc[:200]
                            if desc not in seen_browser_actions:
                                seen_browser_actions.add(desc)
                                activity["browser_actions"].append(desc)
    except Exception as e:
        print(f"[WORKFLOW] Activity extraction error: {e}")

    return activity


def _wf_format_activity_summary(activity):
    """Format extracted session activity as markdown for the task file."""
    lines = []

    if activity["tool_call_count"] == 0:
        lines.append("⚠️ NO TOOL CALLS DETECTED — agent produced text only, no real changes made.")
        return "\n".join(lines)

    lines.append(f"**Tool calls:** {activity['tool_call_count']}")

    if activity["files_read"]:
        lines.append(f"\n**Files read ({len(activity['files_read'])}):**")
        for f in activity["files_read"]:
            lines.append(f"  - `{f}`")

    if activity["files_edited"]:
        lines.append(f"\n**Files edited ({len(activity['files_edited'])}):**")
        for f in activity["files_edited"]:
            lines.append(f"  - `{f}`")

    if activity["files_written"]:
        lines.append(f"\n**Files created/written ({len(activity['files_written'])}):**")
        for f in activity["files_written"]:
            lines.append(f"  - `{f}`")

    if activity["browser_actions"]:
        lines.append(f"\n**Browser verification ({len(activity['browser_actions'])}):**")
        for b in activity["browser_actions"]:
            lines.append(f"  - {b}")

    if activity["exec_commands"]:
        lines.append(f"\n**Commands run ({len(activity['exec_commands'])}):**")
        for cmd in activity["exec_commands"][:20]:  # cap at 20 to avoid huge logs
            lines.append(f"  - `{cmd}`")
        if len(activity["exec_commands"]) > 20:
            lines.append(f"  - ... and {len(activity['exec_commands']) - 20} more")

    return "\n".join(lines)


def _wf_abort_task_session(session_key):
    """Abort a running agent session via gateway chat.abort RPC.

    This immediately kills any in-flight LLM inference for the specific session,
    similar to clicking Stop in the VO chat. Only targets the given session key —
    does not affect the agent's main session or other workflow sessions.
    """
    import asyncio as _asyncio

    async def _do_abort():
        try:
            gw_url = VO_CONFIG["openclaw"]["gatewayUrl"]
            origin = f"http://127.0.0.1:{PORT}"
            token = _get_gateway_token()
            if not token:
                print(f"[WORKFLOW] No gateway token — skipping session abort for {session_key}")
                return False

            import websockets as _ws
            from websockets.asyncio.client import connect as _ws_connect

            async with _asyncio.timeout(15):
                ws = await _ws_connect(
                    gw_url,
                    max_size=1024 * 1024,
                    additional_headers={"Origin": origin},
                    close_timeout=3,
                )
                async with ws:
                    # Wait for challenge
                    raw = await _asyncio.wait_for(ws.recv(), timeout=5)
                    msg = json.loads(raw)
                    if msg.get("event") != "connect.challenge":
                        return False

                    # Authenticate
                    connect_msg = {
                        "type": "req",
                        "id": "wf-abort-1",
                        "method": "connect",
                        "params": {
                            "minProtocol": 4, "maxProtocol": 4,
                            "client": {"id": "vo-workflow", "version": "1.0", "platform": "server", "mode": "webchat"},
                            "role": "operator",
                            "scopes": ["operator.read", "operator.write"],
                            "caps": [], "commands": [], "permissions": {},
                            "auth": {"token": token}
                        }
                    }
                    await ws.send(json.dumps(connect_msg))
                    raw2 = await _asyncio.wait_for(ws.recv(), timeout=5)
                    res = json.loads(raw2)
                    if not res.get("ok"):
                        print(f"[WORKFLOW] Gateway auth failed for session abort: {res.get('error', {}).get('message', 'unknown')}")
                        return False

                    # Send chat.abort targeting ONLY this session key
                    abort_msg = {
                        "type": "req",
                        "id": "wf-abort-2",
                        "method": "chat.abort",
                        "params": {
                            "sessionKey": session_key
                        }
                    }
                    await ws.send(json.dumps(abort_msg))
                    raw3 = await _asyncio.wait_for(ws.recv(), timeout=5)
                    res3 = json.loads(raw3)
                    if res3.get("ok"):
                        print(f"[WORKFLOW] Gateway session aborted: {session_key}")
                        return True
                    else:
                        err = res3.get("error", {}).get("message", "unknown")
                        print(f"[WORKFLOW] Gateway session abort response: {err} (key={session_key})")
                        return False

        except Exception as e:
            print(f"[WORKFLOW] Gateway session abort failed for {session_key}: {e}")
            return False

    try:
        loop = _asyncio.get_running_loop()
        import concurrent.futures
        with concurrent.futures.ThreadPoolExecutor() as pool:
            future = pool.submit(_asyncio.run, _do_abort())
            return future.result(timeout=20)
    except RuntimeError:
        return _asyncio.run(_do_abort())


def _wf_delete_session_via_gateway(session_key):
    """Delete a session from the gateway's in-memory state via WebSocket RPC.

    File-level cleanup alone is not enough — the gateway keeps sessions in memory
    and will keep retrying (with "Continue where you left off") on stale sessions.
    This sends a sessions.delete RPC to properly terminate the session.
    """
    import asyncio as _asyncio

    async def _do_delete():
        try:
            gw_url = VO_CONFIG["openclaw"]["gatewayUrl"]
            origin = f"http://127.0.0.1:{PORT}"
            token = _get_gateway_token()
            if not token:
                print(f"[WORKFLOW] No gateway token — skipping session delete via gateway for {session_key}")
                return False

            import websockets as _ws
            from websockets.asyncio.client import connect as _ws_connect

            async with _asyncio.timeout(15):
                ws = await _ws_connect(
                    gw_url,
                    max_size=1024 * 1024,
                    additional_headers={"Origin": origin},
                    close_timeout=3,
                )
                async with ws:
                    # Wait for challenge
                    raw = await _asyncio.wait_for(ws.recv(), timeout=5)
                    msg = json.loads(raw)
                    if msg.get("event") != "connect.challenge":
                        return False

                    # Authenticate
                    connect_msg = {
                        "type": "req",
                        "id": "wf-cleanup-1",
                        "method": "connect",
                        "params": {
                            "minProtocol": 4, "maxProtocol": 4,
                            "client": {"id": "vo-workflow", "version": "1.0", "platform": "server", "mode": "webchat"},
                            "role": "operator",
                            "scopes": ["operator.read", "operator.write"],
                            "caps": [], "commands": [], "permissions": {},
                            "auth": {"token": token}
                        }
                    }
                    await ws.send(json.dumps(connect_msg))
                    raw2 = await _asyncio.wait_for(ws.recv(), timeout=5)
                    res = json.loads(raw2)
                    if not res.get("ok"):
                        print(f"[WORKFLOW] Gateway auth failed for session delete: {res.get('error', {}).get('message', 'unknown')}")
                        return False

                    # Send sessions.delete
                    delete_msg = {
                        "type": "req",
                        "id": "wf-cleanup-2",
                        "method": "sessions.delete",
                        "params": {
                            "key": session_key,
                            "deleteTranscript": True,
                            "emitLifecycleHooks": False
                        }
                    }
                    await ws.send(json.dumps(delete_msg))
                    raw3 = await _asyncio.wait_for(ws.recv(), timeout=5)
                    res3 = json.loads(raw3)
                    if res3.get("ok"):
                        print(f"[WORKFLOW] Gateway session deleted: {session_key}")
                        return True
                    else:
                        # Session may not exist in gateway memory — that's fine
                        err = res3.get("error", {}).get("message", "unknown")
                        print(f"[WORKFLOW] Gateway session delete response: {err} (key={session_key})")
                        return False

        except Exception as e:
            print(f"[WORKFLOW] Gateway session delete failed for {session_key}: {e}")
            return False

    # Run the async delete — handle both threaded and event-loop contexts
    try:
        loop = _asyncio.get_running_loop()
        # We're inside an async context — schedule as a task
        # Since workflow runs in a sync thread, this shouldn't happen,
        # but handle it gracefully
        import concurrent.futures
        with concurrent.futures.ThreadPoolExecutor() as pool:
            future = pool.submit(_asyncio.run, _do_delete())
            return future.result(timeout=20)
    except RuntimeError:
        # No running loop — safe to use asyncio.run
        return _asyncio.run(_do_delete())


def _wf_cleanup_task_sessions(agent_id, project_id, task_id):
    if _is_hermes_agent(agent_id):
        return

    """Delete the single session created for this workflow task.

    Two-phase cleanup:
    1. Tell the gateway to drop the session from memory (prevents retry loops)
    2. Delete session files from disk (cleanup storage)

    Phase 1 is critical — without it, the gateway keeps the session alive and
    fires "Continue where you left off" retries that loop forever.
    """
    session_key = _wf_task_session_key(agent_id, project_id, task_id)
    gateway_session_key = _openclaw_gateway_session_key(agent_id, session_key)

    # Phase 1: Delete from gateway's in-memory state
    _wf_delete_session_via_gateway(gateway_session_key)

    # Phase 2: Clean up session files on disk
    home_path = VO_CONFIG.get("openclaw", {}).get("homePath", os.path.expanduser("~/.openclaw"))
    sessions_dir = os.path.join(home_path, "agents", agent_id, "sessions")
    sessions_json_path = os.path.join(sessions_dir, "sessions.json")

    try:
        if not os.path.exists(sessions_json_path):
            return

        with open(sessions_json_path, "r") as f:
            sessions_data = json.load(f)

        session_info, stored_session_key = _openclaw_get_session_info(sessions_data, agent_id, session_key)
        if not session_info:
            return

        # Get session ID to delete the JSONL file
        session_id = session_info.get("sessionId", "")
        session_file = session_info.get("sessionFile", "")
        del sessions_data[stored_session_key]

        with open(sessions_json_path, "w") as f:
            json.dump(sessions_data, f)

        # Delete session JSONL and lock files
        cleanup_paths = []
        if session_file:
            cleanup_paths.extend([session_file, f"{session_file}.lock"])
        if session_id:
            cleanup_paths.extend([os.path.join(sessions_dir, f"{session_id}{ext}") for ext in [".jsonl", ".jsonl.lock", ".trajectory.jsonl", ".trajectory-path.json"]])
        for fpath in dict.fromkeys(cleanup_paths):
            if fpath and os.path.exists(fpath):
                os.remove(fpath)

        print(f"[WORKFLOW] Cleaned up session files for agent={agent_id} task={task_id[:8]}: {stored_session_key}")
    except Exception as e:
        print(f"[WORKFLOW] Session file cleanup error: {e}")


def _wf_call_agent(agent_id, message, timeout=600, project_id=None, task_id=None):
    """Call an agent and return its response text.

    All calls for the same task reuse ONE session key, so the agent keeps
    context across work → review → rework cycles, prompt caching works,
    and only one session exists per task (cleaned up when task is done).

    Strategy:
    1. Try the OpenClaw Gateway HTTP API (/v1/chat/completions) — synchronous,
       works when the gateway has openaiHttp enabled.
    2. Fall back to `openclaw agent` CLI — always available when OpenClaw is installed.

    Both are portable — no hardcoded paths or tokens. Config comes from vo-config.json.
    """
    if _is_hermes_agent(agent_id):
        result = _handle_hermes_chat({"agentId": agent_id, "message": message, "timeoutSec": timeout})
        if result.get("ok"):
            return result.get("reply", "")
        return f"[ERROR] Hermes agent failed: {result.get('error') or result.get('reply') or result}"
    if _is_codex_agent(agent_id):
        result = _handle_codex_chat({"agentId": agent_id, "message": message, "timeoutSec": timeout, "conversationId": task_id or ""})
        reply = result.get("reply", "")
        if result.get("ok"):
            return reply
        return f"[ERROR] Codex agent failed: {result.get('error') or reply or result}"

    # Use a stable session key per task — reused across all calls for this task
    session_key = None
    if project_id and task_id:
        session_key = _wf_task_session_key(agent_id, project_id, task_id)

    # Try gateway HTTP API first
    result = _wf_call_agent_http(agent_id, message, timeout, session_key=session_key)
    if result is not None and not str(result).startswith("[ERROR] Gateway returned HTTP 5"):
        return result

    # Some OpenClaw installs do not expose a healthy /v1/chat/completions
    # endpoint but the Control UI WebSocket chat path works. Use it before CLI
    # so Dockerized Virtual Office can still deliver cross-platform messages
    # without needing the host openclaw binary inside the container.
    ws_result = _wf_call_agent_ws(agent_id, message, timeout, session_key=session_key)
    if ws_result is not None:
        return ws_result

    # Fall back to CLI (also pass session key if available)
    return _wf_call_agent_cli(agent_id, message, timeout, session_key=session_key)


def _extract_openclaw_text(value):
    """Normalize OpenClaw message/content shapes into plain text."""
    if value is None:
        return ""
    if isinstance(value, str):
        return value
    if isinstance(value, list):
        parts = []
        for item in value:
            if isinstance(item, str):
                parts.append(item)
            elif isinstance(item, dict):
                parts.append(str(item.get("text") or item.get("content") or item.get("message") or ""))
        return "".join(parts).strip()
    if isinstance(value, dict):
        return _extract_openclaw_text(value.get("text") or value.get("content") or value.get("message") or value.get("delta") or "")
    return str(value)


def _wf_call_agent_ws(agent_id, message, timeout, session_key=None):
    """Call an OpenClaw agent through the gateway WebSocket chat path.

    This mirrors the live Virtual Office chat client. It is intentionally a
    fallback for product deployments where the HTTP OpenAI-compatible endpoint
    is unavailable/unhealthy and the openclaw CLI is not present in the Docker
    container.
    """
    token = _get_gateway_token()
    if not token:
        return None
    session_key = session_key or f"agent:{agent_id}:main"
    gw_url = VO_CONFIG.get("openclaw", {}).get("gatewayUrl", "ws://127.0.0.1:18789")
    origin = f"http://127.0.0.1:{PORT}"

    async def _call():
        async with ws_connect(
            gw_url,
            max_size=1024 * 1024,
            additional_headers={"Origin": origin},
            close_timeout=3,
        ) as ws:
            # Challenge
            await asyncio.wait_for(ws.recv(), timeout=5)
            connect_id = f"vo-ws-connect-{uuid.uuid4()}"
            await ws.send(json.dumps({
                "type": "req",
                "id": connect_id,
                "method": "connect",
                "params": {
                    "minProtocol": 4,
                    "maxProtocol": 4,
                    "client": {"id": "openclaw-control-ui", "version": _get_openclaw_version(), "platform": "web", "mode": "webchat"},
                    "role": "operator",
                    "scopes": ["operator.read", "operator.write", "operator.admin"],
                    "caps": ["tool-events"],
                    "commands": [],
                    "permissions": {},
                    "auth": {"token": token},
                    "locale": "en-US",
                    "userAgent": "virtual-office-server/1.0",
                },
            }))
            # Wait for connect response, ignoring snapshot/events.
            while True:
                raw = await asyncio.wait_for(ws.recv(), timeout=10)
                msg = json.loads(raw)
                if msg.get("id") == connect_id:
                    if not msg.get("ok"):
                        return f"[ERROR] Gateway WS connect failed: {msg.get('error', {}).get('message', 'unknown')}"
                    break

            send_id = f"vo-ws-send-{uuid.uuid4()}"
            await ws.send(json.dumps({
                "type": "req",
                "id": send_id,
                "method": "chat.send",
                "params": {
                    "sessionKey": session_key,
                    "message": message,
                    "idempotencyKey": f"vo-a2a-{uuid.uuid4()}",
                },
            }))
            run_id = None
            final_seen = False
            deadline = time.time() + timeout
            while time.time() < deadline:
                raw = await asyncio.wait_for(ws.recv(), timeout=min(30, max(1, deadline - time.time())))
                msg = json.loads(raw)
                if msg.get("id") == send_id:
                    if not msg.get("ok"):
                        return f"[ERROR] Gateway WS chat.send failed: {msg.get('error', {}).get('message', 'unknown')}"
                    payload = msg.get("payload") or {}
                    run_id = payload.get("runId")
                elif msg.get("event") == "chat":
                    payload = msg.get("payload") or {}
                    if payload.get("sessionKey") == session_key and payload.get("state") in ("final", "done"):
                        text = _extract_openclaw_text(payload.get("text") or payload.get("content") or payload.get("message") or payload.get("delta"))
                        if text:
                            return text
                        final_seen = True
                        break
                    if run_id and payload.get("runId") == run_id and payload.get("state") in ("final", "done"):
                        text = _extract_openclaw_text(payload.get("text") or payload.get("content") or payload.get("message") or payload.get("delta"))
                        if text:
                            return text
                        final_seen = True
                        break
                elif msg.get("event") == "session.message":
                    payload = msg.get("payload") or {}
                    m = payload.get("message") if isinstance(payload.get("message"), dict) else payload
                    if m.get("role") == "assistant" and (payload.get("sessionKey") in (None, session_key) or (run_id and payload.get("runId") == run_id)):
                        text = _extract_openclaw_text(m.get("content") or m.get("text") or m)
                        if text:
                            return text

            # Some gateway versions send final without text; fetch recent history.
            hist_id = f"vo-ws-history-{uuid.uuid4()}"
            await ws.send(json.dumps({"type": "req", "id": hist_id, "method": "chat.history", "params": {"sessionKey": session_key, "limit": 12}}))
            while time.time() < deadline + 10:
                raw = await asyncio.wait_for(ws.recv(), timeout=10)
                msg = json.loads(raw)
                if msg.get("id") != hist_id:
                    continue
                if not msg.get("ok"):
                    return "[DELIVERED] Message delivered to OpenClaw agent; history fetch failed."
                payload = msg.get("payload") or {}
                messages = payload.get("messages") or payload.get("items") or payload.get("history") or []
                if isinstance(messages, dict):
                    messages = messages.get("messages") or messages.get("items") or []
                for item in reversed(messages):
                    role = item.get("role") or item.get("senderKind")
                    text = _extract_openclaw_text(item.get("text") or item.get("content") or item.get("message") or item)
                    if role == "assistant" and text:
                        return text
                return "[DELIVERED] Message delivered to OpenClaw agent."
            return "[DELIVERED] Message delivered to OpenClaw agent." if final_seen else None

    try:
        return asyncio.run(_call())
    except Exception as e:
        print(f"[WORKFLOW] Gateway WS agent call failed: {e}")
        return None


def _wf_call_agent_http(agent_id, message, timeout, session_key=None):
    """Try calling agent via gateway /v1/chat/completions. Returns None if not available.
    If session_key is provided, uses it for session routing (enables cleanup later)."""

    gateway_http = VO_CONFIG.get("openclaw", {}).get("gatewayHttp", "http://127.0.0.1:18789")
    token = _get_gateway_token()
    if not token:
        return None

    url = f"{gateway_http}/v1/chat/completions"
    payload = json.dumps({
        "model": f"openclaw/{agent_id}",
        "messages": [{"role": "user", "content": message}],
    })
    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {token}",
    }
    if session_key:
        headers["x-openclaw-session-key"] = session_key

    try:
        req = urllib.request.Request(url, data=payload.encode("utf-8"), headers=headers, method="POST")
        with urllib.request.urlopen(req, timeout=timeout + 30) as resp:
            content_type = resp.headers.get("Content-Type", "")
            if "application/json" not in content_type:
                # Gateway returned HTML (endpoint not enabled) — fall back to CLI
                return None
            data = json.loads(resp.read().decode("utf-8"))
            choices = data.get("choices", [])
            if choices:
                msg = choices[0].get("message", {})
                return msg.get("content", "")
            return data.get("reply", data.get("text", str(data)))
    except urllib.error.HTTPError as e:
        if e.code in (404, 405):
            # Endpoint not available — fall back to CLI
            return None
        body = ""
        try:
            body = e.read().decode("utf-8", errors="replace")[:500]
        except Exception:
            pass
        return f"[ERROR] Gateway returned HTTP {e.code}: {body}"
    except Exception:
        return None  # Fall back to CLI


def _wf_call_agent_cli(agent_id, message, timeout, session_key=None):
    """Call agent via `openclaw agent` CLI — always available when OpenClaw is installed."""

    openclaw_bin = shutil.which("openclaw")
    if not openclaw_bin:
        return "[ERROR] openclaw CLI not found in PATH"

    cmd = [openclaw_bin, "agent", "--agent", agent_id, "--message", message, "--timeout", str(timeout), "--json"]
    if session_key:
        cmd.extend(["--session-id", session_key])
    try:
        result = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout + 60)
        if result.returncode == 0:
            try:
                data = json.loads(result.stdout)
                return data.get("reply", data.get("text", result.stdout))
            except json.JSONDecodeError:
                return result.stdout.strip()
        else:
            return f"[ERROR] Agent returned code {result.returncode}: {result.stderr.strip()[:500]}"
    except subprocess.TimeoutExpired:
        return "[ERROR] Agent call timed out"
    except Exception as e:
        return f"[ERROR] Agent call failed: {str(e)}"

def _wf_build_project_context(project, task):
    """Build project and task metadata context string."""
    lines = []
    proj_title = project.get("title") or project.get("name") or "Untitled Project"
    proj_desc = project.get("description", "")
    proj_tags = project.get("tags", [])
    task_tags = task.get("tags", [])
    task_priority = task.get("priority", "medium")
    task_assignee = task.get("assignee", "unassigned")

    lines.append(f"PROJECT: {proj_title}")
    if proj_desc:
        lines.append(f"PROJECT DESCRIPTION: {proj_desc}")
    if proj_tags:
        lines.append(f"PROJECT TAGS: {', '.join(proj_tags)}")
    if task_tags:
        lines.append(f"TASK TAGS: {', '.join(task_tags)}")
    lines.append(f"PRIORITY: {task_priority}")
    lines.append(f"ASSIGNED TO: {task_assignee}")
    return "\n".join(lines)


def _wf_build_task_prompt(task, task_file_content=None, project=None):
    """Build the autonomous work prompt for an agent."""
    project_context = ""
    if project:
        project_context = _wf_build_project_context(project, task) + "\n\n"

    checklist_text = ""
    acceptance_checklist = _project_execution_acceptance_checklist(task)
    if acceptance_checklist:
        checklist_text = "\n\nChecklist (you must complete ALL items):\n"
        for i, item in enumerate(acceptance_checklist, 1):
            status = "✅ DONE" if item.get("done") else "⬜ TODO"
            checklist_text += f"  {i}. [{status}] {item.get('text', '')}\n"

    previous_work = ""
    if task_file_content:
        previous_work = f"\n\n--- PREVIOUS WORK LOG ---\n{task_file_content}\n--- END PREVIOUS WORK LOG ---\n\nContinue from where you left off. Do NOT redo work that was already completed."

    return f"""You have been assigned a task. Complete it fully on your own. Do NOT ask for clarification, followups, or user input.

{project_context}TASK: {task.get('title', 'Untitled')}

DESCRIPTION:
{task.get('description', 'No description provided.')}
{checklist_text}
{previous_work}

EXPECTED WORKFLOW:
1. First read the task and determine what content or deliverable must be produced. Write the task/deliverable acceptance criteria into the task checklist. The checklist is only for deliverable acceptance criteria, not a meeting action-item queue. If the task checklist is empty, include the created acceptance criteria in checklistUpdates and, when possible, persist them with PUT /api/projects/{{projectId}}/tasks/{{taskId}}.
2. Execute the task. For any Virtual Office operation, first use the vo-operating-guidelines skill to detect the VO environment, choose the correct VO skill, and follow its boundaries. If you discover an issue that requires alignment, use vo-operating-guidelines to decide whether a formal AI meeting is appropriate; when it is, proactively request a meeting with POST /api/projects/{{projectId}}/tasks/{{taskId}}/meeting-requests. Do not confirm or reject meetings yourself. Add the corresponding action items and discussion points as meeting/task context. Do not put those meeting action items or risks into the checklist or comments.
3. Before finishing, inspect whether every checklist item is complete. Mark completed checklist items done; if any item is unfinished, continue working until it is complete.

MANDATORY RULES — VIOLATIONS WILL FAIL REVIEW:
1. You MUST use tools (read, edit, exec, browser) to make REAL changes to actual files. Text-only responses WILL BE REJECTED.
2. Read the relevant source files FIRST to understand the codebase before making changes.
3. Use the edit tool to modify files. Use exec to run commands, test, or verify.
4. After making changes, verify them yourself — run the app, check the output, confirm it works.
5. In your final response include checklistUpdates as JSON: an array of {{id, text, done, evidence}}. Set done=true only for checklist items you actually verified as complete. Include meetingDiscussionPoints as JSON when there are meeting conclusions, risks, or discussion notes for the task.
5. Use the browser tool to visually verify UI changes on the running app/site if applicable.
6. In your final report, list EVERY file you modified and what you changed.

A reviewer will independently verify your work by reading the actual files and browsing the app. If no real file changes are found, ALL items will be marked DID_NOT_PASS.

WARNING: Do NOT run 'docker restart' on this app's container — it will kill the workflow pipeline managing this task. If you need to reload server changes, the app live-mounts /app so file edits take effect on the next HTTP request for static files. For server.py changes that need a process reload, note what needs restarting in your report and the reviewer will handle it."""

def _wf_task_needs_visual_review(task):
    """Heuristic: determine whether a task should require browser-based review."""
    parts = [
        task.get("title", "") or "",
        task.get("description", "") or "",
    ]
    for item in task.get("checklist") or []:
        parts.append(item.get("text", "") or "")
    hay = "\n".join(parts).lower()

    visual_terms = [
        "ui", "ux", "browser", "page", "screen", "visual", "visually",
        "frontend", "front-end", "layout", "render", "display", "button",
        "form", "modal", "panel", "dashboard", "site", "web app", "webapp",
        "css", "html", "screenshot", "snapshot", "click", "navigation",
        "animation", "canvas", "view", "viewer", "interactive"
    ]
    non_visual_terms = [
        "docs", "documentation", "audit", "analysis", "implementation map",
        "review evidence", "write-up", "writeup", "readme", "markdown"
    ]

    has_visual = any(term in hay for term in visual_terms)
    has_non_visual = any(term in hay for term in non_visual_terms)
    return has_visual and not has_non_visual


def _wf_build_review_prompt(task, task_file_content=None, project=None):
    """Build the self-review prompt for an agent."""
    project_context = ""
    if project:
        project_context = _wf_build_project_context(project, task) + "\n\n"

    items_text = ""
    acceptance_checklist = _project_execution_acceptance_checklist(task)
    if acceptance_checklist:
        for i, item in enumerate(acceptance_checklist, 1):
            items_text += f"  {i}. {item.get('text', '')}\n"

    needs_visual_review = _wf_task_needs_visual_review(task)
    visual_steps = """
3. Use the browser tool to load the running app/site and visually confirm UI changes are working. Take snapshots.
4. If you open any browser/session for review, you MUST close it before finishing your review response. Do not leave browser instances running after review.
5. If you cannot find real file changes for an item, mark it DID_NOT_PASS regardless of what was claimed earlier.""" if needs_visual_review else """
3. Use the browser tool only if the task has a real visual/UI surface that can be meaningfully checked in a running app or site.
4. If you open any browser/session for review, you MUST close it before finishing your review response.
5. If you cannot find real file changes or real deliverables for an item, mark it DID_NOT_PASS regardless of what was claimed earlier."""

    pass_line = "- PASS — verified in the actual files AND confirmed working in the browser/app" if needs_visual_review else "- PASS — verified in the actual files and supported by real verification steps (for example read/exec, and browser if applicable)"
    critical_line = "CRITICAL: You MUST use tools (read, exec, browser) during this review. A text-only review with no tool calls will be considered invalid." if needs_visual_review else "CRITICAL: You MUST use tools during this review. Use read and/or exec for non-visual tasks, and use browser only when the task is visually reviewable. A text-only review with no tool calls will be considered invalid."

    return f"""{project_context}Review your completed work on: {task.get('title', 'Untitled')}

You must INDEPENDENTLY VERIFY each checklist item. Do NOT trust your previous claims — verify by actually checking.

MANDATORY REVIEW STEPS:
1. Use the read tool to open the actual source files that were supposed to be modified. Confirm the changes exist in the code.
2. Use exec to run any tests, linters, or verification commands.
{visual_steps}

For EACH checklist item, respond with one of these statuses:
{pass_line}
- NEEDS_MORE_WORK — partially implemented but has issues you can identify in the code
- DID_NOT_PASS — no real changes found in files, or changes don't work
- REQUIRES_USER_REVIEW — ONLY if the item truly cannot be judged by an agent after using tools, such as a subjective product/design decision, required human sign-off, unavailable external system access that only the user can provide, or a genuinely destructive/approval-gated action. Do NOT use REQUIRES_USER_REVIEW for ordinary coding uncertainty, incomplete implementation, missing evidence, failed verification, or because one item previously needed rework. In those cases you MUST use NEEDS_MORE_WORK or DID_NOT_PASS.

If you can read the code, run tests, inspect outputs, or otherwise verify the implementation yourself, you MUST make your own judgment and use PASS, NEEDS_MORE_WORK, or DID_NOT_PASS.

Respond in this EXACT format (one line per item, after your verification):
REVIEW_ITEM_1: <status>
REVIEW_ITEM_2: <status>
...

Checklist items to review:
{items_text}

{critical_line}"""

def _wf_build_rework_prompt(task, failed_items, task_file_content=None, project=None):
    """Build a rework prompt for failed review items."""
    # project context not repeated in rework — agent already has it from the same session
    items_text = ""
    for i, item in enumerate(failed_items, 1):
        items_text += f"  {i}. {item.get('text', '')} — Status: {item.get('reviewStatus', 'needs_more_work')}\n"

    previous_work = ""
    if task_file_content:
        previous_work = f"\n\n--- PREVIOUS WORK LOG ---\n{task_file_content}\n--- END PREVIOUS WORK LOG ---"

    return f"""These items need more work on: {task.get('title', 'Untitled')}

The following checklist items did NOT pass review. Fix them yourself. Do not ask for help.

Items that need work:
{items_text}
{previous_work}

MANDATORY RULES:
1. You MUST use tools (read, edit, exec, browser) to make REAL changes to actual files.
2. Read the relevant files first, then use edit to fix the issues.
3. After fixing, verify your changes work — use exec to test and browser to visually confirm UI changes.
4. If you open any browser/session during rework or verification, you MUST close it before finishing your response. Do not leave browser instances running.
5. Only fix the items listed above. Do NOT redo work that already passed.
6. In your report, list EVERY file you modified and what you changed.

A reviewer will independently verify your fixes by reading the actual files and browsing the app."""

def _wf_review_had_structured_match(review_results):
    """Check if any review results came from structured line parsing (not defaults/fallbacks).

    Returns True if at least one result was explicitly parsed from a structured
    review line (marked with _parsed=True) or from a freeform-positive fallback.
    Returns False if all results came from the default needs_more_work fill-in
    (marked with _default=True) — indicating the parser couldn't understand the response.
    """
    for r in review_results:
        if r.get("_parsed") or r.get("_fallback"):
            return True
    return False


def _wf_parse_review_response(response_text, checklist, review_cycle=0):
    """Parse the agent's review response into structured results.

    Handles formats like:
      REVIEW_ITEM_1: PASS
      REVIEW_ITEM_2: NEEDS_MORE_WORK
    Or:
      1. PASS
      Item 3: DID_NOT_PASS
    Or freeform lines containing status keywords.

    Important: checks longer status strings first to avoid "PASS" matching "DID_NOT_PASS".

    Fallback behavior for freeform/unstructured responses:
    - If no structured review lines matched, performs sentiment analysis on the full text.
    - If sentiment is positive (pass keywords, no fail keywords), treats as all-pass.
    - If review_cycle >= 3 and all checklist items are marked done, auto-passes.
    """
    results = []
    lines = response_text.strip().split("\n")

    # Ordered longest-first to prevent "pass" from matching "did_not_pass"
    status_patterns = [
        ("requires_user_review", "requires_user_review"),
        ("requires user review", "requires_user_review"),
        ("needs_more_work", "needs_more_work"),
        ("needs more work", "needs_more_work"),
        ("did_not_pass", "did_not_pass"),
        ("did not pass", "did_not_pass"),
        ("pass", "pass"),
    ]

    item_idx = 0
    for line in lines:
        line_stripped = line.strip()
        if not line_stripped or item_idx >= len(checklist):
            continue

        line_lower = line_stripped.lower()

        # Skip lines that don't look like review items (pure prose, headers, etc.)
        # Accept lines with REVIEW_ITEM_, numbered items, or containing a status keyword
        is_review_line = (
            "review_item" in line_lower
            or re.match(r'^\d+[\.\):\s]', line_stripped)
            or "item " in line_lower
        )

        matched_status = None
        for pattern, status_val in status_patterns:
            if pattern in line_lower:
                matched_status = status_val
                break

        if matched_status and (is_review_line or item_idx == 0 or len(checklist) == 1):
            results.append({
                "id": checklist[item_idx].get("id"),
                "text": checklist[item_idx].get("text", ""),
                "status": matched_status,
                "_parsed": True,
            })
            item_idx += 1
        elif matched_status and not is_review_line:
            # Heuristic: if we're already matching items and this line has a status,
            # it's probably a continuation
            if len(results) > 0:
                results.append({
                    "id": checklist[item_idx].get("id"),
                    "text": checklist[item_idx].get("text", ""),
                    "status": matched_status,
                    "_parsed": True,
                })
                item_idx += 1

    # --- Freeform fallback: if no structured lines matched at all ---
    if not results:
        response_lower = response_text.lower()

        # Positive sentiment keywords (agent says everything is good)
        positive_keywords = [
            "all items verified", "all items are done", "all items pass",
            "everything looks good", "everything is working", "all checks pass",
            "all tasks completed", "all completed", "all done", "looks great",
            "fully implemented", "all requirements met", "verified and working",
            "all items look good", "no issues found", "nothing to fix",
            "approved", "lgtm", "ship it",
        ]
        # Negative sentiment keywords (agent says something is wrong)
        negative_keywords = [
            "needs work", "needs more work", "did not pass", "not working",
            "failed", "missing", "incomplete", "broken", "issues found",
            "not implemented", "needs fix", "needs rework", "does not work",
            "errors", "bugs found", "not done", "partially done",
        ]

        # Count occurrences of positive vs negative keywords in the response.
        # This gives a quantitative signal: if positive_count > 0 and
        # negative_count == 0, the agent is clearly approving.
        positive_count = sum(1 for kw in positive_keywords if kw in response_lower)
        negative_count = sum(1 for kw in negative_keywords if kw in response_lower)

        if negative_count > 0:
            # Negative keywords found — don't auto-pass, fall through to defaults.
            # The agent explicitly flagged issues; treat as needs_more_work.
            pass
        else:
            # No structured lines AND zero negative keywords → treat as all-pass.
            # This covers: (a) positive sentiment ("all items verified"), and
            # (b) neutral/ambiguous text with no negatives ("code looks ready").
            # The spec says: empty results = all-pass, not all-fail.
            if positive_count > 0:
                fallback_reason = "freeform_positive_sentiment"
            else:
                fallback_reason = "freeform_no_negatives"
            for i, item in enumerate(checklist):
                results.append({
                    "id": item.get("id"),
                    "text": item.get("text", ""),
                    "status": "pass",
                    "_fallback": fallback_reason,
                    "_positive_count": positive_count,
                    "_negative_count": negative_count,
                })
            return results

        # Cycle-based fallback: if review_cycle >= 3 and all checklist items
        # are already marked done in the project data, auto-pass even with negatives
        if review_cycle >= 3:
            all_checklist_done = all(item.get("done", False) for item in checklist)
            if all_checklist_done:
                for i, item in enumerate(checklist):
                    results.append({
                        "id": item.get("id"),
                        "text": item.get("text", ""),
                        "status": "pass",
                        "_fallback": "cycle_3_checklist_done",
                    })
                return results

    # If parsing failed or incomplete, default remaining to needs_more_work
    for i in range(len(results), len(checklist)):
        results.append({
            "id": checklist[i].get("id"),
            "text": checklist[i].get("text", ""),
            "status": "needs_more_work",
            "_default": True,
        })

    return results

def _wf_unfinished_checklist_items(checklist):
    return [
        item for item in (checklist or [])
        if isinstance(item, dict) and item.get("done") is not True
    ]

def _wf_run_pipeline(project_id, single_task=False):
    """Main workflow pipeline — runs in a background thread."""
    with _WORKFLOW_LOCK:
        wf = _WORKFLOW_STATE.get(project_id)
        if not wf:
            return

    stop_flag = wf["stopFlag"]

    try:
      _wf_run_pipeline_inner(project_id, single_task, wf, stop_flag)
    except Exception as e:
        print(f"[WORKFLOW ERROR] Pipeline crashed for {project_id}: {e}")
        traceback.print_exc()
    finally:
        # Always clean up state
        with _WORKFLOW_LOCK:
            if project_id in _WORKFLOW_STATE:
                _WORKFLOW_STATE[project_id]["active"] = False
                _WORKFLOW_STATE[project_id]["thread"] = None
        _wf_persist_state(project_id)
        _wf_clear_persisted_state(project_id)


def _wf_run_pipeline_inner(project_id, single_task, wf, stop_flag):
    """Inner pipeline logic — wrapped by _wf_run_pipeline for error safety."""
    while not stop_flag.is_set():
        # Load fresh project data
        data = _load_projects()
        project = next((x for x in data["projects"] if x["id"] == project_id), None)
        if not project:
            break

        # Check for an active task (in-progress or review) before pulling from backlog.
        # This prevents backlog tasks from jumping ahead of tasks sent back for rework.
        active_task = _wf_get_active_task(project)
        if active_task:
            # There's already a task being worked on — do NOT pull from backlog.
            # The pipeline should not start a new task while one is still active.
            with _WORKFLOW_LOCK:
                wf["phase"] = "blocked_by_active_task"
                wf["error"] = f"Task '{active_task.get('title', '')}' is still in progress. Backlog tasks will not start until it is fully done or moved to backlog/done."
                wf["currentTaskId"] = active_task["id"]
                wf["active"] = False
            _wf_sync_project_workflow_meta(project_id, active=False, phase="blocked_by_active_task", current_task_id=active_task["id"], active_agent=active_task.get("assignee"))
            _wf_persist_state(project_id)
            break

        # Find next backlog task
        task = _wf_next_backlog_task(project)
        if not task:
            # No more backlog tasks
            with _WORKFLOW_LOCK:
                wf["phase"] = "idle"
                wf["currentTaskId"] = None
                wf["active"] = False
            _wf_sync_project_workflow_meta(project_id, active=False, phase="idle", current_task_id=None, active_agent=None)
            break

        task_id = task["id"]
        assignee = task.get("assignee")
        if not assignee:
            # Skip unassigned tasks
            with _WORKFLOW_LOCK:
                wf["phase"] = "error"
                wf["error"] = "Please assign an agent to all tasks"
                wf["active"] = False
            break

        with _WORKFLOW_LOCK:
            wf["currentTaskId"] = task_id
            wf["phase"] = "dispatching"
            wf["error"] = None
        _wf_sync_project_workflow_meta(project_id, active=True, phase="dispatching", current_task_id=task_id, active_agent=assignee)
        _wf_persist_state(project_id)

        if stop_flag.is_set():
            break

        # Step 1: Move straight to In Progress
        inprogress_col = _wf_get_inprogress_col(project)
        if not inprogress_col:
            with _WORKFLOW_LOCK:
                wf["phase"] = "error"
                wf["error"] = "No 'In Progress' column found"
                wf["active"] = False
            break

        _wf_move_task(project_id, task_id, inprogress_col["id"], by="workflow")
        _wf_write_task_file(project_id, task, "in_progress", work_log_entry="Sent to agent for work")

        with _WORKFLOW_LOCK:
            wf["phase"] = "in_progress"
        _wf_persist_state(project_id)

        if stop_flag.is_set():
            break

        # Clean up any stale session from a previous run of this task.
        # Without this, the gateway may still hold an old session in memory
        # and fire "Continue where you left off" instead of the actual task prompt.
        _wf_cleanup_task_sessions(assignee, project_id, task_id)

        task_file = _wf_read_task_file(project_id, task_id)
        prompt = _wf_build_task_prompt(task, task_file, project=project)
        agent_response = _wf_call_agent(assignee, prompt, project_id=project_id, task_id=task_id)

        if stop_flag.is_set():
            break

        # Update task file with agent response + file activity
        work_activity = _wf_extract_session_activity(assignee, project_id, task_id)
        work_activity_text = _wf_format_activity_summary(work_activity)
        _wf_write_task_file(project_id, task, "in_progress", work_log_entry=f"Agent response:\n{agent_response[:2000]}\n\n**Activity:**\n{work_activity_text}")

        # Step 3: Move to Review
        review_col = _wf_get_review_col(project)
        if not review_col:
            with _WORKFLOW_LOCK:
                wf["phase"] = "error"
                wf["error"] = "No 'Review' column found"
                wf["active"] = False
            break

        _wf_move_task(project_id, task_id, review_col["id"], by="workflow")

        # Review loop
        max_review_cycles = 5
        review_cycle = 0
        task_done = False
        wf["_parseFailCount"] = 0  # Track consecutive parse failures for safety cap
        wf["_reworkCount"] = 0     # Track total consecutive rework cycles for safety cap

        while review_cycle < max_review_cycles and not stop_flag.is_set():
            review_cycle += 1
            with _WORKFLOW_LOCK:
                wf["phase"] = "reviewing"
                wf["reviewCycle"] = review_cycle
            _wf_sync_project_workflow_meta(project_id, active=True, phase="reviewing", current_task_id=task_id, active_agent=assignee)
            _wf_persist_state(project_id)

            # Reload task for fresh checklist
            data = _load_projects()
            project = next((x for x in data["projects"] if x["id"] == project_id), None)
            if not project:
                break
            task = next((t for t in project["tasks"] if t["id"] == task_id), None)
            if not task:
                break

            checklist = _project_execution_acceptance_checklist(task)
            if not checklist:
                _wf_write_task_file(
                    project_id,
                    task,
                    "review",
                    review_results=[{
                        "id": "acceptance-checklist",
                        "text": "Create task acceptance checklist items before completion.",
                        "status": "needs_more_work",
                        "reviewStatus": "needs_more_work",
                        "reason": "Acceptance checklist is empty.",
                    }],
                    work_log_entry="❌ Review: REJECTED — acceptance checklist is empty."
                )
                wf["_reworkCount"] = wf.get("_reworkCount", 0) + 1
                task_done = False
                break

            task_file = _wf_read_task_file(project_id, task_id)
            review_prompt = _wf_build_review_prompt(task, task_file, project=project)
            review_response = _wf_call_agent(assignee, review_prompt, project_id=project_id, task_id=task_id)

            if stop_flag.is_set():
                break

            # Parse review results (pass review_cycle for freeform fallback logic)
            review_results = _wf_parse_review_response(review_response, checklist, review_cycle=review_cycle)

            # Save review results to task
            _wf_update_task_field(project_id, task_id, "reviewCheck", review_results)
            review_activity = _wf_extract_session_activity(assignee, project_id, task_id)
            review_activity_text = _wf_format_activity_summary(review_activity)
            _wf_write_task_file(project_id, task, "review", review_results=review_results, work_log_entry=f"Review cycle {review_cycle}:\n{review_response[:2000]}\n\n**Review verification activity:**\n{review_activity_text}")

            # ── TOOL-CALL VERIFICATION ──────────────────────────────
            # A valid review MUST include actual tool usage to verify the work.
            # For visual/UI tasks, browser review is strongly expected.
            # For non-visual tasks, read/exec verification is enough.
            # Exception: cycle >= 4 with all checklist done bypasses this
            # to prevent infinite loops when the agent refuses to use tools.
            review_tool_count = review_activity.get("tool_call_count", 0)
            review_has_reads = len(review_activity.get("files_read", [])) > 0
            review_has_exec = len(review_activity.get("exec_commands", [])) > 0
            review_has_browser = len(review_activity.get("browser_actions", [])) > 0
            task_needs_visual_review = _wf_task_needs_visual_review(task)
            review_verified = review_has_reads or review_has_exec or review_has_browser
            review_visual_verified = review_has_browser if task_needs_visual_review else True

            # Track whether the original parse had structured matches (before
            # tool-verification may override the result). This is used by the
            # safety cap below to detect repeated parse failures even when
            # freeform-fallback temporarily marks everything as pass.
            original_had_structured = _wf_review_had_structured_match(review_results)

            # Check results
            all_pass = all(r.get("status") == "pass" for r in review_results)
            needs_user = any(r.get("status") == "requires_user_review" for r in review_results)
            failed_items = [r for r in review_results if r.get("status") in ("needs_more_work", "did_not_pass")]

            # Reject reviews that claim all-pass without required verification.
            if all_pass and (not review_verified or not review_visual_verified):
                all_checklist_done = all(item.get("done", False) for item in checklist)
                if review_cycle >= 4 and all_checklist_done:
                    _wf_write_task_file(project_id, task, "review",
                        work_log_entry=f"⚠️ Review cycle {review_cycle}: accepted without full verification (all checklist items done, cycle limit reached)")
                else:
                    all_pass = False
                    failed_items = review_results
                    reason = "used no tools (read/exec/browser) to verify"
                    if review_verified and not review_visual_verified:
                        reason = "did not use browser verification for a visually reviewable task"
                    _wf_write_task_file(project_id, task, "review",
                        work_log_entry=f"❌ Review cycle {review_cycle}: REJECTED — agent claimed PASS but {reason}. {review_tool_count} total tool calls.")

            if all_pass:
                unfinished_items = _wf_unfinished_checklist_items(checklist)
                if unfinished_items:
                    all_pass = False
                    failed_items = [
                        {
                            "id": item.get("id"),
                            "text": item.get("text", ""),
                            "status": "needs_more_work",
                            "reviewStatus": "needs_more_work",
                            "reason": "Checklist item is still unchecked.",
                        }
                        for item in unfinished_items
                    ]
                    _wf_write_task_file(
                        project_id,
                        task,
                        "review",
                        review_results=failed_items,
                        work_log_entry=f"❌ Review cycle {review_cycle}: REJECTED — {len(unfinished_items)} checklist item(s) are still unchecked."
                    )
                else:
                    wf["_reworkCount"] = 0
                    wf["_parseFailCount"] = 0
                    task_done = True
                    break

            if needs_user:
                # Pause workflow — user must intervene
                with _WORKFLOW_LOCK:
                    wf["phase"] = "awaiting_user_review"
                    wf["error"] = "Task requires user review for some items"
                _wf_sync_project_workflow_meta(project_id, active=True, phase="awaiting_user_review", current_task_id=task_id, active_agent=assignee)
                _wf_persist_state(project_id)
                _wf_write_task_file(project_id, task, "review", review_results=review_results, work_log_entry="Workflow paused — requires user review")
                # Wait until user resolves or stop
                while not stop_flag.is_set():
                    time.sleep(5)
                    # Check if user resolved review items
                    data = _load_projects()
                    project = next((x for x in data["projects"] if x["id"] == project_id), None)
                    if not project:
                        break
                    task = next((t for t in project["tasks"] if t["id"] == task_id), None)
                    if not task:
                        break
                    current_review = task.get("reviewCheck", [])
                    still_needs_user = any(r.get("status") == "requires_user_review" for r in current_review)
                    if not still_needs_user:
                        # User resolved — check if all pass now
                        all_resolved_pass = all(r.get("status") == "pass" for r in current_review)
                        if all_resolved_pass:
                            task_done = True
                            break
                        else:
                            # Some items still need work — continue review loop
                            failed_items = [r for r in current_review if r.get("status") in ("needs_more_work", "did_not_pass")]
                            break
                if task_done or stop_flag.is_set():
                    break

            if failed_items and not stop_flag.is_set():
                # Safety cap: track consecutive rework cycles where the parser
                # couldn't extract structured review lines. Uses original_had_structured
                # (computed BEFORE tool-verification may override all_pass→failed)
                # so that freeform-positive responses that get rejected by tool-check
                # still count as parse failures.
                if not original_had_structured:
                    parse_fail_count = wf.get("_parseFailCount", 0) + 1
                    wf["_parseFailCount"] = parse_fail_count
                else:
                    wf["_parseFailCount"] = 0
                    parse_fail_count = 0

                # Also track total consecutive rework cycles (regardless of parse
                # success) to catch loops where the agent keeps failing for any reason.
                rework_count = wf.get("_reworkCount", 0) + 1
                wf["_reworkCount"] = rework_count

                # Escalate at 3 consecutive parse failures OR 3 total reworks with
                # the same pattern (prevents loops from any cause, not just parse).
                should_escalate = parse_fail_count >= 3 or rework_count >= 3
                if should_escalate:
                    reason_parts = []
                    if parse_fail_count >= 3:
                        reason_parts.append(f"parser failed to match structured output for {parse_fail_count} consecutive cycles")
                    if rework_count >= 3:
                        reason_parts.append(f"task has been reworked {rework_count} consecutive times")
                    reason = "; ".join(reason_parts)

                    with _WORKFLOW_LOCK:
                        wf["phase"] = "awaiting_human_intervention"
                        wf["error"] = (
                            f"Review loop safety cap triggered: {reason}. "
                            f"The reviewing agent may be responding with freeform text "
                            f"or the task may be stuck. Please review manually."
                        )
                    _wf_sync_project_workflow_meta(project_id, active=True, phase="awaiting_human_intervention", current_task_id=task_id, active_agent=assignee)
                    _wf_persist_state(project_id)
                    _wf_write_task_file(
                        project_id, task, "review",
                        review_results=review_results,
                        work_log_entry=f"⚠️ Escalated to user — {reason}. Last response:\n{review_response[:1000]}"
                    )
                    break

                # Move back to In Progress for rework
                with _WORKFLOW_LOCK:
                    wf["phase"] = "reworking"
                _wf_update_task_field(project_id, task_id, "lastReviewCheck", review_results)
                _wf_sync_project_workflow_meta(project_id, active=True, phase="reworking", current_task_id=task_id, active_agent=assignee)
                _wf_persist_state(project_id)

                # Clear stale reviewCheck so next cycle starts clean
                _wf_update_task_field(project_id, task_id, "reviewCheck", [])

                _wf_move_task(project_id, task_id, inprogress_col["id"], by="workflow")
                _wf_write_task_file(project_id, task, "in_progress", work_log_entry=f"Back to In Progress — {len(failed_items)} items need rework")

                task_file = _wf_read_task_file(project_id, task_id)
                rework_prompt = _wf_build_rework_prompt(task, failed_items, task_file)
                rework_response = _wf_call_agent(assignee, rework_prompt, project_id=project_id, task_id=task_id)

                if stop_flag.is_set():
                    break

                rework_activity = _wf_extract_session_activity(assignee, project_id, task_id)
                rework_activity_text = _wf_format_activity_summary(rework_activity)
                _wf_write_task_file(project_id, task, "in_progress", work_log_entry=f"Rework response:\n{rework_response[:2000]}\n\n**Rework activity:**\n{rework_activity_text}")

                # Move back to Review
                _wf_move_task(project_id, task_id, review_col["id"], by="workflow")

        # End of review loop
        if stop_flag.is_set():
            break

        if task_done:
            # Extract session activity BEFORE cleanup (needs the session files)
            activity = _wf_extract_session_activity(assignee, project_id, task_id)
            activity_summary = _wf_format_activity_summary(activity)

            # Move to Done
            done_col = _wf_get_done_col(project)
            if done_col:
                _wf_move_task(project_id, task_id, done_col["id"], by="workflow")

                # Write completion with activity summary
                completion_entry = f"Task completed — all review checks passed\n\n### Task Completion Summary\n{activity_summary}"
                _wf_write_task_file(project_id, task, "done", work_log_entry=completion_entry)

            # Clean up workflow sessions for this task (AFTER activity extraction)
            _wf_cleanup_task_sessions(assignee, project_id, task_id)

            with _WORKFLOW_LOCK:
                wf["phase"] = "task_done"
                wf["currentTaskId"] = None
            _wf_sync_project_workflow_meta(project_id, active=(not single_task), phase="task_done", current_task_id=None, active_agent=None)
            _wf_persist_state(project_id)

            if single_task:
                # Auto Mode OFF — stop after one task
                with _WORKFLOW_LOCK:
                    wf["active"] = False
                break
            else:
                # Auto Mode ON — continue to next task
                time.sleep(2)  # Brief pause between tasks
                continue
        else:
            # Task did NOT pass review after max cycles — do NOT pull next backlog task.
            # Keep this task in progress and pause for human intervention.
            _wf_move_task(project_id, task_id, inprogress_col["id"], by="workflow")
            _wf_write_task_file(project_id, task, "in_progress",
                work_log_entry=f"Review failed after {max_review_cycles} cycles — paused for human intervention. Backlog tasks will NOT proceed until this task passes or is manually resolved.")

            with _WORKFLOW_LOCK:
                wf["phase"] = "awaiting_human_intervention"
                wf["error"] = f"Task '{task.get('title', '')}' failed review after {max_review_cycles} cycles. Resolve manually or retry."
            _wf_sync_project_workflow_meta(project_id, active=True, phase="awaiting_human_intervention", current_task_id=task_id, active_agent=assignee)
            _wf_persist_state(project_id)

            # Wait until human resolves (moves task to done/backlog, or restarts workflow)
            while not stop_flag.is_set():
                time.sleep(5)
                # Check if task was manually moved to done or back to backlog
                data = _load_projects()
                project = next((x for x in data["projects"] if x["id"] == project_id), None)
                if not project:
                    break
                task = next((t for t in project["tasks"] if t["id"] == task_id), None)
                if not task:
                    break
                done_col = _wf_get_done_col(project)
                backlog_col = _wf_get_backlog_col(project)
                current_col = task.get("columnId")
                if done_col and current_col == done_col["id"]:
                    # Human moved to done — clean up and continue
                    _wf_cleanup_task_sessions(assignee, project_id, task_id)
                    break
                if backlog_col and current_col == backlog_col["id"]:
                    # Human moved back to backlog — skip this task
                    _wf_cleanup_task_sessions(assignee, project_id, task_id)
                    break

            if stop_flag.is_set():
                break

            # If single_task mode, stop; otherwise loop will re-check backlog
            if single_task:
                with _WORKFLOW_LOCK:
                    wf["active"] = False
                break
            else:
                time.sleep(2)
                continue

    # Pipeline ended (cleanup handled by wrapper in _wf_run_pipeline)


WORKFLOW_STATE_FILE = os.path.join(STATUS_DIR, "workflow-state.json")

def _wf_persist_state(project_id):
    """Persist workflow state to disk so it survives page refreshes and container restarts."""
    with _WORKFLOW_LOCK:
        wf = _WORKFLOW_STATE.get(project_id, {})
    state_data = {}
    try:
        if os.path.isfile(WORKFLOW_STATE_FILE):
            with open(WORKFLOW_STATE_FILE, "r") as f:
                state_data = json.load(f)
    except Exception:
        state_data = {}
    state_data[project_id] = {
        "active": wf.get("active", False),
        "autoMode": wf.get("autoMode", False),
        "currentTaskId": wf.get("currentTaskId"),
        "currentAssignee": wf.get("currentAssignee"),
        "currentTaskTitle": wf.get("currentTaskTitle"),
        "phase": wf.get("phase", "idle"),
        "error": wf.get("error"),
        "reviewCycle": wf.get("reviewCycle", 0),
    }
    try:
        os.makedirs(os.path.dirname(WORKFLOW_STATE_FILE), exist_ok=True)
        with open(WORKFLOW_STATE_FILE, "w") as f:
            json.dump(state_data, f, indent=2)
    except Exception:
        pass
    # Also write shared project-work signal file so other VO instances
    # can show project work indicators.
    # This file lives in ~/.openclaw/shared/ which is mounted by all VOs.
    _wf_update_shared_project_work()


def _wf_update_shared_project_work():
    """Write active project-work data to a shared file readable by all VO instances.
    Maps agent IDs to their active project task info."""
    active_phases = ("in_progress", "dispatching", "reviewing", "rework")
    shared = {}
    with _WORKFLOW_LOCK:
        for pid, wf in _WORKFLOW_STATE.items():
            if not wf.get("active") or wf.get("phase") not in active_phases:
                continue
            agent_id = wf.get("currentAssignee")
            if not agent_id:
                continue
            shared[agent_id] = {
                "projectId": pid,
                "taskId": wf.get("currentTaskId", ""),
                "taskTitle": wf.get("currentTaskTitle", ""),
                "phase": wf.get("phase", ""),
                "updatedAt": int(time.time() * 1000),
            }
    try:
        shared_path = os.path.join(WORKSPACE_BASE, "shared", "project-work.json")
        os.makedirs(os.path.dirname(shared_path), exist_ok=True)
        with open(shared_path, "w") as f:
            json.dump(shared, f)
    except Exception:
        pass


def _wf_load_persisted_state(project_id):
    """Load persisted workflow state from disk."""
    try:
        if os.path.isfile(WORKFLOW_STATE_FILE):
            with open(WORKFLOW_STATE_FILE, "r") as f:
                state_data = json.load(f)
            return state_data.get(project_id, {})
    except Exception:
        pass
    return {}

def _wf_clear_persisted_state(project_id):
    """Clear persisted state when workflow ends."""
    try:
        if os.path.isfile(WORKFLOW_STATE_FILE):
            with open(WORKFLOW_STATE_FILE, "r") as f:
                state_data = json.load(f)
            state_data.pop(project_id, None)
            with open(WORKFLOW_STATE_FILE, "w") as f:
                json.dump(state_data, f, indent=2)
    except Exception:
        pass


def _handle_workflow_chat(project_id):
    """GET /api/projects/{id}/workflow/chat — get the active workflow agent's session messages.

    ONLY reads from the task-specific workflow session (wf-<project>-<task>),
    never from the agent's main session or other sessions.
    """
    with _WORKFLOW_LOCK:
        wf = _WORKFLOW_STATE.get(project_id, {})

    # Also check persisted state if in-memory is empty
    persisted = _wf_load_persisted_state(project_id)
    current_task_id = wf.get("currentTaskId") or persisted.get("currentTaskId")
    phase = wf.get("phase") or persisted.get("phase", "idle")

    # Find the assigned agent — check current task or find any in-progress/review task
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if not p:
        return {"ok": True, "messages": [], "agent": None}

    project_execution_active = _project_execution_enabled(p) and p.get("workflowActive") and p.get("activeTaskId")
    agent_key = p.get("activeAgent") if project_execution_active else None
    task_id = p.get("activeTaskId") if project_execution_active else current_task_id
    conversation_id = None

    # First try the tracked current task
    if task_id:
        task = next((t for t in p["tasks"] if t["id"] == task_id), None)
        if task:
            if project_execution_active:
                phase = p.get("workflowPhase") or phase
                conversation_id = task.get("activeAttemptId")
                if phase == "reviewing":
                    agent_key = agent_key or task.get("reviewerAgentId")
                else:
                    agent_key = agent_key or task.get("executorAgentId")
            agent_key = agent_key or task.get("assignee")

    # If no tracked task, find the most recently active task (in progress or review)
    if not agent_key:
        ip_cols = [c["id"] for c in p.get("columns", []) if c.get("title", "").lower() in ("in progress", "review", "to do")]
        active_tasks = [t for t in p.get("tasks", []) if t.get("columnId") in ip_cols]
        if active_tasks:
            active_tasks.sort(key=lambda t: t.get("updatedAt", ""), reverse=True)
            task_id = active_tasks[0]["id"]
            agent_key = active_tasks[0].get("assignee")

    if not agent_key or not task_id:
        return {"ok": True, "messages": [], "agent": None, "phase": phase}

    # Read ONLY from the execution-scoped session. Project Execution uses the
    # active attempt/review id for OpenClaw sessions so repeat triggers do not
    # continue a prior run's transcript.
    session_task_id = conversation_id if (project_execution_active and conversation_id and not (_is_hermes_agent(agent_key) or _is_codex_agent(agent_key))) else task_id
    msgs = _wf_get_task_session_messages(agent_key, project_id, session_task_id, conversation_id=conversation_id)

    # Check if the workflow session is still actively running
    session_active = _wf_is_task_session_active(agent_key, project_id, session_task_id)

    return {
        "ok": True,
        "messages": msgs,
        "agent": agent_key,
        "taskId": task_id,
        "phase": phase,
        "sessionActive": session_active,
    }


def _codex_reasoning_events_to_chat_messages(events, agent_id, max_messages=50):
    states = {}
    ordered = []
    for event in events:
        if event.get("type") != "reasoning":
            continue
        key = f"{event.get('operationId') or event.get('turnId') or event.get('threadId') or 'turn'}:{event.get('itemId') or 'reasoning'}"
        state = states.get(key)
        if not state:
            state = {"text": "", "ids": set(), "lastTs": 0, "status": "running"}
            states[key] = state
            ordered.append((key, state))
        event_id = event.get("id")
        if event_id and event_id in state["ids"]:
            continue
        if event_id:
            state["ids"].add(event_id)
        incoming = _provider_visible_thinking("codex", {**event, "thinking": event.get("text") or event.get("output") or ""})
        if not incoming:
            continue
        if event.get("replace") and incoming.strip():
            state["text"] = incoming
        else:
            if event.get("boundary") and state["text"].strip() and not state["text"].endswith("\n\n"):
                state["text"] += "\n\n"
            state["text"] += incoming
        state["lastTs"] = max(int(event.get("ts") or 0), int(state.get("lastTs") or 0))
        state["status"] = event.get("status") or state.get("status") or "running"

    messages = []
    for _, state in ordered:
        text = state.get("text", "").strip()
        if not text:
            continue
        messages.append({
            "role": "assistant",
            "text": "",
            "thinking": text,
            "reasoningStatus": state.get("status") or "running",
            "ts": state.get("lastTs") or 0,
            "epochMs": state.get("lastTs") or 0,
            "fromAgentId": agent_id,
            "source": "codex-activity",
        })
    return messages[-max_messages:]


def _wf_get_task_session_messages(agent_id, project_id, task_id, max_messages=50, conversation_id=None):
    if _is_hermes_agent(agent_id):
        agent = _get_hermes_agent(agent_id) or {}
        profile = agent.get("profile") or agent.get("providerAgentId") or "default"
        return _load_hermes_history(profile, conversation_id)[-max_messages:]
    if _is_codex_agent(agent_id):
        messages = []
        codex_conversation_id = conversation_id or task_id
        for event in _load_comm_history(limit=max_messages, conversation_id=codex_conversation_id):
            msg = _comm_event_to_chat_message(event, agent_id)
            if msg:
                messages.append(msg)
        messages.extend(_codex_reasoning_events_to_chat_messages(
            _get_codex_activity(agent_id, codex_conversation_id, 0),
            agent_id,
            max_messages=max_messages,
        ))
        messages.sort(key=lambda m: int(m.get("epochMs") or m.get("ts") or 0))
        return messages[-max_messages:]

    """Read messages from the task-specific workflow session JSONL only."""
    session_key = _wf_task_session_key(agent_id, project_id, task_id)
    home_path = VO_CONFIG.get("openclaw", {}).get("homePath", os.path.expanduser("~/.openclaw"))
    sessions_dir = os.path.join(home_path, "agents", agent_id, "sessions")
    sessions_json_path = os.path.join(sessions_dir, "sessions.json")

    try:
        with open(sessions_json_path, "r") as f:
            sessions_data = json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        return []

    session_info, _ = _openclaw_get_session_info(sessions_data, agent_id, session_key)
    if not session_info:
        return []

    session_id = session_info.get("sessionId", "")
    jsonl_path = session_info.get("sessionFile") or (os.path.join(sessions_dir, f"{session_id}.jsonl") if session_id else "")
    if not os.path.exists(jsonl_path):
        return []

    messages = []
    try:
        # Read tail of file — use a larger buffer to handle long lines (tool results
        # can be 100KB+). Read last 256KB to ensure we capture multiple complete lines.
        TAIL_BYTES = 256 * 1024
        with open(jsonl_path, "rb") as fb:
            fb.seek(0, 2)
            fsize = fb.tell()
            start = max(0, fsize - TAIL_BYTES)
            fb.seek(start)
            tail_data = fb.read().decode("utf-8", errors="replace")
        if start > 0:
            nl = tail_data.find("\n")
            if nl >= 0:
                tail_data = tail_data[nl + 1:]
        for line in tail_data.split("\n"):
            line = line.strip()
            if not line:
                continue
            try:
                entry = json.loads(line)
            except json.JSONDecodeError:
                continue
            msg = entry.get("message", entry)
            role = msg.get("role")
            if role not in ("user", "assistant"):
                continue
            content = msg.get("content", [])
            text = ""
            tool_info = []
            if isinstance(content, str):
                text = content
            elif isinstance(content, list):
                for c in content:
                    if isinstance(c, dict):
                        if c.get("type") == "text":
                            text += c.get("text", "")
                        elif c.get("type") == "toolCall":
                            name = c.get("name", "?")
                            args = c.get("arguments", {})
                            # Build a human-readable summary instead of bare tool name
                            summary = name
                            if isinstance(args, dict):
                                if name in ("read", "Read") and (args.get("file") or args.get("path") or args.get("file_path")):
                                    fpath = args.get("file") or args.get("path") or args.get("file_path") or ""
                                    summary = f"Reading {fpath.split('/')[-1] if '/' in fpath else fpath}"
                                elif name in ("edit", "Edit"):
                                    fpath = args.get("file") or args.get("path") or args.get("file_path") or ""
                                    summary = f"Editing {fpath.split('/')[-1] if '/' in fpath else fpath}"
                                elif name in ("write", "Write"):
                                    fpath = args.get("file") or args.get("path") or args.get("file_path") or ""
                                    summary = f"Writing {fpath.split('/')[-1] if '/' in fpath else fpath}"
                                elif name == "exec":
                                    cmd = args.get("command", "")
                                    summary = f"Running: {cmd[:80]}" if cmd else "exec"
                                elif name == "web_search":
                                    query = args.get("query", "")
                                    summary = f"Searching: {query[:60]}" if query else "web_search"
                                elif name == "web_fetch":
                                    url = args.get("url", "")
                                    summary = f"Fetching: {url[:60]}" if url else "web_fetch"
                                elif name == "browser":
                                    action = args.get("action", "")
                                    summary = f"Browser: {action}" if action else "browser"
                                elif name == "sessions_send":
                                    target = args.get("sessionKey") or args.get("label") or ""
                                    summary = f"Messaging: {target[:40]}" if target else "sessions_send"
                            tool_info.append({"name": summary, "args_preview": ""})
                        elif c.get("type") == "toolResult":
                            pass  # skip tool results for chat display
            if text or tool_info:
                m = {"role": role, "timestamp": msg.get("timestamp", entry.get("timestamp", 0))}
                if text:
                    m["text"] = text[:2000]
                if tool_info:
                    m["tools"] = tool_info[:5]  # cap tool display
                messages.append(m)
        messages = messages[-max_messages:]
    except Exception:
        pass
    return messages


def _wf_is_task_session_active(agent_id, project_id, task_id):
    if _is_hermes_agent(agent_id) or _is_codex_agent(agent_id):
        return False

    """Check if the task-specific workflow session is still actively running."""
    session_key = _wf_task_session_key(agent_id, project_id, task_id)
    home_path = VO_CONFIG.get("openclaw", {}).get("homePath", os.path.expanduser("~/.openclaw"))
    sessions_dir = os.path.join(home_path, "agents", agent_id, "sessions")
    sessions_json_path = os.path.join(sessions_dir, "sessions.json")

    try:
        with open(sessions_json_path, "r") as f:
            sessions_data = json.load(f)
        session_info, _ = _openclaw_get_session_info(sessions_data, agent_id, session_key)
        status = session_info.get("status", "")
        return status == "running"
    except Exception:
        return False


def _handle_workflow_start(project_id, body=None):
    """POST /api/projects/{id}/workflow/start — start the workflow pipeline."""
    body = body or {}
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if not p:
        return {"error": "Project not found", "_status": 404}

    with _WORKFLOW_LOCK:
        wf = _WORKFLOW_STATE.get(project_id)
        if wf and wf.get("active"):
            return {"error": "Workflow already running for this project", "_status": 409}

        auto_mode = body.get("autoMode", False)
        stop_flag = threading.Event()
        wf = {
            "active": True,
            "autoMode": auto_mode,
            "currentTaskId": None,
            "phase": "starting",
            "error": None,
            "reviewCycle": 0,
            "stopFlag": stop_flag,
            "thread": None,
        }
        _WORKFLOW_STATE[project_id] = wf

    # Update project workflow settings
    p["workflowActive"] = True
    p["workflowPhase"] = "starting"
    p["activeTaskId"] = None
    p["activeAgent"] = None
    p["autoMode"] = auto_mode
    p["updatedAt"] = _proj_now()
    _save_projects(data)
    _log_activity(p, "workflow_started", "user", f"Workflow started (autoMode: {auto_mode})")

    _wf_persist_state(project_id)

    # Launch background thread
    single_task = not auto_mode
    t = threading.Thread(target=_wf_run_pipeline, args=(project_id, single_task), daemon=True)
    with _WORKFLOW_LOCK:
        wf["thread"] = t
    t.start()

    return {"ok": True, "status": "started", "autoMode": auto_mode}


def _handle_workflow_stop(project_id):
    """POST /api/projects/{id}/workflow/stop — stop the workflow."""
    current_task_id = None
    with _WORKFLOW_LOCK:
        wf = _WORKFLOW_STATE.get(project_id)
        if not wf or not wf.get("active"):
            return {"ok": True, "status": "already_stopped"}
        current_task_id = wf.get("currentTaskId")
        wf["stopFlag"].set()
        wf["active"] = False
        wf["phase"] = "stopped"
        wf["currentTaskId"] = None

    _wf_persist_state(project_id)
    _wf_clear_persisted_state(project_id)

    # Update project
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if p:
        p["workflowActive"] = False
        p["workflowPhase"] = "stopped"
        p["activeTaskId"] = None
        p["activeAgent"] = None
        p["updatedAt"] = _proj_now()
        _save_projects(data)
        _log_activity(p, "workflow_stopped", "user", "Workflow stopped by user")

    # Abort the running agent session for the active task, then clean up.
    # This sends chat.abort to the gateway which immediately kills any in-flight
    # LLM inference — only targets this specific task session, not the agent's
    # main session or other workflow sessions.
    if current_task_id and p:
        task = next((t for t in p.get("tasks", []) if t["id"] == current_task_id), None)
        if task and task.get("assignee"):
            session_key = _wf_task_session_key(task["assignee"], project_id, current_task_id)
            _wf_abort_task_session(session_key)
            _wf_cleanup_task_sessions(task["assignee"], project_id, current_task_id)

    return {"ok": True, "status": "stopped"}


def _handle_workflow_auto_mode(project_id, body):
    """PUT /api/projects/{id}/workflow/auto-mode — toggle auto mode."""
    auto_mode = body.get("autoMode", False)
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if not p:
        return {"error": "Project not found", "_status": 404}
    p["autoMode"] = auto_mode
    p["updatedAt"] = _proj_now()
    _save_projects(data)

    with _WORKFLOW_LOCK:
        wf = _WORKFLOW_STATE.get(project_id)
        if wf:
            wf["autoMode"] = auto_mode

    return {"ok": True, "autoMode": auto_mode}


def _handle_workflow_status(project_id):
    """GET /api/projects/{id}/workflow/status — get workflow state."""
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if not p:
        return {"error": "Project not found", "_status": 404}

    with _WORKFLOW_LOCK:
        wf = _WORKFLOW_STATE.get(project_id, {})
        # Detect stale state: persisted says active but thread is dead
        thread = wf.get("thread")
        thread_alive = thread is not None and thread.is_alive() if thread else False

    # Merge with persisted state (for page refresh resilience)
    persisted = _wf_load_persisted_state(project_id)
    in_memory_active = wf.get("active", False)
    persisted_active = persisted.get("active", False)

    # If persisted says active but no thread is running, it's stale — clean up
    if persisted_active and not in_memory_active and not thread_alive:
        _wf_clear_persisted_state(project_id)
        persisted_active = False
        persisted["phase"] = persisted.get("phase", "idle")
        # If the phase was a working phase, mark it as stalled
        if persisted.get("phase") in ("in_progress", "reviewing", "reworking", "dispatching"):
            persisted["phase"] = "stalled"

    active = in_memory_active or persisted_active
    phase = wf.get("phase") or persisted.get("phase", "idle")
    current_task = wf.get("currentTaskId") or persisted.get("currentTaskId")
    error = wf.get("error") or persisted.get("error")
    review_cycle = wf.get("reviewCycle", 0) or persisted.get("reviewCycle", 0)

    # Check if the task-specific session is still actively running in OpenClaw
    # This catches cases where the workflow thread is mid-API-call (active=True in session)
    # but the in-memory state hasn't been updated yet
    session_active = False
    if current_task and not active and phase != "stopped":
        # Find the assignee for the current task
        task = next((t for t in p.get("tasks", []) if t["id"] == current_task), None)
        if task and task.get("assignee"):
            session_active = _wf_is_task_session_active(task["assignee"], project_id, current_task)
            if session_active:
                # Session is running but workflow state says inactive — the thread
                # is mid-API-call. Report as active so UI shows progress.
                active = True
                if phase in ("idle", "stalled", "blocked_by_active_task"):
                    phase = "working"

    return {
        "ok": True,
        "active": active,
        "autoMode": p.get("autoMode", False),
        "currentTaskId": current_task,
        "activeAgent": next((t.get("assignee") for t in p.get("tasks", []) if t.get("id") == current_task), None) if current_task else None,
        "phase": phase,
        "error": error,
        "reviewCycle": review_cycle,
        "sessionActive": session_active,
    }


def _handle_review_check_update(project_id, task_id, body):
    """PUT /api/projects/{id}/tasks/{taskId}/review-check — update review status."""
    data = _load_projects()
    p = next((x for x in data["projects"] if x["id"] == project_id), None)
    if not p:
        return {"error": "Project not found", "_status": 404}
    task = next((t for t in p["tasks"] if t["id"] == task_id), None)
    if not task:
        return {"error": "Task not found", "_status": 404}
    if _project_execution_enabled(p):
        return {"error": "Project Execution review results must be produced by the Independent reviewer flow", "_status": 409}

    review_check = body.get("reviewCheck", [])
    task["reviewCheck"] = review_check
    task["updatedAt"] = _proj_now()
    p["updatedAt"] = _proj_now()
    by = body.get("by", "user")
    _log_activity(p, "review_updated", by, "Review check updated", task_id)
    _save_projects(data)
    # Update task markdown file with review results
    current_col = next((c["title"] for c in p.get("columns", []) if c["id"] == task.get("columnId")), "review")
    _wf_write_task_file(project_id, task, current_col.lower().replace(" ", "_"), review_results=review_check, work_log_entry=f"Review check updated by {by}")
    return {"ok": True, "task": task}


def _handle_template_delete(template_id):
    """DELETE /api/projects/templates/{id}."""
    data = _load_projects()
    before = len(data.get("templates", []))
    data["templates"] = [t for t in data.get("templates", []) if t["id"] != template_id]
    if len(data["templates"]) == before:
        return {"error": "Template not found", "_status": 404}
    _save_projects(data)
    return {"ok": True, "id": template_id}


def _handle_agent_delete(body):
    """Delete an agent from its backing platform."""
    agent_id = (body.get("id") or "").strip()
    if not agent_id:
        return {"error": "Agent ID is required", "_status": 400}

    # Safety: never delete the main agent
    if agent_id == "main":
        return {"error": "Cannot delete the main agent", "_status": 403}
    if _is_archive_manager_agent(agent_id):
        return {"error": "档案管理员是系统角色，不能删除；可以在档案室暂停。", "code": "archive_manager_cannot_delete", "_status": 403}

    try:
        agent = _office_agent_lookup(agent_id)
        provider_kind = (agent or {}).get("providerKind", "openclaw")
        if provider_kind == "codex" or agent_id.startswith("codex-"):
            profile = (agent or {}).get("providerAgentId") or agent_id.replace("codex-", "", 1)
            result = _codex_provider_from_config().delete_agent(profile)
            if not result.get("ok"):
                return {"error": result.get("error", "Codex agent delete failed"), "_status": 500}
        elif provider_kind == "claude-code" or agent_id.startswith("claude-code-"):
            profile = (agent or {}).get("providerAgentId") or agent_id.replace("claude-code-", "", 1)
            result = _claude_code_provider_from_config().delete_agent(profile)
            if not result.get("ok"):
                return {"error": result.get("error", "Claude Code agent delete failed"), "_status": 500}
            try:
                os.remove(_claude_code_history_path(profile))
            except FileNotFoundError:
                pass
            except OSError as e:
                print(f"[CLAUDE-CODE] Failed to remove VO history for deleted profile {profile}: {e}")
        elif provider_kind == "hermes" or agent_id.startswith("hermes-"):
            profile = (agent or {}).get("providerAgentId") or agent_id.replace("hermes-", "", 1)
            provider = HermesProvider(
                home_path=VO_CONFIG.get("hermes", {}).get("homePath"),
                binary=VO_CONFIG.get("hermes", {}).get("binary"),
                enabled=VO_CONFIG.get("hermes", {}).get("enabled", True),
                timeout_sec=VO_CONFIG.get("hermes", {}).get("timeoutSec", 600),
            )
            result = provider.delete_agent(profile)
            if not result.get("ok"):
                return {"error": result.get("error", "Hermes agent delete failed"), "_status": 500}
            try:
                os.remove(_hermes_history_path(profile))
            except FileNotFoundError:
                pass
            except OSError as e:
                print(f"[HERMES] Failed to remove VO history for deleted profile {profile}: {e}")
        elif provider_kind == "codex" or agent_id.startswith("codex-"):
            profile = (agent or {}).get("providerAgentId") or agent_id.replace("codex-", "", 1)
            result = _codex_provider().delete_agent(profile)
            if not result.get("ok"):
                return {"error": result.get("error", "Codex agent delete failed"), "_status": 500}
            try:
                os.remove(_codex_history_path(profile))
            except FileNotFoundError:
                pass
            except OSError as e:
                print(f"[CODEX] Failed to remove VO history for deleted profile {profile}: {e}")
        elif provider_kind == "claude-code" or agent_id.startswith("claude-code-"):
            profile = (agent or {}).get("providerAgentId") or agent_id.replace("claude-code-", "", 1)
            result = _claude_code_provider().delete_agent(profile)
            if not result.get("ok"):
                return {"error": result.get("error", "Claude Code agent delete failed"), "_status": 500}
            try:
                os.remove(_claude_code_history_path(profile))
            except FileNotFoundError:
                pass
            except OSError as e:
                print(f"[CLAUDE_CODE] Failed to remove VO history for deleted profile {profile}: {e}")
        else:
            result = _gateway_rpc_call("agents.delete", {"agentId": agent_id, "deleteFiles": True}, timeout=30)
            if not result.get("ok"):
                status = 404 if "not found" in str(result.get("error", "")).lower() else 500
                return {"error": result.get("error", "OpenClaw agent delete failed"), "_status": status}
            _remove_openclaw_agent_paths(agent_id)

        # Refresh discovery
        global _discovered_at
        _discovered_at = 0
        refresh_agent_maps()

        return {
            "ok": True,
            "agentId": agent_id,
            "message": f"Agent '{agent_id}' deleted successfully"
        }

    except Exception as e:
        traceback.print_exc()
        return {"error": str(e), "_status": 500}


