            tail = parsed_path.split("/api/archive-room/projects/", 1)[1].strip("/")
            if tail.endswith("/context"):
                proj_id = tail.rsplit("/context", 1)[0].strip("/")
                result = _handle_archive_room_context(urllib.parse.unquote(proj_id), parsed.query)
                self.send_response(result.get("_status", 200))
                self.send_header("Content-Type", "application/json")
                self.send_header("Access-Control-Allow-Origin", "*")
                self.end_headers()
                result.pop("_status", None)
                self.wfile.write(json.dumps(result).encode())
                return
            if "/" in tail:
                self.send_response(404)
                self.end_headers()
                return
            result = _handle_archive_room_project(urllib.parse.unquote(tail))
            self.send_response(result.get("_status", 200))
            self.send_header("Content-Type", "application/json")
            self.send_header("Access-Control-Allow-Origin", "*")
            self.end_headers()
